insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('db862da7-e6e3-5c46-8916-ba4400c21434', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-21', '17:30:00', null, '通常 / 選抜大会の準備 作品の完成、提出用の作文', '作品を仕上げながら、並行してメモ帳に応募文を書いていました。 作品については、シュート成功判定が厳しくなりすぎたかも？と言って調整をしていましたが、最終的には「こんな感じで」ということで完成させていました。 応募文については、長く書くのがあまり得意ではないようで、400字程度という指定に対し、どれも半分ほどの量にはなってしまいましたが、自分の言葉で一生懸命書こうとする姿勢と集中力はよかったかと思われます。', null, '盛り上がり: 時間は30分近くオーバーしましたが、最後まで投げ出さず、自力でやりとげた姿勢は良かったと思います。 振替を使うことなく、予定通りの提出ができて満足そうでした。
備考: タイピングコンテストについては、参加意欲が高いと思われます。'),
  ('eb421e55-ce94-59e6-840c-d9e8db5a1847', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-21', '17:30:00', null, '通常 / 選抜大会の準備 作品の手直し、提出用の作文', '作品自体は親子大会のままでよいとのことで、応募フォームへの入力をしました。 文章を書くこと自体は抵抗なく、すらすらと長文を仕上げていましたが、フォームへの直接入力や作品ファイルの紛失など、管理面での課題が見えました。 せっかくおもしろい作品を作れる力があるので、管理面やネットリテラシー面についての成長を望みたいところです。（Scratch複数アカウントを管理しきれていない、アカウント停止の経緯なども、早めに改善したいところ…）', null, '盛り上がり: 制作過程の文章は、とてもノリノリで書いていました。作品提出が済んでほっとしたようでした。'),
  ('4897a37f-004a-59ce-8936-4cb5c7233bf1', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-21', '16:30:00', null, '通常 / 条件分岐を使ったスプライトの動かしかたの定着、角度の意識', '当初予定していたゾンビをたおせは既習だったため、アルくんの冒険とフリエを救えをプレイして、やりたい課題を選んでもらいました。 向きを指定してから〇歩動かすやり方は、きちんと覚えていて問題なく作成できていました。自分で選んだスプライトの場合、-方向に動かすとスプライトが逆さになってしまったため、体験で使ったブロックとのヒントを出しましたが、「回転方法を左右のみ」は覚えていなかったので、改めて説明しました。 音を入れるところでは、「音楽はどうでもいいんだよね～」と乗り気でないことも言っていましたが、ブロックの位置について質問すると、いそいそと作成していたので…「プログラミング」として扱うことは嫌ではないのかも？？ 条件分岐の並列や「すべてを止める」についても、チュートリアルを見ながらスラスラと作成していました。 20分ほど時間を残して完成させることができ、とても得意げな感じでした。 敵キャラをもう一つ作れるかと聞いたら、ノリノリでアレンジをしてくれました。速さを調節したりして、おもしろいゲームになるように頑張っていました。', null, 'タイピング: 現在のレベルのキーは打てています。
盛り上がり: チュートリアルは嫌がらずに見てくれますが、それはそれとして、先生にそばにいてほしそうでした。常に隣に座っていなくても、声掛けを頻繁にしていると表情が変わって、熱心にやろうとする姿勢を見せていました。
備考: そうたろうくんがやっていたかけ算クイズが気になったらしく、終了間際のフリータイムで熱心にプレイしていました。'),
  ('06a002c1-1095-505a-9748-f4931db5f981', 'b2246586-4496-52f9-a825-be2488a00a31', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-21', '17:30:00', null, '通常 / 記憶に残る作品作り', '最初あたりは、もうつくるものは作ったと言い張って、遊びに走ることが多々あったが、寿司屋のゲームを作ってお願いして作り始めてもらいました。出来上がった作品はまた寿司屋が燃える話だったが、建物ひび割れ、建物燃える色移り、焼失具合などの演出が上手くコマ送りしていて、見ごたえあるものになっていました。演出の移り変わりデザインがまさきくんの長所になっていると思います。さいごは、せいくんと作品を見せあって、楽しめていました。', null, 'タイピング: 少しいやいやだったが最初の5分はやってくれました。
盛り上がり: また休み期間に遊びに来てね'),
  ('25c375c2-9c8f-59a8-8eb4-bb155d6673df', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-21', '17:30:00', null, '通常 / y座標の理解、りんごキャッチの応用', '前回のりんごキャッチの特にy座標の部分がよくわからないまま終わってしまったとのことで、同じようなボールキャッチで復習をしました。今回はきちんとボールを落とすことができました。数字の全角半角を知らなかったようなので両者を見せ、半角で打たないとスクラッチは認識してくれないことなどを伝えました。プレイヤーに触れたときと床に触れたときの処理もでき、完成しました。', null, 'タイピング: いつも通り楽しみながらやっていました
盛り上がり: 今までまさきくんとの絡みはあまりなかったですが、席が近かった今日は仲良く話していました。'),
  ('ad838d75-aa84-59bf-8303-134dd121ffde', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-21', '17:30:00', null, '振替 / 座標のコントロール、「～まで待つ」の使い方を意識して。', 'はじめにゲームをプレイして、今日は何を学習するのか目標を確認してから取りかかりました。 スプライトや背景、コスチュームにこだわって、コード作成に入るまでに少し時間がかかりましたが、本人が納得してからの進み方はとても順調でした。 スプライトのもともとの向きに合わせて、敢えて見本と左右の配置を変えていましたが、おかげで座標関係のコードの意味をきちんと理解できていることがわかりました。 ジャンプのための上下の動きをするためにはy座標を変える、上に行った分だけ下におろすにはどうすればよいか、などの口頭での質問にもきちんと答えることができていました。 一通りの動きができてからは、ジャンプしたときのコスチュームを変えたり、ジャンプの頂点で滞空時間を作ったりのアレンジも楽しそうにしていました。アレンジしたブロックを既存のコードに入れる際にも、入れる場所を迷うことなくできていました。 完成後の感想も、簡単で面白かったとのことでした。', '今回の課題は全く問題なくできていたので、ピンポンゲームかキャッチゲームに進んで良いかと思われます。', 'タイピング: タイピングは順調です。
盛り上がり: ゲームの構成を理解した上で、自分なりのアレンジができていました。終始楽しそうに取り組めていました。'),
  ('fcbdeddf-d3fd-5057-ac12-94dc14650573', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-21', '17:30:00', null, '通常 / ブロック崩しの完成', 'ゲーム―オーバーの仕組みでは、やりがちな=を使って判定していてたので、条件判定に向かないと伝えたら、すぐさま不等号に切り替えることができました。クリア＆オーバーも作る際も何回も試行する癖がついていてよかったです。アレンジも、ゲームクリア演出を目の光る演出になっていてよかったです。', null, '盛り上がり: 最後、まさき君向けたアレンジで楽しませていました'),
  ('ee9c8ccb-3f64-5af8-9c22-f267289cb86d', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-21', '16:30:00', null, '通常 / 条件分岐の中の順次処理、「～まで待つ」の使い方', 'ボールを動かすところを案外複雑に考えすぎてしまい、「～秒でどこかに行く」など試行錯誤していました。「端に触れたら跳ね返る」を使うことは分かっていたので、端に触れていないときは...?と問いかけると、「～歩進む」で直進するだけということに気づきました。 バットがボールに触れたら行う処理は複数あったので、それらを一か所にまとめてもらいました。 ゲームオーバーやクリアの処理を作る時、練習として「もし～なら」の代わりに「～まで待つ」で作ってもらい、その使い方に慣れてもらいました。', null, 'タイピング: ホームポジションの場所を覚えようとしていました。
盛り上がり: 野球が好きらしく、今日のゲームはバットと野球ボールで作っていました。'),
  ('894564d0-bc00-59ee-b4b3-968e27d6be88', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-21', '16:30:00', null, '通常 / ランダム計算問題を作ろう', '最初に見たとき、九九はまだ習ってないが、果敢に問題に挑んでいました。ランダム性を扱うコードをなかなか思い出せなかったので、以前使ったチーズを探せを見て思い出してもらい、乱数を思い出してもらいました。今回は乱数をコスチューム番号に使うことに戸惑いはあったが、乱数の使い方は覚えていました。正誤判定を作るところでは、演算式で条件を作るところだったので、ある程度＝や＊のブロックをヒントで出しておき、そのブロックの意味を理解したうえで、自力でほかのブロックを何回か試行しながら、組み立てることができました。わかったところは自分の言葉で言いなしてくれるからわかりやすい。そのご、〇×のメッセージのやり取りはスムーズに作れ完成できました。', null, 'タイピング: 1つ1つ指を確認しながらタイピングをしてました
盛り上がり: 4の段くらいまでの九九はよくできていた。'),
  ('2da5fc9a-28a9-56c4-9d48-a16dbf760b75', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-19', '17:30:00', null, '通常 / 変数を使ってスピードの制御をするジャンプの学習', '初めに作品の見本を見せ、これまでやったジャンプ（基本操作コース10）とどこが違うかを観察してもらいました。色々な作品を見たことがあるだけあって、「こういうのは作ったことはないけど、見たことはある」と言って、ジャンプの速度の変わり方が違う等、すぐに答えることができていました。 ヒントとして「ジャンプのはやさ」という変数を作成することを説明してから、ジャンプの速さが変わるには、変数の値が上昇する時と下降する時でどう変化すればよいのか考えてもらいました。はじめは少し混乱が見られましたが、ジャンプのイメージを図解したら、なんとなく理解できたようでした。 単元別演習の中の、x座標を変えるブロックは抜いて、垂直ジャンプの状態で一度完成とし、その後は自由なアレンジに入りました。バッタのスプライトが跳んでいるように見えるよう、コスチュームの変更をするブロックの位置など、いろいろと試しながらうまく作成していました。 垂直ジャンプのコードと並行して、横に動かすコードを作成することを勧めたところ、最初は「○○キーが押されたとき」を使用しようとしていたので、条件分岐を使ってという助言をしたところ、その先は自分で作成できていました。ただ、「〇〇度に向ける」と「x座標を〇〇ずつ変える」を併用しようとしていたので、それぞれのブロックの意味を確認したところ、「〇歩動かす」の方を使用していました。 後半は、飛んでくる弾丸をジャンプしてよけるゲームへのアレンジを熱心にしていました。 弾丸にクローンを使ったりして、とても楽しそうでした。', null, '盛り上がり: 今日は丸椅子だったせいもあるのか、姿勢も最後までしっかりしていて、熱心に取り組んでいました。会話もだいぶ増えてきたように思います。'),
  ('557d2685-d09a-582d-a440-488a3c1c768d', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-19', '17:30:00', null, '通常 / サメから逃げろの完成', 'アルくんを捕まえる仕組みを作っていきました。基本的な動きできており、セリフや音楽を追加して個性を出していました。ただ、追いかけるのがエンドレスになっていたので、変数を使ったカウントダウンの仕組みを作りました。この際、「まで繰り返す」や不等号」の使いかtがまだだったので、問いかけをしながら一緒に作っていきました。クリアとオーバーのコード止めまでできて完成はしました。 完成して残り10分しかなかったが、作る意欲は高かったので、続いてリンゴキャッチを作りました。西遊反転の謎の止まったが、動画を見て解決できました。', 'リンゴキャッチの続き', 'タイピング: 集中してやっていた
盛り上がり: 変数名がこだわりがすごかった'),
  ('0818d921-b1e8-50a9-a5ed-a507f3d27d72', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-19', '16:30:00', null, '通常 / 基本操作コース10_キャッチゲーム スコアとゲームクリアの作成 変数と「～まで待つ」の復習、確認', '使うスプライトをコインに変更し、コスチュームを工夫しました。スコアのプログラムは得点の加点はとてもよくできていました。ゲームクリアのスコアの設定では「～で待つ」を使うことをリクエストしましたが、方法が分からず困っていたので一緒に復習しました。「もし」を使う方法はしっかりできるようです。ゲームクリアの背景のプログラムもよくできていました。 アレンジとして、キャッチする刀の大きさが変わるプログラムを作っていました。着眼点が面白かったです。', null, 'タイピング: 集中して取り組めていました。'),
  ('f6080c25-7f46-5afd-9170-c4d70a2f6dc3', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-19', '17:30:00', null, '通常 / 検定2級 応用課題1 問題011 余裕があれば、あまり「試験準備！」という感じにせずにアレンジを楽しむくらいの雰囲気で。', '40分ありましたが、35分ほどで完成していました。内容を確認しましたが、全て正解でした。プログラムの挙動も確認しましたが、問題ありませんでした。その後にアレンジとして果物の追加と全て取れた場合の特別な言葉を追加していました。なかなかアレンジ内容を考えるのが大変だったようです。 次回は1級の問題に取り組んでみたいそうなので、1級の検定問題にチャレンジする予定です。本人と約束しました。', null, 'タイピング: 集中して取り組めていました！'),
  ('f7b695e7-ea0a-5d47-924c-5324213d5ac4', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-19', '16:30:00', null, '通常 / PRG24 水泳ゲーム 作成続きとバグ探し（ブロックの数値に全角がある） ゲームがきちんと動くようにすることを目的に。', 'うまくネコが沈まないことがありました。原因を分析して間違ってプログラムしていそうな箇所を探しました。本人も、間違っている箇所の見つけ方についてなんとなく理解できた様子でした。（見本とどこが違うのか、動きなのか見た目なのか、タイミングなのかという問題の分類）その後自分で問題の箇所を発見し修正できていました。 時間の最後にネコが折り返さなくなりました。原因が分からず持ち越しになったので、来週確認する予定です。', '動画は17分前後まできています。もう少しで完成です。', 'タイピング: 10分ほど取り組みました。'),
  ('fa0bd6f0-c50a-5d25-a495-4cd26bceb929', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'f3bb6393-f24e-5dfd-a9d3-03590f567292', '2023-09-19', '16:30:00', null, '通常 / 選抜大会提出用作品の作成、完成 ストーリーの改訂がよくできているので、アピールポイントに漏れや弱いところがないか、一緒に確認できれば。', '前半は自分でエントリーシートの内容を振り返り（本人の要望）、後半の時間でまみさんと私で内容を一緒に確認しました。 内容は項目ごとに整理されていてとても分かりやすかったです。言いたい内容はよくわかるのですが、書き方が少し伝わりにくい箇所があったので、少し話しながら修正しました。とくに作成背景の部分が気になったので、短めの率直で伝わりやすい文を目指して一緒に考えました。', null, 'タイピング: 集中して取り組めていました。'),
  ('b6af4fb6-c546-5aff-8f83-f0040ec27206', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-09-19', null, null, '通常 / チエテラス（撮影）', 'チエテラスでは撮影用にGoogle Meetを使ったり、カメラを向けられたりしていましたが、淡々とできていました。', null, '時間帯: その他
盛り上がり: チエテラスの後は、緊張がとけたのか、珍しく机にへばりついてPCをいじっていましたが、お母さんが心配されていたほどの拒否感もなかったように見えました。'),
  ('ca3338b4-ab40-5e1d-91a1-c8d2d4e4cd3f', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-19', '16:30:00', null, '通常 / 口頭での細分化。どのようなコードが必要かある程度自力で考えられるように。', '相変わらず自分で入力することを面倒がって、すぐに「○○ってうって～」と言ってきますが、ここまでは自分で打てるよね？と水を向けると、ローマ字表を見ながら少しずつうつようにはなってきました。 前回作成していたアイスを食べにが、このままだとつまらないといって、 ・アイスを食べたら一斉におばけたちが動き出す ・おばけが動き出して10秒後にアルくんもお化けの姿になる というアレンジをしたいということになりました。 「アイスを食べたら」の判定をしているスプライトと、「動き出す」スプライトが別ということに、自分でコードを作成しようとしていて気づくことができました！この場合は、他のスプライトに合図を送るという説明をし、メッセージの使い方を学習しました。 アルくんをお化けの姿にしたいと言って、別のスプライトを用意していたので、姿を変える場合はコスチュームを変えるという説明をし、ヒントを出しながら2つめのアイディアも形にすることができました。', 'お化けの姿になったアルくんが、他のお化けに触れると元の姿に戻ってしまうのを直したいそうです。', 'タイピング: 今日は体験版だったため、一番やさしいところを少しだけやっていました。
盛り上がり: メッセージによって別のスプライトが動き出すのが余程楽しかったらしく、自分でスプライトをいくつも作成してはコードを複製して、一斉に動かしてとても喜んでいました。'),
  ('bdc572c2-d4f2-5710-a252-a111dcb664fd', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-19', '17:30:00', null, '通常 / 滑らかなジャンプの使い方に慣れよう', 'まず、今までやっていたジャンプと滑らかに上昇するジャンプの違いを見比べてもらいました。前者は上がり幅が一定だが、後者は小さくなっていることには気づけていたことは良かったです。コード作り始めると、変数によって上がり幅を調節していくことに難しく感じ、まで繰り返すの不等号の値がー２０になることは理解は進みづらかったです。ジャンプの形を完成した青砥は、それを剣を避けるゲームを作ってくれました。変数の幅を変えて、ジャンプの調節することも見られたのので、少し使い方は理解できたと思います。', null, 'タイピング: 素早くやっていました
盛り上がり: 跳ぶのがウサギで似合っていた。'),
  ('94fc7ed4-5986-53dd-afda-14423c9ef0a2', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, null, '2023-09-19', '17:30:00', null, '休み（未対象）', null, null, null),
  ('fc4989dc-601a-57ab-b788-b04dec6e5ea0', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, null, '2023-09-16', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('e207804a-7ab6-58ba-b81d-4acebf3de9c4', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-16', null, null, '通常 / 検定1級で出題される定義の問題に慣れる', '今日の目的もよく理解して、定義の部分に着目して課題に取り組めていました。 かけ算の課題で、タイマーが20を超えても結果発表にならないことに悩んでいましたが、繰り返しの中にある「もんだい」定義が最後までいかないと、その先の判定に進まないことを、実際に試しながら理解しました。 DKゲームの方では、それなりにゲームも面白かったらしく、クリアするまで何度もチャレンジしていました。参考にテキストの文章も見ながら、定義（サブプログラム）の使い方や使用する場面などについて、実際に作成しながら理解を深めることができました。 今後の希望について話す中で、自分で作りたいゲームのイメージを語ってくれたので、イメージを形にするためにフローチャートがかけると良いかも、という話をしました。', null, '時間帯: その他
盛り上がり: レッスンんの方は、定義の部分についてはスラスラと進めることができ、どの課題も集中して取り組めていました。 検定1級の準備を進める傍ら、何かやってみたいことがあるかと尋ねると、シューティングやプラットフォーマーのようなもので、ゴールがなくずっと続いていくタイプのゲームを作ってみたいと話してくれました・
備考: 中央線の運行中止のため、授業時間を16時～17時に変更して対応しました。'),
  ('68154fdf-d5c9-5ee5-b88d-32a24f882be8', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-16', null, null, '通常 / キャッチゲームの続きで、ゲームクリア、ゲームオーバーを作成する。 完成したらアレンジタイム、または応用の課題にチャレンジ。', '上から落ちてくるスプライトの種類を増やしてマイナスになる状況も作成し、自分で何度もプレイしては条件となる得点の調整をしていました。 基本操作コースが終わって30分ほど時間が余ったため、小技をいくつか見せて興味を持ったのが弾幕だったので、初めてのクローンをやってみようということで、【Prg】28 まゆネコをさがせに取り組みました。 このレベルのクローンはすぐに理解できて、スプライトを完全に入れ替えて、ゆうかちゃんらしい、ファンシーな雰囲気のゲームにアレンジをしていました。', null, '時間帯: その他
タイピング: 安定しています。
盛り上がり: ゲームの調整などは、いつも丁寧に、そして楽しそうにやってくれています。 今日も、どちらの課題にも丁寧に取り組んで、自分なりのアレンジも楽しんでいました。
備考: 検定の話をお父さんとゆうかちゃんにしました。前向きに考えている雰囲気でした。'),
  ('fe68b23d-bbc0-53cf-9154-836483b87913', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-16', null, null, '通常 / 実力を確認する', 'いつも通りレッスン時間が始まったあともロブロックスで遊び続けてしまったのですが、今日は10分後くらいに切り上げてくれました。検定問題に取り組み、バグはあったものの一通り解き切ることはできました。細かい答え合わせは間に合わなかったので次回やりたいです。', '検定の答え合わせから', '時間帯: その他
盛り上がり: 検定に受かりたいという熱意はそこまでないようですが、頑張るかとは思ってくれたみたいです。'),
  ('13a1eda9-631b-5849-bf6a-6979650c3526', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-16', null, null, '通常 / コードを理解して作ろう', '最初に元から作ってあるコードについてどんな動きをするか聞いてみると、大体は答えられていました。基本は動画を見ながら作りましたが、意外にもスムーズに作れました。何を作っているか聞いても、把握できていて、間違って作ったところもわからなくて放置とはならず、見直す動作はできていました。 作り終わって少し時間があったので、過去に作った虹色ピンポンがなぜかボールを跳ね返すコードが消えていたので、そこを作っていきました。何のコードを使っていたかは覚えていて、少しこちらは回転する角度を指摘するくらいで修正できていました。', null, '時間帯: その他
盛り上がり: 作っている集中力は切れずに、素早く作っていました。'),
  ('b438e447-99c9-5e28-a628-5a61a9c03e55', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-16', null, null, '通常 / 座標による動きの理解、「～まで待つ」の活用の理解', 'ジャンプするときに「～秒で座標を～にする」を使ってやっていて、きちんと動くのでなるほどと思わされたのですが、普通にy座標を変える方法のほうが応用が効くのでそちらを練習してもらいました。スコア>20でクリア、x座標<-209で右に戻すなど不等式は使いこなせました。ただ、予想よりは時間がかかったのでアレンジまでは行きませんでした。また、「まで待つ」で作りたいところを「もし～なら」で作ってしまったので、できれば次回、書き換えられることを伝えたいです。', 'ジャンプゲームの続き？', '時間帯: その他
盛り上がり: スクラッチのマリオのBGMを聞きながら頑張っていました。途中マリオで遊び始めてしまいましたがすぐ終わってくれました。'),
  ('5a95abe1-5113-5cc9-a43a-a0bd3399d88e', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-16', null, null, '通常 / 座標による動きや「～まで待つ」等の再学習', '電車の運転見合わせにより20分ほど遅刻。やや興奮気味に来室し、ゲームをしようとしたので、すぐに課題を提示しました。 1月に、一応カードの最後までジャンプゲームを作成していたはずですが、やったような気もする、程度の記憶だったので、ゲームのテストプレイからやり直してみました。 カードを見ないで作成できるか水を向けてみましたが、それよりもアレンジが気になる！とのことで自分から取り組み始めたため、本人のやる気の方向を優先して「きちんとアレンジを考えること」を条件に作成を始めました。 なかなか卵を飛び越えられないことが気になるらしく、卵のy座標や速さ、大きさなどにこだわって、時間をかけていろいろと試していました。 ジャンプするとスコアが増えるのが気になるといって、他の方法でスコアを増やせないかとしばらく考えていました。ひよこが卵を飛び越えたら卵は止まらずに左端まで動く→卵が左端についたときにスコアをカウントすればいいという思い付きは、なかなか良いひらめきでした！ このアイディアをコードにする際、「演算ブロックと座標を使う」ということまでは自分でわかっていて、このグループのブロックは苦手なんだと言っていました。（他に、調べるグループ、変数グループに苦手意識があるそうです。） 苦手とはいえ、自分のアイディアを形にするためにどのブロックを使うかということまでわかるようになったのは、あおしくんの進歩だと思われます。最後は先生の助けを借りましたが、スコアの増やし方のアレンジを完成させることができました。', null, '時間帯: その他
盛り上がり: 途中何度かScratchのゲームに脱線もしましたが、「自分のアレンジをきちんと考える」という当初の約束を守ろうとする姿勢を最後まで見せてくれました。アレンジのアイディアなど、思いついたことをコードにできたときは嬉しそうにしていました。'),
  ('c46e6b4b-6b54-5735-a564-fb050880c98c', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-16', null, null, '通常 / チーズを探せの続き', 'チーズに動きについてはどこかへ行くと乱数を使った場合で両方体験させて、乱数によるランダムを優位性を判ってもらいました。だが、作る際に座標を乱数の範囲で動かす考えは少し難しく感じていました。「もし」から「まで待つ」の作り替えは止まることなく作れていました。虫の動きについてはランダムで左右で回転はゲームから読み取れたが、作り出すには苦労していました。ゲームのクリアエンドもできてうまく完成はできました。', null, '時間帯: その他
タイピング: 丁寧にやっていました
盛り上がり: 集中して取り込めていました'),
  ('ab71df1d-bf56-5575-93cf-9b31d00790a5', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-15', '16:30:00', null, '通常 / 脱出ゲーム作成の続き', '脱出ゲームの途中から作成していきましたが、キャラクターの動きに慣性が使われていて、それを理解するのに少し苦労していましたが、完成作品を見ながらや図解での説明で理解することができていました。その後は、これといって引っかかることもなく順調に進めていき、ほとんど完成という状態まで持ってくることができました。', null, 'タイピング: 間違いも少なく、それなりの点数を取れていたので、次回からはより速さを追求してのタイピングが効率的にできるようになっていくために必要ではないかと感じました。
盛り上がり: 進捗が順調に進んでいると、自分のやりたいことや思いついたことを取り入れてみようと様々な案を出していました。'),
  ('cf8a999a-7989-5e03-883f-f61eaadc9f45', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-15', '16:30:00', null, '通常 / 集大成となるような作品を作る', '今週はオリジナルの作品を作りました。迷路の壁と動くボールをよけながらゴールを目指すゲームでした。別のゲームモードもあるともっと面白くなるかもねと伝えると、ボールの動きがカオスになるモードを追加していました。また、ゴールまでの速さを競う要素があると面白いということで、クリアタイムを計る機能をつけていました。', null, 'タイピング: 先週に引き続きローマ字の練習をしました。教室に着いてすぐに自主的に始めていて良かったです。
盛り上がり: 色々と考えてて面白いものを作ろうとしていました。'),
  ('ec4e3ab7-cfd0-5676-a584-8478e465983e', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-15', '17:30:00', null, '振替 / オリジナル作品の作成', 'PvNのシューティングゲームを作成する予定らしいです。銃の動きや弾の動きなど、ゲームの軸となってくるような部分を作成していました。できるだけ銃の発射システムにはこだわりたいようで、反動やレートなども詳細に作りたいと考えているようです。その他にも、的のデザインや銃の音などより面白みのあるゲームにしていきたいと意気込んでいました。', null, '盛り上がり: 銃のシステムについて考えている際には、様々な案を出して自分の中で整理してより満足のいくものを作り上げようと集中して作っていました。'),
  ('1297ba0c-991d-5283-b341-fc9f12b3f7d7', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-15', '18:40:00', null, '振替 / プログラミング体験', '完成されている作品を遊んでみたり、数値を変えてよりダイナミックな内容にしてみたりと、様々なことを試していました。プログラミングとは何かというよりは、ここの数字を変えると何が起こるのかを試し、どのように変化しているのかを観察や実際にプレイして楽しんでいました。', null, '盛り上がり: 授業中は様々な作品で遊んでいて、今までにやったことのないものが多いこともあり、常に楽しそうに取り組んでいました。'),
  ('3d92e343-b825-5a8a-b116-5e7f2dcfbce8', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-14', '17:30:00', null, '通常 / 大会作品作成', '自分の中で作りたい作品はイメージできているようなのですが、バグがあったので一緒に原因を探りました。「もし～なら」ブロックが覆っている範囲や不等号の向きが間違っていたので修正しました。途中ゆき先生と作品の方向性について話し合い、当たり判定に影武者を使うこと、バックボードに当たる動きをさせることなどを決めました。できれば今週終わらせたいということは本人にも伝えていましたが、やることが増えたのもあって完成までは行きませんでした。', null, '盛り上がり: 今日の目標は達成できませんでしたが、集中はしていたと思います。'),
  ('4e67150b-9f8d-5bca-aa04-360d9f97864c', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-15', '18:40:00', null, '通常 / キャッチゲームの得点をつける部分からやりたかったのですが、フォートナイトをケイトくんがやっているのを見て、俺もやりたい！とのことでフォートナイト風ゲームの作成になりました。', '最初にお約束でどんなに難しくても、最後までやり切ると約束。わからない漢字などは私が手助けをしましたが、集中してコードを移すことをしていました。途中言葉の意味を確認しながら（重力などちょっと難しい日本語の部分）行うことができました。 ただ、言われてないことを自分でこうだ！と決めつけてしまう癖があるのか、スプライト自体を消してしまい、最初からコードを移す羽目に。 ちゃんとコードを読む、移す、を徹底してほしいなと思いました。', null, 'タイピング: なし
盛り上がり: 自分で始めてやりたいと思ったゲームだったのは良かったです！'),
  ('85cde1a7-b1d1-5d91-96d6-ed9388f43843', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-14', '16:30:00', null, '通常 / 「ではないまで待つ」の使い方、順位の決め方', 'シートで細分化するのは気が乗らなかったようなので、口頭で少しずつ細分化しました。自分で作ったらキーの長押しで進んでしまったので、「ではないまで待つ」を教えました。「キーが押されたではない」はキーが離されているという意味だということや、そうすると長押ししても進まないことは理解してくれたと思います。順位の表示は自力ではできなかったので正解のコードを見せて、順位という変数の値がどのように変化するのかを共有しました。ゲームとしては完成しました。', null, '盛り上がり: 先週までで決勝大会の準備は終わったので、今回はリラックスした様子でした'),
  ('e3ed9259-f88c-5b28-b580-2e47bf3dc584', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-14', '16:30:00', null, '通常 / 細分化して考える', 'ジャンプの部分は難しそうだったので写経しましたが、その前にジャンプの動きを詳しく細分化し、「足が地面についているときだけジャンプの動きができる」「頭が天井に当たったらを終わる」などの注意点を確認しました。そうすると、コードを見たときにどういう意味かが分かっていました。ここでブロック定義を初めて使ったようなので、「ジャンプという名前の動きを自分で決めて、それを好きな場所で使える」という概要だけ説明しました。マグマに触れたら初期位置に戻すなど細かい場所も作って完成し、障害物を追加するアレンジをして終わりました。', null, 'タイピング: playgramには慣れていないみたいですが、基本的なローマ字から練習していました。
盛り上がり: しっかり理解しようとする姿勢が良かったです'),
  ('cb8a5834-1665-5058-8159-03030571f3f7', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-15', '17:30:00', null, '通常 / だるまさんがころんだの続きから 前回は乱数を確認したので、今回は「音の録音」「ピッチの速さを変えるには？」「触れた時の判定」を意識して完成まで向かうようにする。', 'だるまさんがころんだの最後の部分になると少し理解が難しくなるので動画を見ながら行いました。録音、ピッチに関しては動画をみることでピッチの速さが変わることにとても満足していた様子でした。 また判定の部分ですが、動画を見たい時にどうして「２」のコスチュームだと負けになるのか？をきちんと説明したら、「なるほど！」と本人は頷いていました！', null, 'タイピング: 最初のF~Kまでのタイピングにやってみましたがまだまだ、タイピングに関しては不得意な様子。
盛り上がり: 前回やっていた乱数の部分をよく覚えていました！'),
  ('9e196384-6652-5d52-a093-5d8c8ddf3f19', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-15', '16:30:00', null, '通常 / スプラトゥーン風のゲームの続き、ペンギンの動きがまだ出来上がってない。 https://app.arstudio.fun/projects/40940/editor', 'ひとまず最後まで動画の中身をうつすことができました。途中に変数の使い方はどうしてここで使ってるんだっけ？などの質問をしながら行い、本人もきちんと理解してコードを写していました。 なお少しバグがあるみたいなので来週はそのコードを見直してきちんとコードが書けているのかを検証します。', '少しバグがあるみたいなので来週はそのコードを見直してきちんとコードが書けているのかを検証します。', 'タイピング: 高学年の和文は文章になるので少し難しそうではありましたが、慣れてくればとても早く打ち込むことができるようになっていました。英文に関しても同様に難しそうにはしていましたが、なんとか自分が満足いく点数がとれた様子でした。
盛り上がり: 集中しコードを写していました。自分がどういうプログラミングをしているのか？を理解しているようでした'),
  ('1a36e7b1-7d09-5d0a-9162-77a84ab8bbfc', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-15', '16:30:00', null, '通常 / 【Prg】24 水泳ゲームを作ろう', '最初にゆき先生からチエテラスでやっていたコードはアルスパークでここの意味があるんだよと伝えてもらってから変数と演算の使い方自体をおさらいしてみました。 水泳のプログラムはその部分を特に大切に使うからというのをもう一度念押しした上で、水泳のコードを書き始めてみました。 どうしても動画の荒さが気になってしまったようで、少しいらいらしてはいましたが、なんとか最初のチュートリアル部分まで書くことができました。', '水泳の続き', 'タイピング: 和文も英文もなれてくるとスコアもすごく伸びていました！
盛り上がり: 自分が今何を行っているのか？を再度確認できた様子でした。'),
  ('c8c0168a-904b-57b4-898d-8f2021f11075', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-15', '17:30:00', null, '通常 / フォートナイト 前半部分から〜後半まで行う', '集中して行っていた様子でしたが前半部分が終わった瞬間に敵を作るのが難しそうと話して、少しやる気がなくなった瞬間がありました。そのかわりに星を取りに行くキャッチゲームをやるか？と聞いたら、やっぱり最後までやってみるというので後半に進むことに。 多少難しい感じの雰囲気でしたがなんとか敵が球をうつところまではできた感じでした。', '後半の19:54まで完成することができました', 'タイピング: なし
盛り上がり: 自分でアレンジしてみたいと言っていたのはとてもGOOD（最後までコードが完成していない状態ではありましたが・・）'),
  ('0d6ebda8-d35f-5024-90aa-9452ffcb4b39', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, null, '2023-09-15', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('0b617028-36cd-50e5-819d-9632f7ea1639', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-12', '17:30:00', null, '振替 / 検定１級の問題 応用２', '50分まるっと検定の問題に挑戦 最後のバグの問題の時にどうしても定義の使い方が難しかったようで、時間がかかたそう。 いくつか定義ってこういう意味なんだよ〜と話をして、なんとか理解はできたようでした。 定義の問題は講師自体も迷うポイントなのでそこまでの問題ができれば大丈夫だと伝えました。 すべての問題に対してはとてもよくできているので、検定に向けてコツコツ頑張ればよいかなと思います。', null, 'タイピング: なし
盛り上がり: 定義の問題がとても興味を持っていたようでした。次回はもしかすると定義の問題系を楽しみながら解けるようなものが良いかもしれません'),
  ('16825e8a-af65-568c-9cba-5dc67150c5be', '7d01236e-620e-5177-a6f4-af325a582aae', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-15', '17:30:00', null, '通常 / そうすけくんと一緒にレース順位で最初遊んでみるところから かずとくんは黙々タイプでこれを言えばやるタイプなのでひとまず、今まで使ってきたコードで前に進ませるというコードを自分で書いてもらう＞＞判定とキーが難しい部分だと思うので、そのあたりをどう対処するか？を一緒に考える', '最初にそうすけくんと遊んだ時にとても悔しそうにしていたが、ゲームとしては面白いと感じたよう。今日は質問という感じで今まで自分で使ったコードで表現してみよう！と伝え自分なりに途中までポイント部分を作成しようとしていた。 ①とても良かった部分 連打しないといけない〜までないまで待つは、本人にとっては難しかったようだが、「こうかな？」「多分これだと思う」など自分なりの意見が言えるようになった ②判定しているの部分で、アルくんが判定しているのか！と本人なりに答えをキチンと導き出している 答えが一つではないことを十分にわかっていて、僕だったらこうするという自主性が半年前よりも出てきたと思いました。', null, 'タイピング: なし
盛り上がり: 以前受け持った時よりは、コードを理解している感覚がとてもよく出ていたし、それに自分を持っている感が増えてきていると思いました。今日もすべてコードを完成することができ最後はとても満足しているようでした。'),
  ('b2080f63-c416-5c7b-8d76-2ef737d377d5', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-12', '17:30:00', null, '通常 / レース順位 (ではないまで待つのコード) 前回本人にとってあまり気分が乗らないみたいな感じだったらしいので、今日はある程度授業らしくきちんと明確な目標をもって進める ではないまで待つ～＞＞キーがずっと押されないためには？のポイント', '最初にレースゲームをカズトくんと遊んでみて、レースゲームの方が良いとのことでレースに。新しく習う部分なので、一旦自分で思いつくコードで連打しないといけない部分を表現してもらう→1秒待つのコードを使えばいいのかな？と自分で考えて組んでみる、という試行錯誤が見られた（コードをとても理解しているという意味） また、順位を計算するときにもう一度変数の使い方の理解をおさらい。ルールとしては「セットで使う」という変数の独特なルールを理解したようでした。', '来週はジャンプの変数、今回カウントアップの方をおさらいしたので、変数が最初から決まってる数をいれるとどうなるのか？どんな使い方のバリエーションがあるのか？をゲームと一緒に教えた方がいいかも。誰かと一緒に対戦みたいな感じの方がソウスケくんにとっては刺激になるのかなと', 'タイピング: なし
盛り上がり: 自分で取り組む、すべてをその時間でやろうとする努力さなどがとても見えました。本人もとても楽しそう（顔にはださないけど、雰囲気はそんな感じ）でした'),
  ('a3a7367d-8a97-527d-8481-2d55da8e6cab', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2023-09-14', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('db482dac-2380-52ce-a955-96a8ebc361ec', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-14', '17:30:00', null, '通常 / キャッチゲームの作成', 'キャッチゲームを動画をみながら作成していきました。かなり細かく説明されていたので、それほど苦戦することなく作成することができました。自信のオリジナリティを作品に出そうとしていて、面白いゲームにしようと努力しながら作成を行なっていました。', null, '盛り上がり: キャラクターや落下してくるものをキャッチする際のプログラムを動画を見ながら考えて作成をしていたので、さまざまな考えを出しながら作成していて楽しそうにしていました。'),
  ('d23c6b1d-8893-5ca2-8b29-d14ba06ce972', '57f45872-1f3e-5540-b676-bf9023444e39', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-14', '16:30:00', null, '通常 / 迷路チーズの作成', '今回の迷路において最も重要な内容である乱数については、乱数の性質を説明したところすぐに理解することができていました。ランダムに変化するという特徴を実際にやってみて感覚的にも掴むことができていました。', null, 'タイピング: 落ち着きながらであれば、間違わずに打つことができていました。次回からはより広い範囲をやってみてもいいと思います。
盛り上がり: この迷路ゲームの敵を避けながらチーズを獲得してスコアを稼いでいくゲーム性を学びながらの制作でしたので、楽しそうに取り組んでいました。'),
  ('0afef219-5fc7-5a56-8b58-31a3f6c049f9', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-12', '16:30:00', null, '通常 / 大会提出作品の続き', '今回は、少しだけ作品の調整をしてから提出用のアピールポイントなどを作成していました。自分の中である程度書くことが決まっていたようなので、メモ帳に下書きとして書いていました。４００文字程度の内容で、主張したいことも読み取ることができる文章だったので、次回までには完成すると思います。', null, '盛り上がり: 内容をどのようにするかの調整をしていたときは、真剣に取り組んでいました。'),
  ('13259e7d-3dd9-5971-9fed-2310c123d41a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-12', '16:30:00', null, '通常 / いらいら迷路が目標（https://app.arstudio.fun/contents/3249） なので動画でアイスをとりに行く（https://app.arstudio.fun/contents/16871） 今日は真剣にやるというのを念頭にする', 'アイスをとりにいく〜でコードのおさらい 動画で確認しているのにも関わらず、向きなどを書き間違えするので、きちんとコードのブロックを読み込むことが苦手なのかなと思います。 ヒントを出しても自分で探す気がないのが目につき、一緒に探してくれないとやらないというスタンス。ある程度厳しく教えていかないと色々と自分でやろうとする気にならないので、「さっき言ったよね〜」とあえて突き放すような感じでやってみました。 突き放すとある程度自分で探そうとはするものの、やはり諦めてしまうのが勿体無い。ひとまずは、アイスと敵に触れたら〜のコードまではできたので、次回はいらいら〜で黒い部分に触れたら止まるというコードが自分で考えられるようになるといいですね。', '次回はいらいら〜で黒い部分に触れたら止まるというコードが自分で考えられるようになるといいですね。', 'タイピング: ミスなく９５％ほどタイピングできました！
盛り上がり: やることはわかっている、のでそういう部分に関しては自信をもって書いていました！'),
  ('c831f14e-9b7f-59bb-8053-5e9ed45a8f19', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-12', '17:30:00', null, '通常 / スプラトゥーン風オリジナルゲームの作成 続き', 'スプラトゥーンの基本デザインやインクの弾け方について考えていました。より原作を重視したものにしたいようで、特にデザインにはこだわっていました。キャラクターのデフォルト状態とイカになった状態の二つを作成していましたが、かなりの時間と集中力で取り組んでいました。', null, '盛り上がり: 資料収集はどんなものを採用しようかワクワクしながらしながら選択していました。'),
  ('1d76dd39-597b-5a5e-88ef-2cfe1a3f2a8e', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-12', '16:30:00', null, '通常 / 目標はらぺこサメから逃げろ（https://app.arstudio.fun/contents/11346） 前回コードをあまり覚えていなかったそうなので、一旦チュートリアルのサメから逃げろのビデオを見てから行う（https://app.arstudio.fun/contents/4178） その後にPRGの方に行ってマウスを使って動かせる動きをやってみて、どう違うのかを確認する＞なるべく弟よりも一歩先に進んでいるということで自信につなげる', 'サメから逃げろ〜の動画で動きを確認、PRGの方へと難なく移りました PRGの方がより動きがスムーズだということを分かった上で、どういうコードが必要なのか？を一緒に考えてきちんと、マウスを使う、サメが追いかける（向かう）、食べられた後のコメントが追加されていることに気がついていました。 まだ全体的には出来上がってないので、来週も引き続きやってください。 なお、スタートの受け取りが入力していないので、そこも説明になります。', '乱数の部分、スタートを受け取ったら開始する〜の部分を作成する', 'タイピング: 一生懸命タイピングしていました！
盛り上がり: 動きがスムーズに動くととても楽しそうでした、'),
  ('40e6b9bf-fe15-5789-8572-bc135b32adcc', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-12', '16:30:00', null, '通常 / PRG２４水泳ゲームの作成', '今回の課題のメインとなる絶対値についての説明を特に重要視しての授業でした。キャラクターが泳ぐために必要なプログラムと、加速についてどのような処理がされているのかについても、すぐに理解することができていました。絶対値については、まだ学校で習っていないようだったので、どのようなものでなぜこのプログラムに使われているのかを説明していきましたが、どのようなものかを理解できてからはこのプログラムにおいてなぜ必要なのかをしっかりと理解できるようになっていました。', '水泳ゲームの続き', 'タイピング: 基本的なことはできていて、正確性もかなり高いのでブラインドタッチに挑戦しても大丈夫ではないかと感じました。
盛り上がり: キャラクターがどのようなプログラムで加速や泳ぎをしているのかを考えているときは、自分のわからないところを理解しようとしているので、とても真剣になって考えていました。'),
  ('378b62f6-ba1b-53a3-a643-7fc45c75c3f2', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-09-09', null, null, '通常 / 決勝大会用のプレゼンテーション作成、原稿作成、PowerPointのスライドショー時の操作を覚える', '相変わらず、授業時間の7～8割はロブロックスのゲームプレイでした。ただ、以前よりはこちらの話かけにこたえることも増え、画面を閉じたり隠したりすることはほぼなくなりました。 ロブロックスについての話しかけには嬉々として応じ、ゲーム仕様なども熱心に話すため、教室に来るのが嫌なわけではなさそうです。 一応、大会実行委員会から送られてきた書類を印刷したものを持参していたり、昨年度の参加者の動画を見たがったりと、多少は決勝大会を気にするそぶりもありましたが、熱心に作るのはちょっと面倒、という雰囲気でした。 それでも声掛けをするとPowerPointの画面を開き、その場ではスラスラと文字入力をするのですが、Scratchのスクショを貼るのを面倒がったりと、作品や大会への誠意は残念ながらほとんど感じられませんでした。 「作品のアピールポイントなんか、特にない」と言うため、登場人物がCO2にかわったりするところは面白かったし、テーマをうまく会話文にまとめていて、考えさせる作品になっていると思う、と、こちらから見たアピールポイントを話した時は、少し得意げな、嬉しそうな反応をしていましたが、自分でそれをプレゼンテーションにまとめるのは面倒なようでした。', null, '時間帯: その他
盛り上がり: ロブロックスのゲームについての解説をしているときは、大変饒舌で、詳しく熱心に話してくれるのですが…あのくらいの熱意をもって話せるのなら、プレゼンテーションもうまくできると思うと、少しもったいないです…'),
  ('0fd7c4d8-f17e-547a-b093-1ae27c979148', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-09', null, null, '通常 / 座標の指定と「どこかの場所へいく」の組み合わせや、座標による条件分岐の習得', '今日の目的を確認してから、ゲームプレイをして、課題に取り組みました。何のためにこの課題をするかという話もよく聞いてくれ、細分化シートも楽しそうに書いていました。 スプライトを画面上に配置するための座標の問いで、一瞬迷った様子を見せましたが、画面の表示を見て思い出せたようでした。 y座標の指定を使ってスプライトを上に配置したり、下まで落ちてきた判定をするというヒントは必要でしたが、それ以降はコスチュームの変化などのアレンジも加えつつ、楽しんで作成ができていました。', 'キャッチゲームのゲームクリア、ゲームオーバーを作成予定', '時間帯: その他
タイピング: よくできていました。
盛り上がり: よくおしゃべりしながら作成していますが、大きく脱線することはなく、基本的には思いついたアレンジを話してこちらの反応を喜んだりしている感じです。新しいスキルを覚えるのも楽しそうでした。'),
  ('0233e0fa-5ff5-50f5-a4b4-a204d917d2ea', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-11', '17:30:00', null, '通常 / 走り幅跳びの動きの作成', '走り幅跳びでの走る部分とジャンプする部分のプログラムを作成しました。*と/を初めて使ったよで、どのような意味なのか悩んでいましたが、一度教えたところすぐに使い方を覚えていました。プログラムの内容については、一つずつ分解して説明してから元に戻して考えてもらいました。流れもすぐに把握していて走る、跳ぶ両方とも理解できていました。', null, 'タイピング: 速度に関してはかなり速く、一般的な社会人と肩を並べるほどでした。しかし、ミスが少々目立つので正確性を重視していこうと伝えると、かなりの高得点を出していました。
盛り上がり: 完成したプログラムが見本の動画と同じように動いた際は、達成感を感じて喜んでいました。'),
  ('5c370faf-f8ec-5496-b807-e0c5b298061d', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-11', '17:30:00', null, '通常 / フォートナイト風ゲームの完成まで', '定義の部分で定義をどうやって使ったらいいのか？をどうやら忘れていた感じで、いくつかの部分でコードがバグってしまっていました。一緒に見返しながら、バグを潰し最後まで完成することができました。 〜までないまで待つのコードが出てきた時に、きちんと説明できていたのでやはり今までやってきた内容自体は定着できているなぁと思いました。 最後ゲームクリアはないのか？と話していたので、もしかすると来週はそこを作りたいというかも？', null, 'タイピング: 4文字〜5文字のタイピングのレベルまで進んでいる様子。難しいと言いながらもきちんと漢字として成立する言葉のタイピングが打ち込めるようになってきました。'),
  ('ebe3ae9f-4191-5986-ba6f-d83a6d9caf00', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-11', '16:30:00', null, '振替 / 『だるまさんがころんだ』のポイントを最初に説明 ①コスチュームが変わるのはなぜ？②乱数でアルゴンが振り向くタイミングが違う＝乱数の理解＞＞乱数のチュートリアル', '今日はだるまさんがころんだを誰かがそうちゃんのログインで入っていたため、最初にゲームをやってしまいましたが、そこから乱数の理解を深めるためにどうしてこうなっているのか？を説明してもらい2点のポイントの部分をやっていきました。 コスチュームに関しては今まで本人にとって興味がなかった部分だったためか、まだまだすんなりとはコードを思い出すことはできなかったですが、今回のゲームでコスチュームを変化させることの重要性を理解した感じでした。 乱数はチュートリアルをみてから行いましたが、「毎回違う」という風に回答できていたので、乱数ってこういうものなのかというのは実際に使って理解できていたようでした！', 'ねずみとチーズ迷路', 'タイピング: まだFGHJの総まとめができない様子でしたが少しずつどの文字が対応しているのかは理解できてきた感じ。丁寧にタイピングするようになりました。
盛り上がり: 乱数を理解できてとても楽しそうでした！ゲームがこれで自分でもすこしづつ作っていけるという感じというのでしょうか・・'),
  ('63d8530f-5585-5d9f-9616-110ae5523bc9', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, null, '2023-09-11', '16:30:00', null, '休み（未対象）', null, null, null),
  ('84217336-b98c-587f-b357-d4e467471a52', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, null, '2023-09-04', '16:30:00', null, '休み（未対象）', null, null, null),
  ('f6afeb7b-5329-50a2-af4d-343fd8cb33ad', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-07', '16:30:00', null, '通常 / 動きやブロックを細分化して考える', '全体として見ると少し複雑なコードですが、一つ一つ分解して考えていきました。まずはネコの左右移動でしたが、キーが押されたときにx座標を動かすことはできていました。ここで、左右の移動は並列だからまとめてしまってもいいことを助言しました。壁で止まるようにするところは、チーズをさがせでもやったねと伝えましたが思い出せなかったみたいです。壁で止まるにはどのように座標を動かせばいいか、再びイメージをもってもらいました。ジャンプの定義やリスポーンの処理が残っていますが、このままいけば次回完成できそうです。', '続き', '盛り上がり: ゲーム作成はやはり楽しそうに取り組んでいます'),
  ('eb630de9-3b14-5f05-a046-b5c1c97deb84', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-09', null, null, '通常 / 基本的なコードを使ってシンプルなコードを作成する', '自己流でやって手詰まりになることがないよう、テキストの流れに沿って進めました。障害物を繰り返し流すところで困っていたので、障害物をどのタイミングでどの場所に移動させるかなど問いかけると解決しました。やったことのないプログラムを自力で考えながら組むことはもう少し練習したほうがいいかもしれません。スコアの加算やゲームオーバーの演出はあまり時間をかけないうちにできました。一通り完成したのでクローンを使った背景スクロールを勧めましたが、「もっといい方法がある」と言って、スクロールの様子を写したgifファイルを自作して使いました。', null, '時間帯: その他
盛り上がり: 少しめんどくさいような様子や発言を見せていました。しかしそこまでハードルの高くない題材だったのできちんと取り組んではくれました。'),
  ('bb14ccc2-dcc6-513b-8f56-45eea391a8e9', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-08-28', '16:30:00', null, '通常 / 背景スクロールを完成させゲームに生かす', 'スクロールさせるには背景画像を連続して表示していきますが、どうすればそれができるかを聞くと、クローンを使う方法が思いついたのでその流れで進めました。どのタイミングで次のクローンを出すかなどを紙に書きながら一緒に考えていきました。ひろとくんは考える力があるので、少し難しくはありましたが無事にスクロールさせることができました。ジャンプゲーム本体についてはそこまでハードルが高くなく、自力で完成までたどり着きました。', null, '盛り上がり: 真剣に考えて試行錯誤する姿勢が良かったです。'),
  ('ab64bad6-ee1b-5032-a1d1-da0862fa8c2c', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-09', null, null, '通常 / 細分化しながらゲーム作成', 'まず迷路の形を自分好みに変えました。その後各スプライトについて一緒に細分化しました。迫ってくる壁については「左から右に動く」と言語化してコードにも直せました。複雑なアルくんの動きも順番に細分化しようとしましたが、難しかったようなので写経に近い形で完成させました。その際、それぞれのコードが何をしているのかを共有しました。', null, '時間帯: その他
盛り上がり: 今日のそうたくんの題材は以前あおしくんがやったものだったので、一度助け舟を出していました！'),
  ('94f0870b-89ac-5571-8140-728e247f9126', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-09', null, null, '通常 / 今までやったブロックを組み合わせてゲームを作る', '座標の概念はよくわかっているようで、ボール(地球)を打ち返すバットの動きについては、少しヒントを出すときちんとバットのx座標=マウスのx座標にできていました。打ち返されたボールは角度を変えればよいことも思いついていました。ゲームオーバーの処理などもして完成しました。アレンジとして、打った時にバットの角度を変えていて面白かったです。', null, '時間帯: その他
盛り上がり: あおしくんの作っている迷路脱出ゲームがかなり気になったみたいです'),
  ('307f5fda-c823-55fb-b287-62e24f5c6158', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-09', null, null, '通常 / 04 迷路脱出ゲームの作成', '見本である迷路のプログラム内容については、どのような動きをするのかをほとんど理解していました。プログラムにおける流れを掴んでいたので、サクサクと進んでいくことができました。余った時間でオリジナルのコースやゴールを作成していました。', null, '時間帯: その他
盛り上がり: オリジナルのコースを作成している際に、自分のやりたいことをステージ内にしっかりと残そうとしていて、終始楽しそうに作成していました。'),
  ('2df0b5af-0a04-5b0d-b6c8-a4458f2e40a2', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-09', null, null, '通常 / 基本操作コース06_物語を作ろうの作成', '基本操作コースの２と３で行ったことの復習を兼ねてのレッスンでした。教えていったことは素直に取り組んでいて、今までの応用が出てきた時にはやったところを使うということをしっかりと、理解して取り組むことができていました。', null, '時間帯: その他
タイピング: 50音の基本をしっかりと復習していました。
盛り上がり: キャラクターやセリフの選択時には自分のアイデアを使っていこうとアレンジをして作成していました。'),
  ('6e29fa37-a23b-556a-9dba-d501634cb860', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-08-26', null, null, '通常 / ではないまで待つの練習', '基本は自力でやってもらいましたが、あまり歴の長くないそうたくんには厳しそうな部分もあったので、そこは写経もしながら進めました。ポイントとなる「ではないまで待つ」が何をしているのか、そしてなぜ必要なのかについて問いかけをしました。すると、夏休み前に別の題材でやったらしく、思い出すことができました。順位の変数は少しわかりづらいので、いつ値を変えて表示するのかを時系列で一緒に確かめました。ゲームは完成し、コスチュームに軽いアレンジも加えていました。', null, '時間帯: その他
盛り上がり: 最初のほうは遊んでしまいましたが、切り替えたあとはしっかりやっていました。'),
  ('88458e0b-8fbb-5e1e-9443-7325146c7886', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-07', '17:30:00', null, '通常 / タイピング、スキルチェック', '仲のいい聖くんと一緒の題材をやろうということで、ブロック崩しゲームを作りました。まずはボールの大きさやコスチュームを調整しました。このとき、「～にする」と「～ずつ変える」がごっちゃになってしまったので違いを確認しました。 ボールを打ち返すバーを操作できるようにするにはx座標とy座標をうまく設定する必要があったので、座標の概念を復習し、「マウスのx座標」というブロックを使う必要があることを共有しました。今日は最後まで終わらなかったので、メッセージの送りあいは次回やる予定です。', '続き', 'タイピング: 少し大変そうではありましたが、頑張って練習しました。ローマ字を覚えきれていないとのことだったので、色々な文字を一つずつ練習して身に着けました。
盛り上がり: 関係ないことを聖くんと言い合う場面が多かったので2人の席を離したところ、少し改善しました'),
  ('07be0b07-7278-5c44-b6a0-5a065c5b5d69', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-07', '17:30:00', null, '通常 / ブロック崩しからつくる', 'バーの動かし方に、やったことはあるけどどのブロックか思い出せないになって、過去のピンポンに不利かってできました。きほん、ピンポンと同じなので、ボールの跳ね返りお条件やブロックの消し方などはスムーズに作れました。バーとボールの反射は難しいのでコード見せながら軽く説明はして、なぜ向きが「180-（向き）」となるかは理解できていました。随所メッセージで描いてほしいところも迷わずできていたので次回くらいでできると思います。', null, 'タイピング: キーボードを見ながら止まらずにやっていました
盛り上がり: まさき君とのあおり合いがすごかったです'),
  ('dcee2b43-dedc-5f2b-9e2d-b686be0a265e', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-07', '17:30:00', null, '通常 / 選抜大会用のバスケットゲーム作成', '前回の続きから作成に入っていました。 バスケットのゴールの仕様をいろいろと試行錯誤していて、どの位置にあたったらゴールに入る設定にするかを悩みながら作成していました。 シュートのボールの動きは大体できてきたようなので、この後いかにオリジナル要素を付け加えるかを相談しました。この後、シュート練習をするに至る過程を少し作成するそうです。', 'おうちの方から、今度はレッスン1回分の余裕を見て完成させるようにと言われているそうで、一応次回で完成レベルまで持っていきたいそうです。', '盛り上がり: バスケットの動きにはこだわりたいようで、どうしたら思ったようなゴール判定になるかなど、楽しそうに考えていました。'),
  ('4e7b98d3-833e-550e-8def-55cf5029c693', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-07', '17:30:00', null, '通常 / 決勝大会用のプレゼンテーション作成、原稿作成、PowerPointのスライドショー時の操作を覚える', '授業開始時には、プレゼンテーション作成を面倒だと言っていましたが、「文章を書くのは得意なのでは」と水を向けたら、すごい勢いで作成していました。 WindowsにおいてのSnipping Toolの使い方とファイルの保存の仕方を教え、作品のスクショとPowerPointへの貼り付け方を教えました。 プレゼンテーションに必要な3項目を一緒に確認し、ひとまず完成までもっていくことができました。', null, '盛り上がり: 口では「面倒」などと言いながらも、文章を書くのは気持ちが盛り上がるのか、作成に入ると一気に長文を打っていました。 「朝はやい」「順番が最後なのがいや」等ぼやきながらも、「パソコンをもらえるかどうかはいつわかる？」などと、楽しみにしている様子も見せていました。
備考: ゆき先生の確認が済んだら、そのまま提出してほしいようなことを話していました。'),
  ('da7262b6-40b8-5a11-b6c3-fb2812e77fb2', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-07', '16:30:00', null, '通常 / コードづくりの試行をしよう', '最初に前回完成したサメから逃げるゲームで重要なコードを復習しました。ずっとや何回繰り返す、メッセージの役割を聞いてみたところ、答えられないものの説明をしたら、「あっ、そうだった」と納得するような返事が返ってきたので、頭の奥底には考えはあった高尾tがわかりました。 次のゲームとして、チーズを探せを作り始めました。このゲームの基本となる十字キーでミミを動かすところを自分で試しながら作る形をやってみました。え、わかんないが少し口癖気味だったので、必要なブロックは用意して、どの順番で組めばよいか試してみた。かなり時間をかけて正しく組めたが、何となくこのブロックで使ったら動くを順番の形で覚えさせることができる手助けをできた気がします。これで、結構疲れてしまったが。最後にほかの3方向を複製するときは、向きを変えることはすぐ気づけました。', 'チーズを探せのつづき', 'タイピング: 迷うことなく進められました'),
  ('ba5aa4d2-44c5-512b-a46b-79accc59cbc8', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-07', '16:30:00', null, '通常 / 決勝大会用のプレゼンテーション作成、原稿作成、PowerPointのスライドショー時の操作を覚える', '自己紹介の紙は忘れてきてしまいましたが、家で話し合った内容は覚えていたようで、スムーズに作成に入ることができました。 文字の強調の編集が気に入ったようで、やたらとB、I、Uを多用していましたが、本人が「これが目立っていい」ということなので、思うように編集させてみました。 スライド内でのアニメーション効果はあえて教えませんでしたが、スライドの切り替え効果はかなり楽しかったようで、盛り上がって編集していました。（一応、派手な効果をやりすぎても大切なところがわかりにくくなるという話はしましたが、それを踏まえた上で、りょうやくんなりに効果を考えて付け加えていたので、最終的にはりょうやくんが良いと思うように作成してもらいました。） スライドショーのやり方もすぐに覚えることができました。 ノートの部分に原稿を打ち込み、当日は印刷して手持ちしたときに読みやすいよう、フォントを大きめにして完成させました。 最後のスライドの感想が少ないため、家で話し合ってくるそうです。', null, '盛り上がり: プレゼンテーション作りも楽しんで取り組んでいました。とにかく、何かを作ることが好きなようです。 画面切り替え効果なども、熱心に試しては楽しそうに選んでいました。 当初は人前で発表することにしり込みしていましたが、準備をしていくうちに楽しくなってきたのか、当日の案内のPDFを見ながらお辞儀や退場の練習までしていました。
備考: お母さんによると、今までも色々なことに興味をもったものの、広く浅く取り組んできたため褒められることはあまりなかったそうなので、今回の受賞はご家族内でもとても喜んでいて、りょうやくんの晴れ舞台！と楽しみにしているそうです。'),
  ('392808f7-bc1f-5a9f-8e5c-063d7132d21f', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, null, '2023-09-07', '17:30:00', null, '休み（未対象）', null, null, null),
  ('b48a39ee-6543-5269-9bbb-431730838d50', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-05', '17:30:00', null, '通常 / スプラトゥーン風オリジナルゲームの作成 続き', 'スプラトゥーンの大量の武器をどう取り入れるか、いろいろと自分で調べながら考えていました。作成したい武器をリストから選んだり、その効果をどのように作成するか、参考になる作品を見たり、自分で少しいじってみたりしながら進めていました。', null, '盛り上がり: 今回のゲームはしっかりと作り込みたいようで、いろいろと研究しているようでした。公開されているスプラトゥーンのゲームで遊んでいるようなときもありましたが、以前のようにただ遊ぶだけではなく、コードを見たり組み替えたりと、一貫して参考にしようという姿勢が見られました。'),
  ('d2dd393f-7bac-5a4d-a382-478c0f645b95', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-05', '17:30:00', null, '通常 / 検定2級問題にチャレンジ', '前回取り組んだロケットの問題の復習から始めました。乱数のところと「答えを聞いて待つ」がわからなかったとのことなので、乱数が必要な意味と、それを変数に入れている意味を一緒に確認しました。その後、口頭で「2ケタ同士の足し算」「九九の問題にする」などの質問にも答えることができていて、本人も納得した、との感想でした。 「答えを聞いて待つ」にブロックについても、実際に動かしながら確認ができました。 続いて問題②にチャレンジしましたが、「じゃんけんの勝ちの判定」のところだけ、どうしてもわからなかったとのこと。「かつ」と「または」のブロックの説明をし、勝つパターンを並べていく箇所の解説をしました。本人によると、条件式が長くなるのでよくわからなくなった、とのことでした。', null, 'タイピング: 特に問題なく取り組めていました。
盛り上がり: 検定問題自体には、やる気も見せて積極的に取り組んでくれました。 試験後も、「どこがどういう理由でわからなかった」と自分の言葉で説明できているため、こちらの解説もスムーズに進み、ゆずとくんも納得して授業を終えているようでした。'),
  ('7c78e31c-5573-5c8e-9a94-9f60f5d88f2b', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-05', '17:30:00', null, '通常 / コードのテクニックを増やそう', '新たなスキルのために単元別のAをやりました。全体的に、持ってくるコードのブロックはいいがコードの順番が上手くいかないことが多かったです。問題文から必要とするブロックを持ち出せている洞察力は良くできています。ずっとの位置があやふやでコードが上から下へしか流れないことが身についてなくて少し難しく感じています。そして、不等号の使いやすさや色判定のあいまいさも知れてよかったと思います。', null, '盛り上がり: 見える見えないのところは魚でまるで泳ぎ隠れているのが伝わってきました。'),
  ('7fff90db-cce5-5b98-8386-d330595f944a', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-05', '17:30:00', null, '通常 / フローチャートで選抜大会の計画、構成 作品の作成に入れれば', '作成したフローチャートを見せてもらい、どんな内容なのかを説明してもらいました。親子大会の後、フローチャートを元にストーリーも考え直したそうで、かなりドラマチックな作品に仕上がっていました。 はじめのうちは、担当が変わって慣れないせいもあったのか、言葉数も少なめでしたが、授業後半は作品の意図や作成過程についてなど、熱心に話してくれるようになりました。 ストーリーは一生懸命に考えたようで、会話や説明部分なども学習教材にふさわしいボリュームでよくできていると思われました。 作品自体は楽しめるものに仕上がっているので、前回の作品からどう発展してこの作品になったかということや、アピールポイントなどをうまく文章にしていくことで、印象に残る作品を目指そうと話しました。', 'アピールが苦手だと本人が言っていたので、次回からは、そのあたりを一緒に考えようということを約束してあります。', '盛り上がり: ストーリーを親子大会から変えたことや、はるちゃんが工夫したところなどを、熱心に教えてくれました。親子大会の結果のせいか、授業初めは作品を見せるのにもおどおどした感じでしたが、後半は少し自信がついたのか、嬉しそうに作品について説明をしてくれるようになったのが印象的でした。'),
  ('3feed326-9f95-50f1-9582-fa607ac52b00', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-05', '17:30:00', null, '通常 / いろんなゲームをふれよう', 'いろんなゲームに慣れさせるために、だるまさんがころんだを作っていきました。遊んでから作ろうといった後、少し時間がたつと、ただ音をいじっているだけでコードを辞退は進んでいなかったので、まずはアルくんから方針を立ててあげました。途中模写していくうえで、見たことないブロックある？と聞いたが、反応が薄かったので、「コスチューム#」は何かわかるときいて、やっとわからないと意思表示してくれたので、そこは見逃さずによかったです。その後は順調に作りあがってゆき、完成はできました。 少し思うところは、モチベーションが表面に現れないので、やる気がある稼働側か憎くて判断が困っています。たまに椅子でダラーとなっているときはどうなんでしょう？', null, 'タイピング: ゆくうりやってた'),
  ('7f6814b3-c91e-554e-8867-de0bab0f2393', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-05', null, null, '通常 / 前回の続きのScratch、またはチエテラス', '今日は久しぶりにチエテラスからやってみる、とのことで、2進数の四則演算部分をやっていました。計算用紙が必要か確認しましたが、特にいらないと言って問題なく解けていました。 20分ほどチエテラスをした後、自分でアルスパークに切り替え、新幹線の制御盤？を作成していました。何度か声掛けをしましたが、今は、自分が面白いと思ったScratch上の作品を真似て作ることが楽しいようで、熱心に作成したり調べたりしているので、たまに作成中のものの説明を聞いたりする程度にとどめておきました。', null, '時間帯: その他
盛り上がり: 淡々としながらも熱心に手を動かしていました。 雑談等の声掛けはたまに向こうからしてくることもあるので、教室で好きなことをしながら息抜きを楽しんでいるようにも見えます。'),
  ('8d30c2e9-2a04-5c47-8950-cfc492a11746', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-05', '16:30:00', null, '通常 / コードを思い出そう', '2か月ぶりだったので、ゆっくり動画を見ながら、宇宙バトル1で復習しました。コードを覚えているか不安だったので、動画をまねして、動画からそれそうまたはわからず進めてそうになったら、補足してあげました。そしたら、意外とつきっきりにならず、できたら見せに来る来るくらいでやりやすかったです。最後の敵に当たったら止まるも作り終えていてよいコードならしになったと思います。２くらいまでは勧めてもいいと思う。最後に大きさを変えて、なインドも変えることもできていました。', null, 'タイピング: あきしょうであまり続きませんでした
盛り上がり: イチゴの反乱は結構得意になっていました。'),
  ('6e5a3deb-62ef-5458-a9d4-f66b6fcf2772', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-05', '16:30:00', null, '通常 / 基本操作コースの最後の課題に挑戦。座標のあたりを丁寧に復習する。', '最初にゲームの完成版で遊ばせたところ、あまり面白くないと言っていたので、ファイルを見せて「これで初級コースが卒業だからがんばってみよう」ともちかけると、少しやる気になってくれました。 ランダムに落ちる場所を設定するところは「俺、これ知ってる」といってすぐに「どこかの場所へ行く」ブロックを持ってきましたが、「必ず上に出現する」ように設定するのは、実際にスプライトを動かして、「上にある」ということはどういうことかというヒントが必要でした。 落ちてくるスプライトが下端まできたときに上に戻すには、という問いかけで、すぐに「地面」スプライトを出してきて、「地面に触れたら」という条件を作成していました。これはこれで、しょうたくんのアイディアが良かったので、そのまま採用しました。作成できた後で、「ほんとはどうやって作るの？」と自分からきいてきたので、座標で指定しているブロックを見せたところ、納得していました。 キャッチする側のスプライトの左右の動きも、自分で向きを指定してから〇歩動かす、というブロックで作成していました。x座標を使用するテキストとは違いますが、これまで習ったことをよく覚えていて再現できていることを褒めておきました。 キャッチしたときの動きは、物騒なものにはなりましたが、本人なりにコスチュームを変えたりして工夫して作成していました。', 'このゲームは、終わりがないというのも面白いと思う、などと言っていましたが…一応、スコアをつけてゲームの終了を作成することを伝えてあります。', 'タイピング: 久しぶりと言いながらがんばっていました。
盛り上がり: はじめのうちは、ゲームの面白さがイマイチだと言ってだるそうにしていましたが、しょうたくんが覚えているブロックで、自力で作成できていくうちに、集中して楽しそうになっていきました。 キャッチゲームというよりは、落ちてくるものを切るゲームになりましたが、しょうたくんなりのアイディアも取り入れて、盛り上がって作成できていました。'),
  ('dc49a510-d28d-5f18-9b1c-6a2444725fff', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-05', '16:30:00', null, '通常 / コードを思い出そう', '約2か月振りの授業だったので、復習もかねて宇宙バトル１から振り返りました。見せた時、簡単すぎるじゃんと豪語していたので、動画を見せずに作ってもらおうとしました。だが、いざコードを作り始めると、手が止まっていたので、動画の途中のコードの流れを見せながら、少しでも考えながら作ってほしいと思いとやりました。コードは思い浮かばずに、どうやるのや、このコード知らなかったとか出てきたので、コード知識不足でした。ほかの子を見ているとイラストに作りこんでしまう癖があるので、それで進みが遅くなったこともあった。今回は、あえて動画を見せずに考える中心にやってみたが、考える上のコード知識不足でいまいちだったので、動画を見せてみるのもありかと思います。', null, 'タイピング: まずまず
盛り上がり: コスチュームの色の配色がすごく凝っていました。'),
  ('bbb89564-d872-5c0a-a6e3-d3f168e4415f', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-05', '16:30:00', null, '通常 / シンプルなコードの作成と、コードの並列に慣れる', '前回の幅跳びが作成できたことが、自信になっているようでした。「私は幅跳びがつくれたから～」とやる気を出す場面も見られました。 作品自体は前回よりも少し易しくなっている分、自分で考えるところを増やし、迷路のかべを通り抜けないようにするコードなども、これまでの学習から思い出させるように仕向けました。 コードの順序や並列する箇所で何度か「これでいい？」と聞く場面もありましたが、ヒントを出すと概ね自己解決ができ、楽しそうに作成できていました。 ゲームの難易度が、クリアするにはかなりギリギリだったのが面白かったらしく、スプライトの幅や速さなど、いろいろ調節しては面白がっていました。', '「次は何を作るの？！」と楽しみにしているようでした。', 'タイピング: 記録に挑戦しようと何度か頑張っていました。
盛り上がり: ゲーム自体もとても楽しんで何度もプレイしていましたし、作成も難易度がちょうどよかったのか、集中して一気に作り上げていました。 今日も一つ完成できた、というのがとても満足そうでした。'),
  ('9e848b43-b099-5ed3-83a6-26be5a96c319', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-04', '17:30:00', null, '振替 / 一旦おさらいとしてはらぺこサメを。ヒントを出すとおそらく大体は理解できるかと思うので、一番難しいマウスポインターで魚が動くのと、～まで待つのコードを使うことを最初に教える。', '物を動かすときに、向きと歩くで分けて考えることが難しい様子でした。しかし「マウスポインターへいく」「マウスポインターへ向ける」を伝えると、自分で考えてプログラムすることが出来ていました。「～まで待つ」のブロックの使い方に少し困っている様子でしたが、見本を見て話し合いながら解決できました。メッセージもしっかり使い、クリアの様子もアレンジしてプログラムできていました。 迷路チーズではネズミの動きをプログラムしました。壁のプログラムは少し考え方が難しかったようです。次回からはチーズを動かします。', '迷路チーズ続き', 'タイピング: 集中して取り組めていました。'),
  ('67d051a4-6002-5621-9da1-1e794e757e21', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-04', '17:30:00', null, '通常 / フォートナイト風ゲームの続きから', '今日は敵の動きを作る部分から、途中ちゃんと動きができているのかゲームをしながら確認。ちゃんとプレイヤーが壁を製造できるかを見てから敵の動きを作り始めました。 定義の難しい部分でも自分でこのコードはここだなというのが理解できており、バグを潰すなどの作業はとても良くなってきたなと思います。 敵が球を打った部分に関しては座標の動きが関係するため多少難しそうにはしていましたが、概ね後半の方まで来ているので十分学びになっているのかなと思います。', '後半の２３：００〜', 'タイピング: タイピングもとてもミスが少なくなっていた様子です。一番初めから比べたらとても成長したなと思います。
盛り上がり: 最後まで集中し、動画の後半も残り1/3までコードをすらすらと書いていました！'),
  ('1d8f64ab-73b8-5f7f-a681-2f9a94d282b2', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-04', '17:30:00', null, '通常 / ・キャッチゲーム星取のラスト（クローンで星を増産するやり方も教えました） ・バレーボールキャッチ（変数で向きを定義と右と左で違う動きをとることができる） ・PRG23走り幅跳び', '今日は最初に星取の部分でクローンでも星を増産することができることを学び、その後バレーに移行。ジャンプの部分とキャッチを合わせるゲームなんだということを理解した上でだったので、概ね自分でコードを書くことができました。 変数で向きを変えることで、変数をうまく使うと左と右で違うジャンプの仕方もできるということを理解したようです。 本当は上記の部分を学んでいるとprg21の方がとてもよい学びになるかなと思ったのですが、やったことがあったので２３の走り幅跳びの方を行いました。', 'prg23の続き〜プレイヤーが飛ぶ〜から', 'タイピング: スコアが今日は落ちた様子でしたが概ね早く打ち込めるようになった様子です。
盛り上がり: 変数で向きを変えることを今回は学びましたが、ちょっと今日もおねむの感じで話半分で聞いてました。ただPRGのほうで変数で向きを変更するというのをもう一度やった感じなので理解はできたかなと思います。'),
  ('52071cdf-61e3-5b8e-a721-cbb6136567d5', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-01', '18:40:00', null, '通常 / チーズ迷路の下準備：イライラ迷路', 'チーズ迷路は遊んだことがある様子でした。イライラ迷路では「壁を認識する」ということを確認してもらいました。チュートリアルを見ながらやってもらいましたが、スプライトやコースに自分なりにたくさん工夫していました。壁の色が黒ではなかったですが、プログラムを書くときに自分で決めた色でプログラムできていました。最後にゲームクリアやゲームオーバーの画面を作成していました。 あまり好きなゲームではなかったそうです。チーズ迷路の方が気になっている様子でした。', '自分が作ってみたい作品もあるようですが、プログラムよりビジュアル重視のものみたいです？？', 'タイピング: 集中して取り組めていました。'),
  ('5d343617-a2b8-54cb-93cc-6817042fa4f2', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-01', '17:30:00', null, '通常 / 乱数の考え方、迷路チーズに取り組む', '乱数の考え方をチュートリアルで確認しました。最後に乱数の考え方を確認すると、なんとなく理解できていた様子です。 迷路チーズでは最初にチーズの動きをプログラムしました。乱数を使って考えるように促しましたが、座標を使ったブロックを使うことは考えにくかった様子です。「ねずみと触れたとき」の考え方はできていました。 ねずみの動かし方について「～キーが押されたとき」というのをやったことがなかったそうなので共有しました。次回は壁を貫通してしまうことを直す予定です。', '壁の貫通を治す！', 'タイピング: ミス率0％でした！すごい！！'),
  ('e50f120b-2025-529a-be37-5d615a4f4e1c', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-01', '17:30:00', null, '通常 / フォートナイト風ゲーム', '長時間集中して取り組めていました。変数や定義を作るときに長めのタイピングがありましたが、表を見ながら全て自分で頑張っていました。定義を使うときや、記入する数字を間違えやすい場面もありますが、それもなく、丁寧に取り組めていました。画面スクロールがうまくいったときは満足そうでした。動画は37分31秒まで進みました。', null, 'タイピング: 集中して取り組めていました！'),
  ('717ea116-be22-5421-81c2-b201c37bdee5', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-01', '16:30:00', null, '通常 / 脱出ゲーム', 'ボールを取り、点数を入れ、ボールを消すプログラムを作っていました。スクリプトが増えてプログラムが大変そうだったので「または」を使うことを提案しました。自分でよく考えて整理することができていたので良かったです。 ボールによって点数が入らなかったり、ボールが消えなかったりすることがありました。ボールとスラボーの両方から「～に触れたら」と「消える」のブロックを使っていることが原因だと思われます。一緒に原因を考えましたが、解決することができませんでした。一度全部クリアにして動画に立ち返るのが良いかと思います。', '全てのボールが消えて点数がうまく入るようにする', 'タイピング: 集中して取り組めていました。'),
  ('aad67720-fec9-514f-9d84-567620aa91b0', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-01', '17:30:00', null, '通常 / 単元別Gの問題２～ 以前１をやっていたので、その続きから。今回の演算は検定３級にもでてくる内容もあるため、条件分岐と合わせてどれぐらい実力がついたか再度確認したい。 それが終わったら、好きなゲームか、まだ教室にはないけれゾンビゲームを動画見ながらやってもいいかも「この時にはるくんが作ってくれたらみんな遊べるから」と気分をのせてあげるといいかも https://www.youtube.com/watch?v=n0fHJofxWbk&list=PLWKGhDFS9KJho8kxPraN0dqJ0Gz0sczYz&index=10 大元のゲームは削除されている 素材はあり：https://scratch.mit.edu/projects/711060444', '今日は検定を意識しすぎたせいか問題の文章だけで作成するというのがわからなかった感じ。 何回か分割してヒントを出しながらやったのですが演算系と変数系が合わさってしまうと一気に自分にはむりというマインドになってしまいその後が立て直すのが難しかったです。 なので最後はゾンビゲームを最初から動画をみて作ろうと話して、途中までは真剣に作成をしてくれました。', null, 'タイピング: やる気が今日はあまり感じられずタイピングもちょっと上の空気味でした。
盛り上がり: 難しいと一回思ってしまうとテコでも動かず・・演習問題系は一回外した方がやはりいいなと思いました。 PRGも動画の画質が悪いと言って、あまりやってくれないので動画が綺麗なもので写経をさせる方がいいのかな・・・'),
  ('57893de3-5677-52fc-85c4-8b5d6dc64b68', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-01', '17:30:00', null, '通常 / スキルチェック はらぺこサメの最後ゲームオーバーまでを完成させる 多分全部終わると思うので、ここが終わったらドリル、レベル１の問題９～１１までを行うと良いかも。動きなどはわかっているはずなので今度はコスチュームを変えながらで動かせるかをチェック', '目標を今日は持ってやっていたのですが、やはり集中力が途切れてしまい最後まで完成とはいかず・・しかし自分でもこの動きは、このコードだというのを紙を見ながら確認はしていました。ちゃんとお約束した部分まではやろうとするので、プログラミング自体は好きなんだなぁと思いました。 見た目の部分の理解をもう少しした方がいいかな。。。表示と隠すの関係', '食べられた・・・の部分を完成させる', 'タイピング: まだ最初のステージのまとめがクリアできない様子。ゲームを探す際にも全部やって〜みたいな感じです。楽しくはやっているのですが・・なので今後は私たち先生も「これ打って〜」と言われても自分でタイピングの練習をしようねとお約束しました。 ＞このままだと甘えて自分でタイピングの練習をしなくなってしまうため
盛り上がり: サメが動き始めたら、やっとゲームらしくなった！と喜んでいました。'),
  ('eb686604-d2a9-56cf-ac5e-5bb01f3f8838', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-01', '16:30:00', null, '通常 / 先週アルスパークがやりたいと言っていたのでスプラトゥーン風のゲームを動画を見ながら行っています。12：52の部分から開始 https://www.youtube.com/watch?v=B4Ksy6_jsgM', '今回作っているゲームは比較的今まで学んだことの集合なので、一個一個丁寧に動画をみながら作成をしていました。途中途中、変数のルールってなんだっけ？やここで〜回繰り返すのコードを入れる意味はなんだっけ？など質問を入れながらおこなってみました。 大体は自分の言葉で説明ができるようになってきて、チエテラスでのコードを文字で書くの部分の論理的な理解が進んでいるなという感触を受けました。', '＞１９：２８から', 'タイピング: 今日はタイピングは嫌だと話していたのでそのままゲームを作成へと移りました
盛り上がり: お腹がちょっと痛かったみたいで何回かお手洗いに行っていましたが終始集中してゲームを作成していました。'),
  ('3781799c-9e4c-5029-92e9-a710b159dc22', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-01', '16:30:00', null, '通常 / 今回では前回演算の復習をしたところの理解をもう一度できるかどうか？。 走り幅跳び https://app.arstudio.fun/projects/18010/editor をやってみることになりました', '一度やったことがあるゲームだったが作るとなると話が別だったようで最初から見ないでつくるというのは、やりませんでした。その代わりきちんと動画をみて、先週やった演算でかつ、またはという式や掛け算割り算を改めておさらいができていた様子でした。 途中脱線はありましたが、ジャンプして距離を測るという部分はできたので本人にとっては、なるほどという理解に進んだようでした。', '次回は水泳のPRGでもいいかなと思います！', 'タイピング: プラチナ級まであとちょっと、すごくそれが悔しかったみたいです。
盛り上がり: 割り算の表記の仕方などが最初はわからなかったようでしたが、/ だよと伝えたところ、そうかこれだったのか！や もっとジャンプが弧を書いた方が面白いのにと、実写を反映させたい様子でした。'),
  ('1b6620b8-4dfa-51d3-9ecd-19172b3d9986', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-08-28', '17:30:00', null, '振替 / メッセージなどの習得', '休み明けだったので自由作品なども検討していましたが、やる気があったので腹ペコザメの写経をやってもらいました。流れに沿って問いかけをして理解を確認していきました。マウスポインターに「向ける」と「行く」については、回転なのか移動なのかという違いを分かっていました。メッセージは以前やった時よくわからなかったようですが、今回は誰が送って誰が受け取るのかという流れをつかめました。メッセージの送信と受信が一枚の紙にまとめて書いてあったことで視覚的に納得できたのかもしれません。ゲームが完成したのでアレンジを勧めましたが、自分ではアイデアが思いつかなかったようでした。キャラクターの見た目を変えてみるなど例を挙げると、それを参考にアレンジしていました。', null, 'タイピング: キーを覚えながら頑張っていました
盛り上がり: 振替でいつもと違う環境でしたが楽しんでいたと思います。'),
  ('1b4fbf6f-d9ee-5fb9-8d2e-6f81536da31a', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-31', '17:30:00', null, '通常 / 選抜大会用の作品作りの相談。どんなものを作成するのか、具体的に見通しをたてる。', '選抜大会には、好きで続けているバスケットのゲームを作ることを決めてきていました。 バスケットの作品は意外と少ないため、Scratchでも参考になる作品がなかなか探し出せないようでした。ゲームそのものを作成するのは難しそうなため、バスケの中でどの部分を作りたいのかを自分で考えさせ、最終的に、シュートの部分をメインに作ることになりました。 参考にしたいゲームをScratchで探し出したようですが、いろいろな要素がつまっていて混乱していたため、アレンジ大賞でシンプルなコードの賞をとったことを思い出させ、自分が理解できる範囲で作成しないとあとで困ることを納得してもらいました。 シュートゲームではどんな要素を作りたいのか整理させ、近い動きをしているアーチェリーゲームのコードを見せたらとても納得していたので、それをもとに作成していくことになりました。 作成を始めたところで時間がきたため、続きは次回の予定です。', null, '盛り上がり: 最終的にゲームの方向性が決まったのが嬉しそうでした。 今はバスケでキャプテンをしているそうで、そのあたりの話も嬉しそうにしながら作成していました。'),
  ('6ea7ab29-58b4-56b8-918c-c781971d234f', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-31', '17:30:00', null, '通常 / やりたいことをコードに落としていこう', '前回思ったように進まなかったので、今回はやりたいことを聞いてそこから発展させていく形で進めていきました。やりたいことができれば、覚えやすいだろうという望みで。ビームの打ちずらさを感じていたので、そこから止めるコード一緒に学びながら連射できるようにしました。止まるコードは一度使ったことがあるがいかにも所見のリアクションだったので、0から終えていきました。敵のビームの当たり判定もその前に端に触れたら消えるを一緒に作ってから取り掛かったので、似たような形だと判明し、大体1人で作ることができました。そして、HPを増やしたいそうだったので、変数も使いました。ただ、これも場所はわかるが使い方が抜けていました。なので、初期値と減少地による2種類の使い方でならしておきました。これで、こんかいのことが次に残っているかは確かめるたほうがいいかも', null, 'タイピング: 不用意なミスタイプが多いです'),
  ('742c8e2d-a58e-509d-93eb-429a679c072f', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-31', '17:30:00', null, '振替 / コンテスト用のプレゼンテーション作成', 'コンテスト提出前の「絶対秘密」モードは解除されたようで、入賞お祝いの言葉も素直に受け取って、よくしゃべってくれました。同じ大会に応募した友達は決勝に残らなかったので、その子の分まで頑張ると二人で約束したそうです。 PowerPointを作り始め、どのような内容が必要かをPDFを見ながら一緒に確認しました。細かい内容は、そのお友達と一緒に考えるという話をしているらしく、次回のレッスンまでに考えてくるとのことでした。 少しPowerPointを作成してはロブロックスで遊ぶ、というのを繰り返していましたが、ロブロックスを直ちに否定しないで少し放置していると、PCを除いても隠さなくなり、声をかけるとすぐに課題に切り替えて、作品も見せてくれるようになりました。反抗期？も少し落ち着いてきたかもしれません。', 'プレゼンテーションの完成、提出', '盛り上がり: コンテストが終わって落ち着いたのか、久しぶりにずいぶんとたくさん会話ができました。 友達の分まで決勝をがんばる、という約束もあるせいか、モチベーションもそこそこあるように見えました。'),
  ('d85204d0-7afc-554c-a9bd-c2230e0b39ae', 'b2246586-4496-52f9-a825-be2488a00a31', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-31', '17:30:00', null, '通常 / タイピングスキルを身に着ける', '今回は、包丁から当たらないようにさけるげーむをせいさくしていまた。どこにいてもいずれかは当たるようになっていて、サケゲーうまくできていました。デザインにもこだわりが感じてグロテスク云々は除いてよかったです。', null, 'タイピング: 授業前、クリッカーゲームをやりすぎて、手が痛くなって後半に回したが、またゲームをやりだしてタイピングから逃れようとしていた。やり始めた時にはミスタイプが10％以下になるように目指した。
盛り上がり: クリッカーゲームは億万長者を目指して、に手を痛くしてました。'),
  ('eca385f1-66c6-5421-8214-0c2cfab815f2', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-31', '17:30:00', null, '通常 / コンテスト用のプレゼンテーション作成', '選抜大会に賭けるつもりで、とりあえず提出した親子大会で入賞したのが嬉しくも予想外、という感じで、9月のスケジュールをどうするか、少し困惑しているようでした。 応募作品が少なすぎて入賞したんじゃないかなどと言っていたので、きちんと選ばれた作品だということを説明したら、少し嬉しそうになりました。 PowerPointは使ったことがないということだったので、最初だけ少し説明しましたが、さすがにすぐ操作を覚えて、テキスト入力をしていました。文章を書くのは得意なのですぐにできる、と言っていましたが、自己紹介には悩んでいました。 今年度の大会入賞を親御さんから言われていたらしいのですが、これで一つ目標が叶ってしまったので、選抜大会へのモチベーションは少し下がっているようでした。 とりあえず今は親子大会の決勝に向けて、できればグランプリを狙って頑張ってみて、時間がなければ、できている範囲で選抜大会に出しても構わないから、と、プレッシャーを軽くする方向で声掛けをしました。', 'プレゼンテーションの完成と提出', '盛り上がり: なんだかんだ言いながらも、楽しそうにプレゼンテーションを作成していました。 自分のPCが欲しいというのが、一つのモチベーションにはなっているようでした。'),
  ('eca26556-b5b5-5e2b-bf9b-b266ad337a47', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-31', '16:30:00', null, '通常 / コードを振り返ろう', 'ほぼ1か月ぶりで前回の作業を最初は元のゲームを遊んでからやりました。モチベーションは学校が始まって、お疲れムードだったので、考える頭は結構ゆったり進んでいきました。サメの追いかける歩数について、そこで変えたら難しさが変わると伝えたら、一時集中モードに入る瞬間もありました。セリフをつけるときに、ひとことくらいでもめんどくさいとタイピングに苦手意識を抱いていること見られました。コードの止めるコードでは、3種類を説明し、似たようなところでは自分で選んで使えることができました。ゆったりながらも完成はできて、終わった後はずっと遊んでいました。', null, 'タイピング: キーの位置がまだあやふやでした。'),
  ('16359d04-4a6a-5b68-ac55-def1ab45fb8e', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-31', '16:30:00', null, '通常 / コンテスト用のプレゼンテーション作成', '締め切りが9/13のため、教室で作成できるのは今日を除いてあと1回ということを説明してから始めました。 「決勝大会プレゼンテーションについてのお知らせ」を一緒に読んで、プレゼンテーションに入れなければいけない条件なども一緒に確認しました。 話をしたり、受賞者の動画を見たりしていたら気持ちも盛り上がってきたようで、先週ほどおじけづくこともなく、発表を楽しみにする様子も見られました。 既に商品（商品券）はもらえることが決まっているということで、とてもテンションが上がっていました！ PowerPointについては、先週やった操作もきちんと覚えていて、図のトリミングはスムーズにできていました。今日はスライドの削除や移動、図形の挿入、テキストの編集などを教えました。日本語入力はこちらがほとんど口述筆記しましたが、編集は頑張って自分でやっていました。', 'ユーザー視点での工夫ポイント、感想、まとめなどのスライドを作成して完成させ、提出の予定。その後は原稿作成。', '盛り上がり: 公開されている動画に自分の作品が載っているのを見たり、発表時にレーザーポインターを使うという説明を読んだりしたら、だんだんと受賞の実感がわいてきて、緊張よりも楽しさ、嬉しさが勝ってきた、という感じでした。 今日は終始、発表にも前向きで、楽しくプレゼンテーションの作成に集中できていました。'),
  ('7fec9937-e459-5c19-a3de-b787af46fc80', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, null, '2023-08-31', '16:30:00', null, '休み（未対象）', null, null, null),
  ('56360250-bfc2-5184-81af-36ef8965844b', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-29', '17:30:00', null, '通常 / 間違えを直す能力をたかめるために、エラー間違え探しをしよう', '間違えを直す能力を作化るために、間違え探しをしました。1問目は不等号の仕組み「比べる数を含まないを」悩まされました。誘導しながら小さい数で比べて悩みを解消できました。2問目の「かつ」と「または」の違いを考えさせるのは少し難しかったと思います。学校でもまだ触れない部分であるので、軽い理解を流しました。3問目はコードの順番に関するくじ引き問題でこの問題が1番難しく感じたそうです。場所ごとによる範囲の違いを判ることに手こずりました。この問題は、細かいところで重要なので、今後重要視していけたらいいと思います。でも15分も余らせて終わったので、理解する納涼は良かったです。', null, 'タイピング: 指を見ながらつくれていました'),
  ('9dac75e2-5be1-5618-b923-f7706bd6a645', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-29', '17:30:00', null, '通常 / スプラトゥーン風オリジナルゲームの作成 続き', 'スプラトゥーンの中で、みずきくんがこだわって再現したいところを一生懸命調べたり、試行錯誤したりしながら作成していました。 発射した玉（インク）がぶれる「玉ブレ」という現象を再現しようとして、乱数を使ってまわすことを思いつき、嬉しそうに「玉ブレができた！」と呼びにきてくれました。 ボムを投げた時と、投げた後のインクの広がりなども、コスチュームを使ってうまく再現していました。 自キャラの動きは、だいぶ満足のいくところまでできたようで、頑張って完成まで持っていきたい！と意気込んでいました。', '作成続き', '盛り上がり: 細かい動きをどう作成したらよいのか丁寧に考えて、楽しそうに作成していました。 今日もやりたかったことが解決できたので、次回以降へのモチベーションにもつながっている様子でした。'),
  ('5a71fb97-6eb6-538d-8315-f9a1fb98efb1', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-29', null, null, '通常 / 本人の希望により、チエテラス、Scratch', '今日は珍しく、チエテラスではなくScratchをやりたい、ということでした。 PCNこどもプロコンの話をしたら、動画を見るところまではノッてきましたが、見終わった後は、「僕はいいかなあ…」という反応でした。何か自分で作って、これは、というものがあったら応募を考えてもいいかもね、くらいの話にしておきました。 Scratchについては、こちらからの課題提案もしましたが、今は自分で作っている作品をやり続けたい、ということで、基本は好きなようにやらせました。 Scratchで電車関係のゲームをよく検索しているので、一応中身をチェックして載せられている作品だから、という理由で、NHKのワイワイプログラミングhttps://www.nhk.or.jp/school/programming/program/index.html のサイトを紹介しました。今月は銀座線の3Dシミュレータと、京急のシミュレータが載っていたため、よかったらこういうのも参考にしてほしいと勧めたら、目を通していたようでした。', null, '時間帯: その他
タイピング: 淡々とできていました。
盛り上がり: 基本は一人で淡々と作業しているので、放置になりすぎないように、たまに声をかけていましたが、話には素直にのってきてくれて、作品もできたら見せてくれるような反応をしていました。'),
  ('4a554235-24fe-5fbc-8a74-fd53ea43a4c5', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-29', '16:30:00', null, '振替 / ゲームを読み解いて作ろう', '過去に途中で止まっていたアイテム脱出ゲームを作っていきました。動画を見ずに自分で作りたかったので、一から作りました。独自のコースになっていて、アイデア作れていました。ボールの動きは元のものよりぎこちないが、変数を使ってカギを集める、集まったらゴールへ行けるなどの基本となるところはスムーズに作れていました。とりあえず1面は完成したので、次はステージ転換と2面を作れて行けてたら補助していいと思います。', null, 'タイピング: シルバー急になれました'),
  ('520c135a-0bae-5f7e-b98d-3153bf88b54d', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-29', '16:30:00', null, '通常 / 「ではないまで待つ」ブロックの使い方に慣れる', '途中までは動画を見て丁寧にやっていましたが、最後の方は自力で頑張って作成していました。 「りんごとばなな」ブロックの使い方がわからなかったようで、「文字をつながるブロック」であることを説明し、完成版を見せたら、変数ブロックを使うところなどは自分で解決できていました。 ネコが走る動きをするものの、前に進まないバグがあるといってしばらく悩んでいました。バグを探すときに見るべきコードがよくわからなかったようなので、どのコードが何の動作を担当しているのかを意識してコードを読む練習をして、イベントブロックが間違っているところに自分で気づくことができました。', null, 'タイピング: スピードは相変わらずはやいです。
盛り上がり: さらちゃんにとっては少し難しかったかもしれませんが、自分でやろうとする態度が見られ、成長を感じました。ゲームが完成したときは、とても喜んでいました。'),
  ('aa5046cd-b202-55ca-81c0-621ed1b57dcf', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-29', '16:30:00', null, '振替', '演算を多用する単元別のものを作っていきました。「かつ」や「と」の使い方の区別は、最初は迷いつつも最終的には慣れました。また、スコアを加算する条件が左右に動かすコードに後に作ってあって、そこが進まず今回の悩みどころでした。コスチュームの変化の途中のところを条件をしていて、直列のままだと元のコスチュームの後に判定されてしまうことを伝えてあげました。この直列並列条件の問題には毎度加賀が得させた方がいいと思う。', null, 'タイピング: 中なkプラチナ級にたどり着けないそうです
盛り上がり: たっちゃんのゲームに魅了させされていました'),
  ('a2132ed0-47e9-5ad2-a145-8f908463569b', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-29', '17:30:00', null, '通常 / スキルチェックを兼ねて、間違い探しクイズ', 'これまで学習してきたところのファイルを見せ、スキルチェックと次へのステップへのつなぎとして、バグ探しがどのくらいできるかやってみよう、と促してクイズに挑戦しました。 右端についたら消える問題では、x座標の数値が合っていないということにはすぐに気づけましたが、不等号と数値の関係に少し悩んでいて、大きい数を入れたりと試行錯誤していました。自分で試しながら、正解にたどりついたという感じでしたが、正解してみると、納得、という感じでした。 25については、「または」と「かつ」を使うのが初めてという感じだったため、説明をした上で一緒に解いていました。 31は、1～10までの数を書き出して、どれが大当たり、中当たり、はずれになるかを明確にしたら、大当たりのブロックの位置がおかしいということにすぐに気づいて条件分岐の位置を直すことができました。 今回は31が一番簡単だった！との感想でした。', null, 'タイピング: ゴールド級を出せていました
盛り上がり: 一緒に考えるときなども、とてもよく話すようになり、笑顔も増えました。 今日はこちらの予想よりもかなり早く問題を解き終えたので、満足そうでした。'),
  ('86ddf344-43c1-5506-b5fb-e9191974e82e', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, null, '2023-08-26', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('2e597e6e-b6b7-56fd-bad8-f0bd3b630472', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, null, '2023-08-29', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('5a874267-1380-579a-84fb-606ec47bce7a', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, null, '2023-08-29', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('3aee1ff1-32c5-5725-b022-2d9d5c884a79', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, null, '2023-08-28', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('157fbc5b-72b4-539b-a815-54327e18b315', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2023-08-28', '16:30:00', null, '休み（未対象）', null, null, null),
  ('d950a3a2-28ec-5a76-a126-5e286f982a78', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-28', '17:30:00', null, '通常 / キャッチゲーム 基本操作コース10〜星とりゲームの応用までhttps://app.arstudio.fun/projects/6263/editor', 'ひとまず自分で基本のキャッチゲームを話ならがら相談っぽい感じでゲームを作成。 最初の基本操作っぽい部分は座標を駆使しながらアイテムをゲットしたら消えるなどもう一度おさらいしてみました。 その後に、応用問題でスコアが一定の状態になったら、ロケットに進んで消えるまでをできることができました。', null, 'タイピング: なし
盛り上がり: 作品としては大会で使ってた部分もあり、多少やってたことのおさらいっぽく思い出しながらやってみました。 特に座標の上から下に動く動きに関してはとてもいい部分もあり、単純なコードに描きなおすのが逆に不得意になっている様子。 ただ全体的には、自分がやっていたコードのおさらいという試されているという感覚がよい刺激にはなったようです。'),
  ('ebc73ca1-3de4-510e-90b9-c475c4ba33f0', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-26', null, null, '通常 / 夏休み前までに覚えていたコードの復習、楽しくプログラミングをする', 'チュートリアルレッスンの使い方をよく覚えていて、自分から「この前の続き」と作品作りを始めていました。 ブロックの文字が小さくて見づらいとのことだったので、コード作成部分の拡大のやり方を教えました。 スコアを増やすブロックを、条件式のうち、「はしにふれたら」の方に入れてしまうというミスはありましたが、ゲームの状況から何を直せばよいのか考えさせたところ、きちんと解決できました。 ローマ字も大体わかっていて、「ゲームクリア」などの文字も自分で打っていました。 「ゲームクリア」スプライトを作成したところで集中力が切れたので、残り15分はこうしろうくんと一緒にギアブロックで遊びました。二人とも大変盛り上がり、ほぼすべてのギアをつなげて正面に直方体を作り、「発電所がある家！」と大喜びしていました。', null, '時間帯: その他
盛り上がり: 30分前に来室しましたが、レッスン前のゲームタイム、レッスン中のプログラミング、残り時間のブロック遊びと、それぞれの時間を集中して楽しめていました。'),
  ('78b1df6b-4d19-5519-bd06-66854fad7e2b', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-26', null, null, '通常 / 夏休み前までに覚えていたコードの復習、楽しくプログラミングをする', 'タイピングをやりたくないなどと、授業冒頭では少しごねましたが、レッスンを始めると一生懸命取り組めていました。 アルくんと敵の動きができたところでアイディアが湧いてきたようで、敵のコスチュームにくりぼーとつぶれたくりぼーを自作し、当たったらつぶれて、そのあと音を出して飛んでいったような表現を工夫して作っていました。 「もし○○に触れたら」「表示する」「隠す」などのブロックもよく覚えていて、このあたりはノーヒントでスラスラ作成していました。 「旗にふれたらゲームクリアのスプライトを表示」のところで、初めてメッセージを使いました。ブロックの使い方については、納得していたと思います。 15分前に上記が完成して、一気に集中力が切れたので、残り15分はのあくんと一緒にギアブロックで遊びました。二人とも大変盛り上がり、ほぼすべてのギアをつなげて正面に直方体を作り、「発電所がある家！」と大喜びしていました。', null, '時間帯: その他
盛り上がり: プログラミングもブロックも、とても楽しそうにできていました。 自分からコードに使用するブロックを探せるようになってきたのが、得意そうでもありました。
備考: 左利きだからマウスが使いづらい、と、とてもイライラしながら右手でマウスを使おうとしていたので、左側に余裕ができるように座らせ、左手にマウスを持たせました。 それ以降はイライラすることもなく、熱心にできていました。'),
  ('6dd21864-3f67-5c92-912f-0ccea0f78833', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-26', null, null, '通常 / 視覚的な効果の学習', '飛ばす子も多い今回の課題にも、まじめに丁寧に取り組んでいました。 テキスト通りに作成してから少しずつアレンジを加えて、自分なりの作品にしようとがんばることができました。 最終的に4つのスプライトを使い、自分で動かすスプライトと影を残すスプライトをうまく配置して、とても満足そうに作品を披露してくれました。', null, '時間帯: その他
タイピング: 毎回まじめに取り組んでいます
盛り上がり: スプライトの色をオリジナルにしたり、セリフを挿入したりと、なつめちゃんなりの世界観をもって、楽しく作成ができていました。 久しぶりにファイルを開き、「今日の課題はクリア！」と日付とスタンプを入れたところ、とても嬉しそうにしていました。'),
  ('633c8522-3d79-597d-8bb0-857c6450026d', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-26', null, null, '通常 / シンプルなコードでのジャンプ作成', 'コンテスト作品がプラットフォーマーでジャンプを使っていたため、シンプルなジャンプの動きの復習をしてスキルの定着をはかることを説明してから課題に入りました。 たてのジャンプはさすがにすぐ作成できていましたが、敵が左方向に動いてくるところでは少し悩んでいたため、使用するブロックのヒントを出しました。 敵（りんごスプライト）が横にスライドするだけではつまらないので、転がるようにしたいといって、左に動かすブロックの下に「〇度回す」ブロックをつなげ、転がる動きをしないと困っていました。そこで、ブロックの動作が終了しないと次のブロックに進まないことを説明し、コードを並列にすることで解決していました。 何度もプレイしながら、ゲームバランスを丁寧に考えて速さやサイズを調整していました。', 'ジャンピングゲームの応用をするか、キャッチゲームに進むか選択', '時間帯: その他
タイピング: よくできていました
盛り上がり: 久しぶりだったせいか新鮮な気持ちで取り組めたようで、ゲームバランスに何度もツッコミを入れながら、楽しそうに作成していました。 りんごが転がりながらせまってくるところは、思い通りにできたようで満足気でした。'),
  ('697e9197-994c-5511-a77c-1627701eb166', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-08-26', null, null, '通常 / 検定の考え方を学ぶ', '基礎固めをするため検定4級の問題に取り組みました。「完全に問題文の指示通りにコードを書く」など検定の概要を説明した後解いてもらったところ、比較的すぐ終わったのですが、かなり自己流で作成していました。問題文をあまり読んでいなかったとのことで一緒に一文ずつ読み進めていきましたが、理解に時間がかかる場所が多かったです。できるだけ簡単な要素に分解しながら進め、なんとか最後までコードを修正することができました。', null, '時間帯: その他
盛り上がり: レッスンの前後にはHTMLを書いてホームページを作成していました。本当に好きなことになると熱量がすごいです。'),
  ('f0ccc1d6-d158-5529-b02a-30c2d36ce8af', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-26', null, null, '通常 / 色々なクローンの使い方を学習する', '検定の合格証を渡し、1級にチャレンジするならクローンのマスターが必要なこと、検定受検の有無に関わらず、クローンはもう少し色々なパターンで使ってみてほしいことを説明し、本人の意思で【DKアート】07 うずまき作品に取り組みました。 角度や色のパターンなどを色々変えて、動きの変化をしっかりと観察していました。ちひろくんにとっては、「わりと簡単だった」とのこと。 アート系の課題が続いたため、残り時間はprgから好きなものを選んでもらい、【Prg】55 走ってゴールを目指せ！キャットランゲームを作ろう！をやりました。さすがにゲームをプレイしてみて、これを素材だけにしてしまうと何から手をつけたらいいのかわからなくなる、とのことだったので、ネコのコードから「たての動き」の定義ブロックを作成してもらいました。たての動きの条件などを口頭で説明してもらってから作成に入りましたが、「もし白色に触れていたなら」と「上向き矢印キーが押されたとき」を「または」でつなげて書いていたため、条件を論理演算子で並べる場合と、ネストする場合の違いを説明し、今回の条件の書き方はどちらにあてはまるかを考えさせ、解決することができました。 続けてジャンプの定義について、「ジャンプ力」変数のところを隠してちひろくんに説明してもらいましたが、こちらはよく理解できていました。 「ゴール」スプライトの、それぞれのメッセージを受け取った時に続くコードを作成させましたが、こちらは「次のステージにうつった時」に「背景を変える」としていたため、背景がものすごい勢いで変わって困惑していました。背景の処理は他のスプライトでしていることを確認させ、このコードでしたいことは何かを一緒に考えて解決しました。', '回数が少ないため、今年度中に検定1級を受けるかどうか考えてきてもらい、それによって授業内容を変えていく予定です。 チエテラスをするかどうかも含めて、次回、希望を教えてほしいと伝えました。', '時間帯: その他
タイピング: 安定して余裕のトップクラスの結果を出していました。
盛り上がり: どちらの作品も、楽しそうに取り組んでくれていました。 今回は珍しく、うまくいかないところを素直に聞いてきましたが、解決すると満足そうにしていました。
備考: タイピングコンテストについては昨年で満足したようで、今年は参加せずにプログラミングをしていたい、とのことでした。'),
  ('4d8b9cc6-4094-54b8-91fb-516dbc60a7ab', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-08-26', null, null, '通常 / 「ではないまで待つ」の練習', '今日作るゲームでそうたくんと対戦してもらって始めました。座標の設定やキーを押したときの動きなどの基本的な部分はコメントを見ながら作れましたが、長押しを防止するところで困ったので、重要なポイントとして「ではないまで待つ」を教えました。「キーが離されるまで待つ」という意味だということは少し説明しましたが、理解は曖昧かもしれません。ゴールするところまでいきましたが順位を表示するのがまだなので、次回やる気があれば完成させたいです。', 'やる気があれば続き', '時間帯: その他
盛り上がり: 休み明けということもあり最初はスクラッチのゲームに夢中になってしまいましたが、なんとか頑張れました。'),
  ('9ded7466-fa48-5880-b690-7b854fb5fb24', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-25', '18:40:00', null, '通常 / ジャンプゲームの応用までできればと思ったのですが、基本操作コース０９のジャンプの最初の部分から作成しました', 'ジャンプゲームを最初からとなりました。わかっている部分もあれば、卵の動きなどは〜秒で動かすというのが忘れてしまっているような感じもあり、一個ずつおさらいしながら行いました。 途中自分でこんなアレンジがしてみたい！というので、少し手を加えてメッセージの送受を中心にゲームが展開するようにしていました。', '次回はジャンプ〜の応用に進むか、もしくは一個戻ってチーズを探せにしても良いかなと思います', 'タイピング: 概ねタイピングは良くなっている様子、無駄が少なくなってきたなと思います
盛り上がり: まだメッセージのやり取りに関してロジカルな感じで書いているわけではないですが、自分でこうしたい！という意欲的な状態が見られてとても嬉しく思います！'),
  ('3303342c-24a1-5e3f-90cf-0274c2efd7d6', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-25', '18:40:00', null, '通常 / 初級スキルチェック https://app.arspark.jp/contents/11346 ～歩など基礎的なスキルチェックを最初に行う', '終始眠たそうにしていたので、何回か声をかけながら、このコードの意味はなんだろう？と問いかけながら進めていきました。〜分までがんばろうと話した際に、実際にその時間になっても終わっていなかったのですが、最後まで頑張るということですべてのコードを書くことができました。説明を聞いていると、実際には理解しているような雰囲気ではありましたが、〜に向けるなどの向きの部分と動作が一緒になって描けるということをもう少し練習した方がより今後のゲーム作成に意欲が出るかなと思います。', '来週はジャンプ問題の応用を行ってもいいかなと思います。もしくはチーズを探せ', 'タイピング: 簡単のタイピングをおこない、以前よりは文字数を多くタイピングできるようになってきた感じ
盛り上がり: 最後までちゃんとやる！と決めたことが素晴らしい！一度決めたことをやり遂げる強さが増えたなと思います、'),
  ('12cc5894-9165-54e7-9af5-c9f38919853a', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-25', '17:30:00', null, '通常 / 初級スキルチェック https://app.arspark.jp/contents/11346 ～歩など基礎的なスキルチェックを最初に行う', '最初に色々と確認しながら行う部分があったので、どうして赤で囲われているコードの部分を重点的に説明をしてもらいながら、進めていきました。 サメの動きに移行した際に回転方法を左右のみにするのか？の部分では、左右に動くとはどういうことなのか？を再度おさらいできていたようなので、本人的には勉強になったのではないか・・と思います。集中力が途切れ途切れだったので今回は途中までになりました。', '今回の続きから', 'タイピング: FASJKを重点的にタイピング練習していましたが、やはりお休みがあったのでキーボードの位置が覚え切れていない感じでした。ちょっと大変そうではありましたが一生懸命練習していました
盛り上がり: 自分で答えられる部分がどんどんと多くなっているのが楽しくなってきた感じ。 進んで自分からコードを選ぶということやプリントを見て行えるようになっていたのでとても良かったかな！と思います'),
  ('883ac1db-bc86-5021-bfa3-5b7650110625', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-25', '16:30:00', null, '通常 / 休み開けのため、最初にアルスパークがやりたいと話していたので、気になるゲームをやってみようというスケジュールに変更（PRG走り幅跳び、水泳、スプラトゥーン風のなかから選んでみることにしました。）', '今回のゲームで大切なのは向きを表現する時に〜度やコスチュームが変化する、また条件分岐、変数が大切だよと先に明確にしておいた状態にし、動画を見ながらやってもらいました。 やはりゲームっぽい感じなのは好きな様子で、キチンと明確にしていた部分に関しては概ね理解ができているようでした。', '今回は12：52の部分まで終了していたので、次回はその続きからです。', 'タイピング: 難しいは難しいけど、タイピング自体は苦手ではないので淡々と行っていました。
盛り上がり: 進んで選んだゲームなので終始集中して行っていました。'),
  ('f83e2fef-db9a-5020-a6f6-343485df5f61', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-08-25', '17:30:00', null, '通常 / 休み明けなのでスクラッチを復習する', 'やる気があれば検定練習をやってもらう予定でしたが、休み明けということもあり微妙だったので動画を見ながらフォートナイト風ゲームの作成をしました。ジャンプ中かどうかの変数を使っていたので、「ジャンプ中=0」とはどういう意味か問いかけると、少し考えていましたがジャンプしていないことだと答えられていました。また、床に触れているかどうかの判定は色を使ってやっていることを理解していました。プレイヤーとターゲットが動くようにするところまではできました。', 'フォートナイト続き', 'タイピング: きちんとやっていました。
盛り上がり: 再びふりこのシミュレーションで遊んでいました。'),
  ('2ad51319-0894-52b4-9d4f-b617a857849b', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-08-25', '17:30:00', null, '通常 / スプラトゥーン風オリジナルゲームの作成', 'メインキャラや武器のデザイン、弾の発射や着弾についてのコードを組んでいました。デザインに関しては、好きなゲームということもあり出来るだけ本家に近づけるように頑張って作成していました。プログラミングは、多少つまづくこともありましたが、すぐに修正して思い通りの出力をすることができていました。', null, 'タイピング: なし
盛り上がり: キャラクターや武器のデザインには特にこだわって作成していました。自分の好きなことが絡んできていたので、いつもより張り切って作成していました。'),
  ('6fb2380f-bd86-5b48-8aec-5617f7e08582', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-25', '16:30:00', null, '通常 / バグの修正 ①右端にふれた瞬間に、消えて欲しい（現状消えない） https://scratch.mit.edu/projects/707851367 ②ちょっとむずい くじびき 大当たり～はずれがきちんとランダムに表示されない https://scratch.mit.edu/projects/707862969 ③むずい１００以上の数を入れてもまる判定になる https://scratch.mit.edu/projects/707852979', 'お休み明けだったので、気になったゲームのコードをやってみるか、バグ修正にしてみるかの相談をし、バグの修正でいいということで連続３問を行いました。１〜３に関しては自分でどのコードが違いそうなのか？という間違えている部分を理解できていた様子でした。 ４はチャンレンジということでやってみたのですが演算問題をまだ授業でもいっぱいやっていないためか、少し難しい感じで解いていました。ただ正解を見た瞬間「あぁそうか！」というふうに自分で引き算の問題なのか！というのは理解できていた様子でした。', '一度どこかのタイミングで検定問題をやってみてもいいかもです。４級はパーフェクトだと思うのですが飛び級で３級にしてあげても。お母さんがいらっしゃったので、その旨は伝え済み', 'タイピング: スコアがお休み前よりも100点ほど増えていて目覚ましい成長をしていました！
盛り上がり: バグを修正するというのは割と得意？なのかもと思いました。条件分岐の部分も頭で理解しようし、それを手を動かして表現できる子だなと思いました。'),
  ('c7b77dce-71f9-5dbc-9956-5bb3105fc39e', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-08-25', '17:30:00', null, '通常 / 大会提出作品の作成', '大会提出作品の作成を始めていました。内容はドット絵のシューティングゲームを作成しています。初回であった今回は、銃の素材の透過やメインキャラクターのデザインを主に作成していました。', '大会提出作品の続き', 'タイピング: ミスすることなく入力することができていたので、今後は少しづつ速度を上げてタイピングができるようにしていくと良いと感じました。
盛り上がり: キャラクターのデザインをしている時は、独創的なアイディアを使い作成していました。'),
  ('08f5727a-8fc7-5f0e-98bc-709a15e03d94', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-25', '17:30:00', null, '通常 / 前回のPRG走り幅跳びを行う予定だったが急遽検定３級の応用問題１８を再度行う', '一度やっているためか前回よりもとても文章を読み込むことが上手になった感じがしました、1回目では迷いがありながらコードを書いていましたが今回は自分でこの文章の時は絶対こうだ！という自信がついていた感じでした。 おおむねコードに関してはパーフェクトにできていたので、次回また時間があった時に検定の過去問をやろうねと伝えておきました。', 'PRGの走り幅跳びでもいいが、もしかするとエニシくんのように好きなゲームを写し書きの方がいいのかも・・', 'タイピング: うでだめしの方を行い、タイピングミスはかなり少なくなっている様子
盛り上がり: 1回目のコードと今回のコードを見返して自分でも成長したと実感していた様子でした。特にサッカーのボールの動きのあたりは変数の理解がよくできていたので、一緒に答え合わせしていた時も、かつての自分を客観的に見れていた様子でした。'),
  ('fea3c674-f3e0-533a-8b1d-6f4232106f8d', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, null, '2023-08-04', '16:30:00', null, '振替', null, null, null),
  ('ac8f9e6b-0b55-5bf6-91bf-d7574ba6e23a', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-08-24', '16:30:00', null, '振替 / 基本操作コースに戻る', 'キャッチするカゴのほうは自力ですぐにできました。ボールの動きは少し複雑で困っていたので、テキストの流れに沿って進めました。イメージをもってもらうためヒントを出すと、どのブロックを使えばいいか思いついていました。最終的にほとんど完成しましたが、1回のキャッチで何回も点が入ってしまうされてしまうバグが残りました。見たところ、2つのスプライトで重複してスコア変数を加算したことが原因だったようなので、これを直せば完成です。', 'キャッチゲームが終わったら次の題材に', 'タイピング: まだ長めの言葉を打つのには苦戦しているようですが、楽しみながら頑張っていました。
盛り上がり: ちょっと工夫したいということでネットから画像を検索して使っていました'),
  ('0afbd60f-9e00-5273-b8d9-2e3bcb9e7282', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-24', '17:30:00', null, '通常 / コードを復習しよう', 'コード復讐のためにゾンビを倒せに似た宇宙バトル1を作り始めました。まずは、敵を上下に動かすことを提案したが、座標の認識がすっぽり抜けていた。ずつ動かすを持ってきてほしいのににするを持ってきたり、角度も認識も甘いです。どのコードがどのような動きをするかの対応がほとんど一致できていなかったんので、また0から教えのしていきました。ビームも横に打てずに終わってしまったので、また丁重にやっていくしかない', null, '盛り上がり: ピクミン4をずいぶんやりこんだそうです'),
  ('a9c6abda-b134-5462-bc06-c7d9b293c633', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-24', '16:30:00', null, '通常 / 習ったコードに作品作りで慣れよう', '1度はコードがわからず断念しただるまさんがころんだのゲームを作っていきました。コードの形はゆっくり思い出しながらスロースターター見たいに正しく作れて行きました。ただ、ずっとの忘れが少し多いです。ゲームから何が起こっているかは良く読み取れていました。「負け」になる条件で、コス名がひだりになることのコードの作り方が、=を使って表現することにだいぶ頭を悩ませました。＝の使い方が数字だけの認識があるかもしれないが慣れていくしかない。そして、2条件同時のもしのの作り方が、別々の並列になっていて、ドツボにはまっていました。そこはもしの中にもしを入れることで同時条件を満たせることの認識が甘かったので、ここは重点的にやった方がいい。', null, 'タイピング: 指を使いをしっかり見ながらミスなくやっていました
盛り上がり: 夏休みだいぶ満喫していた'),
  ('ea5672fd-ac8e-5271-9e62-29c8276f13c4', '57f45872-1f3e-5540-b676-bf9023444e39', null, null, '2023-08-24', '16:30:00', null, '休み（未対象）', null, null, null),
  ('7248a89e-3c8a-59b5-bcd2-ce9e9d220642', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, null, '2023-08-24', '17:30:00', null, '休み（未対象）', null, null, null),
  ('c8b5c51e-d354-53cf-81c3-e46eae919ba5', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2023-08-24', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('e03f9ea2-c459-5ec5-b938-63b3b939fa9a', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-24', null, null, '通常 / チエテラス 2進数の復習', '2進数を復習する意味もよくわかってくれて、動画を2本、しっかりと見ていました。 なんとなくはできていたけれど、動画を見て、自分の考え方が間違っていなかったという感想を持ったようでした。 チエテラスの学年による正答率の目安を伝えたところ、基準を余裕で超えていることがわかって、少し嬉しそうな笑顔を見せてくれました。 Scratchに切り替えるときは、こちらから課題の提示もできる話もしましたが、チエテラスの後は好きなようにプログラミングをしたいとのことだったので、自主性に任せてみました。', null, '時間帯: その他
タイピング: 淡々とクリアしていました。
盛り上がり: これまで淡々と進めていたチエテラスの基準がわかったのが嬉しそうでした。
備考: テキストを1部渡しました。'),
  ('0515b222-0b3e-5c15-9e9f-0877087cabe7', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-08-24', '17:30:00', null, '通常 / タイピングのスキルを身に着ける、プログラミングのスキルチェックをする', '今までやってきたことを確かめるため単元別演習に取り組み、最初から3問解くことができました。いつも通りのカオスなアレンジもしていましたが、ほどほどにしてねと伝えると本題に戻っていました。最初の2問はあまり困らずに通過しましたが、3問目は「こういう問題苦手」とのことだったので、問いかけながらスプライトの動きを時系列で整理していくと解くことができました。', null, 'タイピング: 教室でタイピング練習をすることを保護者さんと約束したそうなので、初めてココアタイピングをやりました。レッスンの時間前から自主的に始めるなどやる気が感じられました。しばらく順調にやっていましたが、「もっと練習して上達しておかないと...」と焦ってタイピングをやめようとしなかったので、一度にたくさんやるよりは何回かに分けて練習したほうがいいから大丈夫だと伝えました。
盛り上がり: 保護者さんと話をしたのもあったのか、今日はいつもより集中していたと思います。'),
  ('3e00e01c-7a85-5618-84a1-157cfabc5851', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-24', '17:30:00', null, '通常 / 習ったコードの組み合わせを考える', '当初は学校の甲子園優勝記念で、【Prg】25 野球ゲームを作ろうを用意していました。が、30分ほど遅れてきたため、最初は乗り気で上記をプレイしたものの、バットにボールは当たらないし、終わる気がしないとのことで、単元別演習に切り替えました。 単元別演習G-5をプレイしたあと、残り20分でできることをやるということで、虫の部分のコードのみを考えました。虫が上からランダムに落ちてくるコードで、条件式に「y=○○なら」を使っていて自分で混乱していたので、その部分だけ検定方式でこちらがやってほしい動きを文章で伝え、それをブロックにしてもらう方法で進めました。これは納得しやすかったようで、スムーズに進めることができました。 カエルが虫を捕る部分は、虫が落ちてくるコードの下に、虫を捕った判定を入れていたので得点が入らず、しばらく悩んでいました。「虫を捕るのはどの動作の中でされるべきか」をヒントにしたら、少し考えた後に解決することができました。', null, '盛り上がり: だいぶ疲れて入室してきましたが、一気にドリルに取り組んで完成できたのが満足そうでした。'),
  ('71584dfd-eb12-5538-83fc-ff8e3cd2d566', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-24', '16:30:00', null, '振替 / 習ったコードを作品作りに慣れよう', '習ったコードの復習としても視野メッセージが多用されているだるまさんがころんだを作りました。コンテストで使ったコードの形が多くあったので、大方スムーズに進んでいきました。迷っているときも手を止めることなく、「ここどうかな」聞きながら作っていくことが多くなってきました。コスチューム名を＝でつなぐところやもし2条件での使い方は質問形式ながらも少しのヒントで自ら作ることができました。メッセージのやり取りも使い方に迷うことなかったです。これより「もし：」やメッセージの使い方が身に染みて使えるように感じました。', null, 'タイピング: 基本手が止まることなく
盛り上がり: 久しぶりで作品作りに勢いが乗っていました。'),
  ('2a8c1102-ce12-58ae-8a66-417581b788d6', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-08-24', '16:30:00', null, '通常 / コンテストの決勝大会に向けて計画をたてる、プレゼン資料作成', '決勝に残ったことは嬉しそうでしたが、どんなところで発表するのかなどをとても気にしていて、昨年の様子を見たがったので、少し動画を見せました。 今年のホールの写真の大きさ、全員がマイクを持って舞台中央でしゃべっていることにかなり引いていましたが、とりあえず資料を作ろうということで進めました。 学校でもグループ発表のときは発表担当はやらないとかで、プレゼン作成に使うアプリも先生が用意しているからよくわからない、とのことでした。PowerPointを開いて見せましたが、初めて使うとの反応でした。 使い方はすぐに覚えて、デザインや色を変えたりするのを楽しんでいました。 動画の質疑応答に驚いたようで、字を小さくして見えにくくすれば突っ込まれないかな？とやっていたので、見えやすいほうが突っ込まれないと思うと伝えたら、慌てて字を読みやすくしていました。 ゲーム画面のキャプチャーを貼り付けるのと、画像のトリミングを教えたところ、面白かったようで、見本の1つ目以降は自分で一生懸命作業していました。', 'プレゼンテーション作成の続き', 'タイピング: 自分からやるとは言ったものの、ちょっとおふざけモードで、ミスタイプ率を100に近づけるように敢えて隣のキーを打つ、左右のキーを逆に打つなど、ややこしいことをしていました。
盛り上がり: 発表は嫌だけど、残ったことは嬉しい、誇らしい、という感じで、授業中も基本的には嬉しそうに、よくしゃべりながら作成していました。 初めてのPowerPointもすぐに覚えて使いこなしていました。
備考: お母さんのお話では、いつも発表は直前まで嫌がるものの、やってしまえば「がんばった！」となるので、今回もなんとかなるのではないかという感じでした。 ただ、来年になって「プレゼンが嫌だから応募しない」とはなってほしくない、とのことでした。'),
  ('e8bd7360-b6c7-5294-916c-f7d4ea0ab4f8', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-22', '17:30:00', null, '通常 / 基本操作コース10_キャッチゲーム', '最初のスプライトと背景を選ぶのにこだわっていました。カミナリを画面の上に配置させるときにかなり困っていたので、考え方を細かくして伝えました。下に動かして上に戻すことも難しかったようです。下に動かすことだけを考えてもらうと、そこから上に戻すことも繋げて考えることができていました。人を左右に動かすこと、カミナリに当たったときに見た目を変えることは自分で全てプログラムできていました。', null, 'タイピング: あまりやりたくない様子でした。
盛り上がり: 今日はあまり気分が乗らなかったようなので、目標を決めて頑張りました。最後は楽しそうに帰ってくれたので良かったです！作品のコンセプトはバッチリです！'),
  ('b6d0dbdf-7e72-56bc-8717-b2c0f4377d46', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-22', '17:30:00', null, '通常 / 検定2級問題①（ロケット）', '初めて2級の問題に取り組みました。40分を使ってもらいましたが、3/5ほど解き終わっている様子でした。できていない部分は条件分岐と演算、変数が組み合わさる部分で、条件がどこまで適応されるのかの理解が曖昧でした。また「～と聞いて待つ」に対応する「答え」の意味がよく分かっていなかったようなので説明しました。 基本的な部分はよくできていましたが、2級ならではの少し複雑な文章の言い回し、論理構造にもう少し慣れる必要があると感じました。来週は終わらなかった部分を進める予定です。', '前回の検定の続き', 'タイピング: 集中して取り組めていました。'),
  ('ace9a096-eebb-506d-955d-553e6e76f4d0', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-22', '17:30:00', null, '通常 / 本人のモチベ次第でprgまたはエラー発見クイズ', 'かねてから作りたい様子だったので、挑戦することになりました。前半は武器の画像やイカの画像にこだわりたい様子でした。後半ではインクの塗り方を一緒に考えました。ねこちゃんが向いている方向にインクをまきたい様子だったので、ねこちゃんの角度とねこちゃんからの距離（射程）を使ってプログラムすることを提案しました。インクはスタンプで表現することを提案しましたが、イマイチ本人は納得がいかない様子です。', null, 'タイピング: しっかり取り組めていました。
盛り上がり: どうしても画像の方に気がいってしまうようなので、しっかり時間を決めてプログラムにも取り組んでもらいたいです。'),
  ('dc406a5f-993a-5001-8394-f2bdcf76667c', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-22', '17:30:00', null, '振替 / 【Prg】23 走り幅とびゲームを作ろう https://app.arstudio.fun/contents/18722 "長押しした時の連射（連続）防止するには～？ 「〇〇〇ではないまで待つ」の使い方', '16:30のところ、17:30に来てくれました。本人がやりたいとのことだったので、やっていくことになりました。 動画を見ながら進めました。ひとつずつ丁寧に取り組めていたので良かったです。途中うまくプログラムが動かないことがありましたが、使うブロックのミスのようでした。変数については使い方があまりしっくり来ていない様子でした。来週またゆっくり確認しながら進めたいです。', null, '盛り上がり: 雨の中よくきてくれました。'),
  ('798ebbf1-1755-5fe3-901e-9f7f8697b31d', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-22', '16:30:00', null, '通常 / アルスパークレッスン/アルくんの冒険2 条件分岐のネストを意識、ジャンプを台の上でとめるにはどうするのかを考えさせながら進める', '前回やったあるくんの冒険1を一度みて、内容の復習をしました。冒険2はレッスンを見て進めていました。座標の「ずつ変える」「にする」の意味の違いを復習しました。チュートリアルで問われていることに答え、手を動かせていたので良かったです。完成した後は、敵にぶつかった回数を数えるアレンジをしました。変数を適切に使うことができていました。ゲームオーバーの画面を自作し、うまくプログラムできていました！', null, 'タイピング: 腕試しの簡単に挑戦していましたが、難しい様子でした。
盛り上がり: 丁寧に取り組めていました！'),
  ('9974e65a-4bea-5720-964b-a7fbc6440e35', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-21', '17:30:00', null, '通常 / フォートナイト続き', '前回、スクロールがうまくいかずモヤモヤして終わってしまいました。今回は自分でプログラムをしっかりとチェックし、時間はかかりましたが自分でうまくいかなかった原因を突き止めることができていました！すごい！単純なプログラム忘れだったそうです。後半は足場のプログラムに入りました。これもスクロールの問題、消えない問題など多々課題は発生しましたが、よく考えて自分で対処することができていました。今日は足場のプログラムまでなんとなく終わったようです！次回も続きをやりたい様子でした。', null, 'タイピング: ホームポジションに気を付けて丁寧に取り組めていました！'),
  ('51cf7506-f1db-5fad-bf16-ce532784f252', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-21', '17:30:00', null, '通常 / ジャンプ（等速①②と背景スクロール）', '等速ジャンプは難なくできていました。変数で飛ぶ高さをわざわざ設定する意味があまり納得できなかったようなので少し議論しました。 ジャンプゲームで背景スクロールをやりました。最初は自分で考えながら始めていましたが、どうしてもうまくいかないので見本を見て一度やり、逆算することになりました。見本通りにやるのはあまり好きではないようでしたが何とか完成し、最後にどのような動きを作っているのかについて一緒に考えました', 'クローンを使った背景スクロールに挑戦する予定です。', 'タイピング: スピードは速かったです。ホームポジションを意識できるようになりたいです。'),
  ('9b32dccf-0092-5014-8b5a-f27b966e6b42', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-21', '16:30:00', null, '通常 / 前回の作品作りの続きでもOK（ただし、夏休み中は何もやってなかったので最初は初動がおそいかも） 水泳のPRGでも（https://youtu.be/ZjjaFdXqVRI）', '夏休み中の自分の作品の進捗を聞いたところ、バグつぶしや整理を行っていたようです。 今日PRGの水泳に取り組むことになりました。動画を見ながら丁寧に進めることができていて良かったです。時間内に完成しました。本人によると演算の使い方が難しかったそうです。個人的には演算のほかに、泳ぐスピードがタイミングと、タイマーと関係していることにも気づいてほしかったので詳しく説明しました。', null, 'タイピング: 集中して取り組めていました。'),
  ('7e0c0fa8-0208-53a9-bbdf-def2683c499a', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-21', '17:30:00', null, '振替 / 急遽のため、バグの修正3個と、走り幅跳びPRGを動画を見ながら途中まで作成。', '今日はスケジュールに入っていなかったのでこちらが準備できておらず、ただ検定のためにバグの演習問題をやってもらいました。 １６、３６、３７の問題を行いましたが、変数プラス演算の問題は変数の数をプラスするというところに行きつかず、変数のそもそもの数字を変えたりすれば？など自分でアレンジをかけてしまう。 また条件分岐でもではないまで待つのコードを忘れているためかクリックの回数をスクラッチで理解しようという部分でも〜秒待つなどのコードでやってしまえなど自分の簡単な癖の方に行きがちでした。そのため走り幅跳びの動画を見てもらってしばらく変数と条件分岐のコードの理解をした方がいいかなと思い、途中から動画という感じになりました。', '今日の続き', 'タイピング: なし
盛り上がり: 自分で解消しようという努力はとても見られるので、見守りながらやっていきたいと思います'),
  ('37205359-fb7b-52be-8592-8220c4ede5f7', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-21', '16:30:00', null, '振替 / ゾンビを倒せ２（https://app.arstudio.fun/my/lesson_maps/advance）を行う、やっていることは今までと同じだが、変数が今度はついて～の状態になった時にメッセージを送るタイミングがどこにくるのか、と座標の動きと歩数の動きがどう違うのか一旦説明しながらやってもらう（大半はチュートリアルを見ながらで最後に説明でいいのかな）', '最初は今までやっていたことが覚えていなかった様子なのでゾンビの１をもう一度見返して〜歩とY座標の違いをおさらいしてみました。 その後に２のコードとどう違うのかを観察してもらって、変数で止まるということを見てもらいました。 本人は動画を見てやることに対しては集中力が多少足りない感じでしたが、どうしてこのゲームでは〜歩を使っているのか？の理解はできた様子でした', '今日の続きから〜変数（スコア）の部分は難しいので、多少動きに焦点当てた方がいいかも', 'タイピング: 今日は95点！まとめに行くことはできそうなので次回まとめ〜の部分のスコアで合格点を目指せればいいなと思います！
盛り上がり: タイピングがとても良くできたようで本人は満足したようでした！ 今日は久しぶりだったためかコードの意味というのがどうしても難しかったようでしたが、それでもコードを重ねていく楽しさはあったようです'),
  ('8a79ea60-bcaa-5385-9995-b3581065f0f2', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-21', '16:30:00', null, '通常 / 背景が動くジャンプ【Prg】20 ジャンプゲームを作ろう！（https://app.arstudio.fun/contents/2610）座標の動き～から入った方がその後が楽かな？', '最初に、背景の動く原理から始めてどうして前に進んでいるのか？を理解するところから始めてみました。 その際に小技の背景スクロール１と２を合わせて〜右左の端の数字を確認すること、座標の動きがどうなっているのか？を確認しました。 背景ジャンプ〜の方は、その後に作成し始めたので実際のジャンプの動きまでには進んでいませんでしたが、背景が動くということを理解したようでした。', '今日の続きから', 'タイピング: ９３％の正答率でした！２週間前よりも、精度がとても上がっていて素晴らしい！
盛り上がり: タイピング力が上がっていることや背景も動かせるということに気がつけてとても楽しんでいました。'),
  ('e44387d2-9403-5ff9-9f52-aeede29130e7', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-07', '17:30:00', null, '通常 / フォートナイト続き ツッコミで理解度確認しながら', '動画をみながらひとつずつ丁寧に取り組めていました。ターゲットは隠さないのかを聞きましたが、「まだいい」とのことでした。コスチュームを変えるプログラムも自分で試しながら取り組めていました。ジャンプ力を変えるときも自力でプログラムを見直して修正していました！上にはみ出したときのプログラムも、座標を自分で加減して考えて取り組めていました！ 動画をただ見ているわけではなく、何を自分がしているのかが分かっている様子です。自分がプログラムした内容についてはしっかり考えられていましたが、これからすることに対してはあまり考えられていないようです。', '次回は25:19くらいからスタートです。背景スクロールがうまくいかないので、修正したいです！', 'タイピング: 取り組めていましたが、記録はしたくない様子でした。'),
  ('6d03b0a8-b5cb-54af-9b38-4b37eb4ecb8a', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-07', '17:30:00', null, '通常 / バグ修正の問題３問だけにしぼり、その後は自分が好きなタイピングを行う', '初級レベルチェック（はらぺこ〜）はやらないで、バグ修正のみをやりたいと言ったので、３問行いました。 １、２に関しては手を動かしながら、修正（理論は２番目の問題はちょっと話かならなかった様子ですが、かつ、またはの違いに関しては理解したようです） ３に関しても動かして、どうしてそうなるか？はわからなかったようでしたが、条件分岐の重ね合いに関しては少し違うだけでも正誤性が少なくなってしまうことを理解したようでした。 残り30分間は寿司打でタイピングの練習をひたすら最高点までやろうとしていました', null, 'タイピング: 準２級のレベルになり、過去最高だ！と嬉しそうでした！'),
  ('23b48e74-37d1-5182-b52a-b06e395473f9', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-07', '16:30:00', null, '通常 / バグ修正の問題２問 ①右端にふれた瞬間に、消えて欲しい（現状消えない） https://scratch.mit.edu/projects/707851367 ②１００以上の数を入れてもまる判定になる https://scratch.mit.edu/projects/707852979', '①の問題に関しては、右端という考え方が座標の数字でその数字が見ている部分ではないということ、をきちんと確認できた様子でした。 ②に関しては、かつ またはの違いがまだやってなかったようで、問題を解いた後に説明を聞いていた時に「なるほど」と理解できていたようでした。かつ、または が今後ゲームなどを作る際にうまく使用してくれたらと思います。', null, 'タイピング: 3分間でタイピングした量は少ないものの、正答率がかなり上がっていました（97%） 丁寧に行えることがとても素晴らしいと思いました
盛り上がり: かつ、またはの違いをきちんと理解できたようでとても良かったです'),
  ('4c72804e-47c5-54f3-bb94-b402d90423c3', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-07', '16:30:00', null, '振替 / 前回の振り返り〜はらぺこサメ初級スキルチェック https://app.arspark.jp/contents/11346 を行ったので、今日はそのアレンジを行うみたいな感じに。 特にメッセージの送り合いなどを復習する', '今日は、さかとなが逃げ切れた！という部分〜アレンジへ。 最初に逃げ切れた部分に関しては、”新しく学んでいる”ということを重点的に思い出しながらメッセージのやりとりを確認しました。 アレンジに関してはもう１っぴきサメと魚をだしましたが、同じ動きになってしまうこと自体に疑問を持っていなかったようなので、どのコードで違った動きにできるのか？をコード全体を見直してもらい作ってみました。 何歩動かすの数字を変えることをまだ思い出せないのか、もしくはコードがたくさんあることで読むことをやめたいのか？がわからなかったのですが、それでもヒントをもらいながら音をつける部分まで行いました', 'メッセージの部分と動きの部分、特に何歩動かすと座標で動く系の違いをもう一度おさらいした方が良さそう', 'タイピング: 初級の森がクリアできたようで、とても嬉しそうにしていました！
盛り上がり: アレンジをする際に自分でなにか作れる！というのが嬉しかったようです。'),
  ('ad43d8e3-9aaf-5cdb-be1e-5b50a0f068cd', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-08-04', '18:40:00', null, '休み（未対象）', null, null, null),
  ('c6d2cef3-7a1e-5655-8080-175b443332d5', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-04', '17:30:00', null, '通常 / 基本操作コース03 世界を想像しよう→メッセージを送った後に条件分岐をし当たったらメッセージを送り、言葉セリフを言う 337拍子で音を作ることを学ぶ＞音階で自分の希望する音楽を作れることand音もメッセージが受け取ったら、ならせるという部分まで', '最初のメッセージの部分は前回からの復習でやっているので、もう一度行うことで理解したようでした。音に関しては、作成もできるよ〜と話しましたが、めんどくせーと言っていたので音楽系に関してはあまり興味がないのかな・・・と思います。', null, 'タイピング: タイピングはまだまだといったところですが、自分でタイピングやってみようという気持ちは高くてGood
盛り上がり: メッセージの受け取りなどをもっと掘り下げていきたい様子でした。'),
  ('d48cedca-4fd2-5f9c-b5b0-b21caec0d5bf', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-07', '16:30:00', null, '通常 / 作品見直しと47数当て', '大会作品では、ゲーム終了後にスプライトにポインターが触れてしまうとヒントを喋ってしまう現象があったので、そこを修正していました。私が気になった点を伝えただけでしたが、しばらく自分で考えて自力で訂正できていたので素晴らしかったです。 数当てについては、問題文がすぐに理解できずに悩んでいました。「大きい」「小さい」の言葉に引っかかり、困っている様子でした。定義の内容があやしいことには気が付けていました。最後に定義の内容を説明しつつやると納得した様子でした。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 商用利用もできるおすすめのイラストサイトを共有しました！'),
  ('5cf1e822-8e47-5e85-b3f5-63a34a4ce349', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-04', '16:30:00', null, '通常 / Easy 右端にふれた瞬間に、消えて欲しい（現状消えない） https://scratch.mit.edu/projects/707851367 くじびき 大当たり～はずれがきちんとランダムに表示されない https://scratch.mit.edu/projects/707862969 ＋自分の作品の続き', '右に消える問題に関しては、座標の理解と隠すというコードが問題だよ〜と話したところ、少し考えた先で簡単に解いていました。くじびき〜の方に関しても演算が関わっていることにすぐ気がついてきちんと自分の頭の中で文章が構成されコードをその上で書くということができている様子でした。 最後は自分の大会に提出した作品をもう一度見直して、アイテムをゲットするまでにとてもプレイヤーが左右に動く動きを難しくしていた様子でした。', null, 'タイピング: ナシ
盛り上がり: 簡単に問題が解けたということにとても自信を持っていたようでした'),
  ('4a93e771-10b6-59b3-8c31-f7b5ab2d9a84', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-08-04', '16:30:00', null, '通常 / バグ修正を見つけられるか？ Easy １００以上の数を入れてもまる判定になる https://scratch.mit.edu/projects/707852979 難しい かずあての正しいヒントが数を入れた後に出てこない https://scratch.mit.edu/projects/708196863/editor/', '最初のEasyの問題は、楽に”かつ”じゃないとダメだということに気がつけたのですが、かずあての正しいヒントの方で不等号の向きの違いにとても戸惑っていた様子でした。 変数や、条件分岐に関してはとても理解ができているというのは分かりましたが、不等号系右と左で入るものが違ってしまうと動きが動かない＝今回の作品作製でも不等号でバグっていたものもあったので、その辺りを次回から丁寧に行っていきたいと思います。', '不等号の使い方', 'タイピング: なし
盛り上がり: 問題を２つ解くこと自体はあまり苦ではなく、問題なんて楽勝〜という感じに解いていました。ラスト30分ほどはゲームを存分に満喫した様子で、半期の授業を終えていました'),
  ('4550cb4d-c89d-531e-946c-a400931d78dd', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-08-05', null, null, '通常 / メッセージなどの新しいコードを習得する', '「 腹ペコザメからにげろ」のプリントにのっとって進めました。 今日はメッセージを初めて扱いました。誰かがメッセージを送ったら別の誰かが受け取り、そのときの動きをするという流れを共有しました。また、「スプライトの他のスクリプトを止める」ブロックも初登場だったので、スプライト=サメなどのキャラクター、スクリプト=ブロックの塊、というように説明しましたが、まだ理解は難しかったようでした。さらに、「～へ向ける」「～へ行く」の組み合わせもやりました。これら2つのブロックは紛らわしいので、向きと移動という違いを説明しました。ゲーム自体はほんの一部を除いて完成しました。', null, '時間帯: その他
タイピング: いつも通り集中してやっていました
盛り上がり: レベルが高くなりましたが集中を保てました。'),
  ('f1419c59-7938-576b-9036-76194c2d1a91', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-08-05', null, null, '通常 / 問題を解く', '大会が終わって初のレッスンだったので、どれくらい力を出せたかを聞くと7割くらい出せたと答えていて、初めてにしては上出来でした。 最初の問題は若干試行錯誤を挟みましたがきちんと解けました。 次の問題はよくわからなかったようで、「または」のブロックをとりあえず適当な演算ブロックに変えまくっていました。数字が「0より大きい」と「100より小さい」の共通部分を取ると0～100までになることを、紙に書きながら説明しました。完全に理解できたかは怪しいですが、「かつ」と「または」を使い分けないといけないことは分かったと思います。そのあとは三問目に入ることを促しましたが、二問目のアレンジ(と言えるかわかりませんが)としてネコのクローンを大量に作って動かしていました。', null, '時間帯: その他
盛り上がり: 気が散るからスクラッチのゲームのタブは閉じようと言ったところ応じてくれたのですが、問題のアレンジで遊んでいました'),
  ('2e55ee6d-1108-5532-a8a3-83c49d3a3f79', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-05', null, null, '通常 / Prg25 野球ゲームつづき', '最初からやるのかと思いきや、前回の続きから始めていました。気の進まない様子でしたが、前回自分がやった範囲は覚えていた様子です。動画の内容をそのままプログラムしていた様子なので、用いられているブロックの使い方について全てを理解できているわけではないと思いますが、しっかり集中して取り組むことができていました。 やる気があるのかないのかがこちらから分かりにくく、どう促すかが難しかったです。思っていることと言っていることが違うのかも？？？', null, '時間帯: その他
タイピング: やりましたが、かなりやりたくない様子でした。'),
  ('e6aec77c-b848-5a4a-9e68-e6139a8ec197', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-05', null, null, '通常 / サメから逃げろ', 'タコスを動かす際に、角度と動く距離の対応が十分でなくマイナスを使ったり、サメに「ぶつかったら隠れる」のコードを間違えていれたりしていました。角度と歩数の話は完璧に理解できたかは分かりません。 後半でアレンジを加え、消えた後に再び出現するようにしました。「〇秒待つ」を使いましたが、サイコロの話とともに乱数の話をしました。うっすら分かってくれた様子でした。', null, '時間帯: その他
盛り上がり: サメが好きなようです。生態についていろいろ教えてくれました！'),
  ('841cb3dd-795d-59f5-9f48-a5e45ff9689e', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-05', null, null, '通常 / 〇22. 右端にふれた瞬間に、消えて欲しい（現状消えない） 〇31. くじびき 大当たり～はずれがきちんとランダムに表示されない 〇25. 0より大きく100より小さい', 'とても集中して取り組めました。右端のプログラムについては、猫のx座標に注意してみるように伝えると自分で全て気が付くことができました。0より大きい数については、怪しい箇所はなんとなく見つけられていました。「または」「かつ」のブロックの考え方の違いがあやふやだったので、図示しながら説明しました。くじびきの問題は、数が大きいものから考えるようにアドバイスをしました。 最後に右端のプログラムをアレンジして、サメが旅をするプログラムを作っていました！', null, '時間帯: その他
タイピング: 集中して取り組めていました。タイプミスがほぼありませんでした！すごい！'),
  ('ba43a036-fd47-5171-bde7-4236a3656d28', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-04', null, null, '通常 / 〇右端にふれた瞬間に、消えて欲しい（現状消えない） 〇0より大きくて100より小さい', '「隠す」のブロックを自分で持ってくることができました。置く場所に困っていたので、時系列に沿って一緒に整理しました。また、「また」という概念をあまりよく知らなかったようなので、ベン図を使って色分けをして説明しました。理解できたかは少し微妙です。 最後に右端のプログラムをアレンジしてもらいました。渦巻きの効果やモザイクの効果を使って面白くできていました。ビームのプログラムを作ったときのことをよく覚えているようです。', null, '時間帯: その他'),
  ('6e7acb59-9b3a-5e2e-a4e7-9a52f1158281', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-04', '17:30:00', null, '通常 / 〇右端にふれた瞬間に、消えて欲しい（現状消えない） 〇くじびき 大当たり～はずれがきちんとランダムに表示されない 〇0より大きく100より小さい 〇数当て', '右端、くじびき、0より大きく100より小さい問題はスラスラ解けていました。数当てについては、怪しいところを直しただけだそうですが、うまく動いて満足そうでした。ゲームなど、他の要素が絡むとたくさんのことを一度に考える必要がありますが、重要な部分だけ抜き出して考えることは得意な様子でした。 最後にスプライトを自分でアレンジしていました。猫の色を変えたりウサギの耳を付けたりして楽しんでいました。', null, 'タイピング: 集中して取り組めていました！'),
  ('37d7c7d2-b24d-570c-b867-d21703d2909e', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-04', '17:30:00', null, '通常 / 〇右端にふれた瞬間に、消えて欲しい（現状消えない） 〇くじびき 大当たり～はずれがきちんとランダムに表示されない 〇0より大きく100より小さい', 'よく考えてプログラムできていました。「隠す」のブロックをきちんと置けていました。端まで動いた後のプログラムがうまく動いていなかったので、端の考え方を伝え、数字を調整するようにアドバイスをしました。くじびきの問題は順序だてて考えることができていましたが、中当たりから考えていたので順番を変えるように伝えました。0より大きく100より小さいプログラムもいろいろ試して自分で考えられていました。', null, '盛り上がり: ふりこに興味があるようです。二重振子のプログラムで遊んでいました。'),
  ('42282235-a2eb-53b3-bdf4-74761589c448', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-04', '16:30:00', null, '通常 / 右端にふれた瞬間に、消えて欲しい（現状消えない） くじびき 大当たり～はずれがきちんとランダムに表示されない', '「隠す」のプログラムがすぐに思いつかない様子でした。自分なりに考えることができていました。「～まで繰り返す」のブロックの意味があまり理解できなかった様子です。くじびきのプログラムについては、数が大きい方から整理することができていました。最後の場合分けに苦戦していましたが、順序に気を付けてうまく完成させることができていました。', null, null),
  ('ba5d2033-d28e-58ef-ae4c-afb2496e1513', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-08-04', '16:30:00', null, '振替 / 〇右端にふれた瞬間に、消えて欲しい（現状消えない） 〇くじびき 大当たり～はずれがきちんとランダムに表示されない', '「消える」のブロックがすぐに思いつかない様子でした。使い方も「～まで繰り返す」の中にいれてしまったり、よく考えないでブロックを置いてしまっているイメージでした。 くじびきも、問題の解決方法がすぐに思いつかない様子でした。演算のブロックと条件分岐のブロックをうまく組み合わせることができず、困っている様子でした。こちらがアドバイスをして完成した後に作成したプログラムを振り返ったのですが、「知らない」の言葉が多くて残念でした。', null, null),
  ('3b948506-733a-52cf-9989-afe59147d930', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-08-04', '16:30:00', null, '休み（未対象）', null, null, null),
  ('a49c9139-d284-5aa7-b30f-21da266a18b1', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-31', '17:30:00', null, '通常 / 大会作品完成、提出', '前半は、最後に残っていたラスボスの製作をしました。ビジョンは見えていたのでさくさく進みました。二つの隕石が飛んでくるときに重なって表示されてしまったのですが、1秒ずらして重ならないようにするなどの工夫ができていてよかったです。 比較的余裕をもって作品が完成したので、自分で文字を打って提出してもらいました。', null, '盛り上がり: きちんと終えられて少し安心したようでした。'),
  ('495c0bff-ff4a-572a-ae32-c58dd85af8cb', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-08-03', '17:30:00', null, '振替 / 東京大会に出す作品作り', '◆8/1に発熱により八王子大会に作品を出せず。東京大会をおススメしたところ、かなりヤル気 ◆大会概要の説明、テーマ性の重要性を伝えたところ、八王子で作ったのではなく新しい作品を作って提出したいとのこと。作品アイデアの収集がメインとなりました。 ◆八王子大会の提出予定の作品を見せてもらったところ。バグが多く途中であるとのこと。ハルちゃんと同じく、場面転換が多いにもかかわらず、それらを「時間」でコントロールしていたので。場面の変数の使い方と考え方は紙に書いて説明した。 ◆但し、「場面転換を変数を使う」というのは新しいスキルでこれを今から使うのは大変かもしれないから、今回はまずは自分が好きなように作ってみてもいいよと伝えると、結構、即座に「まずは自分のやり方で作ってみる」とのことでした。 大会作品作りを終えたら、変数の使い方、演算系などスキルアップの習得を目指したいところです。', null, 'タイピング: 割愛
盛り上がり: 自分の中で、ある程度イメージがあるようだったので、まずは自由に作るように促した。昨年の決勝大会の動画をみたり、その作品を検索して内容を確認するなど、情報収集力の高さは凄いです！'),
  ('92f3eb5f-c799-54b2-b3d4-b7745c17f6f0', 'b2246586-4496-52f9-a825-be2488a00a31', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-08-03', '17:30:00', null, '休み（未対象） / 連絡忘れのお休みでした。退会を希望とのこと ⇒レッスンの様子に記載あり', '先日、学校のPC持ち帰った時に、タイピングが全くできていないことに保護者さんがショックを受けたとのこと。 「やりたがらない」という話と、それ故に「楽しくが第一であった」ことをお伝えしたが、「さすがに２年通って、何にもなっていないとは、、、、うちの子の問題なのかもしれまえんが」とのことでし他(T_T) ９月末に退会予定で、それまでにタイピングは少ししっかりやってスキルアップできるようにしておきますと、お母さまに伝えました。', null, 'タイピング: ─'),
  ('c06f1746-b1c7-5217-9af1-ddc16bf7cfa3', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-03', '17:30:00', null, '通常 / 跳ね返り、まで待つ、クローンの理解', '最初に、迷路の横切り禁止が跳ね返りなく作っていたので、なるように考えさせました。そして、適当にやったらできただったので、質問攻めして理解の根本を作りました。そして、コインの方も「もし」から「まで待つ」に変えてもらったが、本人がより深く理解するためには不十分だと思い、また、クローンをやったことがなかったので、後半宇宙バトル3を作りました。動画のステップで長押しでも連射できてしまうことに見る前から気づいたので着眼点はいいです。「まで待つ」の発展として「ではないまで待つ」で連打防止になることをしてもらいました。これらのスキルを使えるように、まで待つ」なら連打の競争ゲームとか、クローンに関連するものを1から作らせたほうへ進めた方がいい気がします。', null, '盛り上がり: 周りへゲームを誘う誘惑をすごかったです'),
  ('5634cc8c-8b7a-54b6-be6d-4bcc88e89cc5', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-08-03', '17:30:00', null, '通常 / 【目的】これまで。結構たくさんのプログラミングを使えるようになってきたから、それを使った復習！', '↓難しいサメから逃げろ https://app.arspark.jp/contents/11346 ずっと「虹色ピンポン」をやっていたので、気分一新で。 ・これまで、案外沢山の作品、種類を作っているようですが。やや精度が悪い（＝各教材のテーマを理解はしきれていない様子） ・飽きやすい子なので、それも致し方ないが。一旦、基礎を整えたい。 ★「サメから逃げろ」の教材を見せたところ、「やったことある」とのことであったが。動きのプログラミングイメージが全くわかなかったので、「名前を動かそう」でやったよね～と伝え、２月にやった。こんだけたくさんやったプログラムの復習ね！と何度も念押ししました。 ⇒やったことがある＝できる、という事ではないということの認識を徹底してあげてください ⇒「やったことがある⇒忘れてる⇒じゃあ、復習しよう」という流れの徹底でお願いします。 ★「サメから逃げろ」のサメの動き、メッセージのやりとりが全くできませんでした(T_T) →次回予定に記入あり', '◆タイピングを少しやらせたいというお母さんの意向があり。フォームポジションなどのお話がありましたが。それ以前に「アルファベットをあまり覚えられていない」と伝えました。お母さんともお話をしたので、少し、しっかりとタイピングをする方向が良いです。 ◆まずは、検定４級合格できるスキル習得を目指しましょう！', 'タイピング: ─'),
  ('11a5bac3-040d-5545-9619-1d755f116cba', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-03', '16:30:00', null, '通常 / メッセージの使い方をなれよう', '前回物語でメッセージを使ったことから、今回はゲームつくりの中でメッセージを慣れてもらうことにしました。最初に遊んでもらって、それぞれのスプライトの特徴を述べたところ、不足なく読み取れていました。コードの動きは紙に書き、コードの橋渡し「へ行く」「に向ける」などの初めて触れるブロックは試作して自分の手で動かしながら、教えていったので、驚きを感じて理解している感じでした。サメの出現で、右端から出てくるが、座標の認識がまだ甘いか少し悩ませていました。ここは、しつこく聞いて定着させたほうがいいです。サメが魚を狙って動くところまでできたので、ゆっくり進めてあげてください。', null, 'タイピング: ストーリーのあるものを初めて、敵を倒していくことに興奮してました。
盛り上がり: 先週初めてよみうりランドに行って、サマランより全然楽しかったそうです。'),
  ('26686936-4ccd-5370-8fe2-828e29ae6dab', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-27', '17:30:00', null, '通常 / 小技を学び自由作成に生かす', '先週と同様に小技を勧めたところ乗り気だったのでやってもらいました。内容自体は簡単だったのですぐできましたが、目つぶしの要素を入れたいということでアレンジに入りました。もともとのきも目玉と合わさって、まさきくんらしいカオスな作品ができました。血走った目なども描いていてリアルでした。', null, '盛り上がり: 定期的にせいくんに見せていました。'),
  ('1c7086f6-37c0-532a-8ffa-2146791f06ee', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-27', '17:30:00', null, '通常 / 割った余りの学習', '素材のみで1から作るのは難しそうだったので、リミックスしてアレンジする方向で進めました。せいくんが鳥の速さがだんだん速くなっていくことに気付いたあと、どんな条件のときにどんなコードでそれを実現しているか考えてもらい、5で割ったあまり=0 という演算を使っていることを知ってもらいました。 そのあとゲームのアレンジに入りましたが、さっき勉強した あまり=0 の演算を応用して、15点取るごとにビルの隙間を狭くしていました。いいアウトプットになったと思います。', null, '盛り上がり: ゲームを作るよと聞いたときは少し喜んでいました。アレンジもよく考えながらやっていました。'),
  ('94f98085-ec6c-55bc-bd7c-b56b28e58432', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-01', '17:30:00', null, '通常 / コンテスト作品完成', '前回ほぼ完成していたので、細かいところの手直しをしました。書いてきた文章から少し修正してコードも直していました。完成した後も入力作業も素早くできて、無事完成しました。', null, '盛り上がり: 4時間も塾言った後に来たのに、しゅうちゅが途切れませんでした。'),
  ('e9f79f50-e5fd-5ca9-bd68-ab0dab26f530', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-01', '17:30:00', null, '通常 / コンテスト作品完成', '作品は1度は提出したが、まだ、作りたい理ない部分があったので、作り増やしました。ドラゴンが動かないまま、ただビームが必ず当たってしてまうだけだったので、ドラゴンを乱数で動くようになりました。乱数の使い方は範囲を決めて使うことを覚えていました。バグで体力が減らないことがあったが、時間がなかったため、こちらで応急処置しました。そして、EDも自分好みに作れて満足が作れてよかったです。', null, '盛り上がり: 完成したときは、前余地もよい笑顔を浮かべていました。'),
  ('0a747d3d-1093-5c09-9f58-edd88ca3e6d0', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-08-01', '16:30:00', null, '振替 / コンテスト作品完成', '来て早々、フグの敵回りバグを修正していきました。1つのバグを直すとまた別のバグが生まれて、その連鎖が何回か続いてしまいました。それでも一生懸命バグを直して、時間いっぱいにかけて完成できました。不等号やメッセージの煩わしさをバグを起こしていました。', null, '盛り上がり: 1時間以上の集中力が続いていました。'),
  ('8055fa9d-4bad-509b-9e95-80c1fca17da8', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-31', '16:30:00', null, '通常 / 大会準備', 'ごみよけゲームをリスタートできないというバグについて一緒に考えました。該当部分のコードを確認して変えてみたりしましたが、しばらくしても解決に至らなかったため他のところを先に進めてもらいました。教室では終わらなかったので、家で提出すると言っていました。', null, '盛り上がり: 作業途中そのときの状況を共有してくれたりして、頑張っていました。'),
  ('65fe6869-9971-58e4-933f-3bc94bd232b1', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-31', '16:30:00', null, '通常 / 大会作品完成、提出', '気になったポイントとして ・木を最前面から最背面に変える ・タヌキが動くときに向きを変える があったので伝えたところだいたい自力で直すことができました。ゲームオーバーのスプライトも最前面に来てほしいところ最背面になっていたため、木の応用で修正できました。向きを変えるときの「回転方法を左右のみにする」は忘れていたようなので軽く復習しました。また、ゲームオーバーの条件が「体力=-1」であることにより正しく動作しなかったので、不等号を使って書き直してもらいました。他に追加したい要素もあったようですが、時間がなくなってしまったためそこで提出しました。ゲームとして成立させることはできました。', null, '盛り上がり: 最終調整を集中して頑張っていました。'),
  ('2f1b0a5b-a852-5e15-af24-ec87597952e4', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-31', '17:30:00', null, '通常 / スクラッチでフォートナイト風ゲーム を動画みながら作成 youtube.com/watch?v=MHvwnU0_yP0&t=10s', '３０分間はクリアしようとゲームで遊んでいましたが18時からは絶対作成するよ〜と約束し、動画を一緒にみながら作成してみました。 いくつか自分でもわかるコードがあったりと、割とすんなり動画の速さと同じぐらいのレベルでコードを書いたり変数を作ったり、定義を作ったりしてくれていました。', '来週はおじさんの動きを作るところからです！', 'タイピング: 変わらずタイピングは成長めきめき成長しています！
盛り上がり: 相当楽しかったようです、クリアしようと頑張っていました！'),
  ('2424e217-9ac5-5d13-b42a-6352e2229e1b', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-31', '16:30:00', null, '振替 / 自分の作品&提出まで', '今日はまだやりたい部分があると言っていたのですが、できている部分までは頑張ってもらいました。 特に武器を選んで棒人間に持たせるというコードを一緒に作り、ひとまず家の中に入るまでの部分に関しては満足していた様子でした。', null, 'タイピング: なし
盛り上がり: 家の中に入った後に、ベットに寝たりしたいと話していたのですが、それはスプライトを別に分けてあげないといけないよ〜と話したりしていたので、次回来た時はその部分をやってもいいかも知れません。 アイディアが出てくるのはとても良い傾向だと思います！'),
  ('2532e1da-7272-5aa4-af6d-6d6734c26ddd', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-31', '16:30:00', null, '振替 / 自分の作品&提出まで', '上に通り抜けてしまうバグは、迷路と同じようなバグなので色々とこれはこうだったよね〜と話ながら進めてみました。 最後は全てのバグを潰せ、きちんとゲームとして完成。 提出もお母さんが来るまで自分で入力してくれ、きちんと提出することができました。', null, 'タイピング: なし
盛り上がり: 勘が良いので、１ついったことに関して、１０で返してくれる理解度がありとても有意義な大会までの道のりだったのではないかな？と思います。'),
  ('8b069421-9a0d-5f00-8688-f2825bfcdd1a', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-24', '17:30:00', null, '通常 / 大会準備', 'ほぼ完成に近いと思っていましたが、意外とやることがありました。まずは、倒した敵が隠れないというバグを直しました。しゅうくんが該当の敵の挙動をよく観察すると、倒したときに一瞬隠れているがすぐに表示されていることがわかりました。そこで、「表示する」ブロックがあるところを見ればバグの原因がわかるねと誘導し、敵を間違って表示しているスクリプトを止めることができました。 その後ラスボスの製作に入りました。完成はしませんでしたが、隕石が主人公を追いかける形で攻撃するようにしたいと言って方向性は決まっています。 エントリーシートもだいたいは書けているので、次回提出できそうです。', '作品を提出', '盛り上がり: バグつぶしなどの作業に時間がかかって焦っていましたが、来週もあるから落ちついていいよと伝えました。結果、後半のほうは順調に作成できていました。'),
  ('d2e17d10-0033-5225-83f9-5303dbab9d33', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-24', '16:30:00', null, '通常 / 大会準備', 'りんごが意図しないところで表示されるというバグが前回解決しなかったため一緒に考えました。りんごを表示するためのメッセージが連投されていたため、そのスクリプトを止めることで解決しました。その後は、森の場面と川の場面を交互に切り替えるのに取り組みました。ゲームの流れを時系列で追っていくと、適切なタイミングでメッセージを送りあって交互にすることができました。また、メッセージを多用しすぎて複雑になってしまったところがあったので、「〇秒待つ」を使って簡略化しました。最後の方に、触れたら体力を減らしてくる敵の熊を追加していて、面白いアイデアでした。イージーモードに関してはほとんど完成したようです。', '本人のやる気次第でハードモードを作る(提出はイージーのみでもOK)', '盛り上がり: 問いかけに応じてしっかり考えてくれます。コードの流れを把握できています。'),
  ('1c625bb2-7f79-5cb6-b3e5-90a41bf5256f', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-29', null, null, '通常 / 作品提出 チエテラスは40分くらいを目安に。レッスン5の条件分岐と反復を進めてもよいし、レッスン4の変数をもう一度解きなおしてもよいかも。', '作品提出は、あくまでもこっそりと自分でやっていました。提出前に見せてほしいと先生たちが声掛けをしていましたが、見せるのも、紙に書いて先生にわかるようにするのも嫌だとのこと、自分で責任を持って入力するとのことなのでそれ以上は立ち入りませんでした。 提出後はロブロックスをしていたので、レッスン1でもよいから進めてみようということで、チエテラスに入りました。変数への数値代入や真偽判定などで間違えた時に確認しましたが、口頭ではわかっているとのこと、実際に説明させてもあってはいるのですが、選択肢をよく見ないで押してしまった等、少々動作がいい加減になっているところも見受けられました。 チエテラスの後は一人でロブロックスをしていましたが、一人にされると少し寂しいのか、他の子のレッスンをのぞいてみたり、独り言を言っていて先生が反応すると喜んで会話するようなところもありました。', null, '時間帯: その他
盛り上がり: レッスン内容や態度についてはまだ迷走中ですが、一時よりも会話をしたそうな様子を見せるようになりました。また、ちひろくんが整数判定について考えているときに、自分も一緒に考えてみたりするそぶりを見せていました。あともう少し、何かきっかけがあるとよいのかもしれませんが…'),
  ('85053fd7-cae3-543b-b3b3-12245f52dd54', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-29', null, null, '通常 / コンテスト作品の提出 ・内容を確認の上、提出作業。 ・提出が終わったら、検定4級の1回目', '家で音声や画像をいろいろ取り込んできたそうで、それらを素材としてオープニングやエンディングの作成をしていました。 ゲームとしてはだいぶスッキリとして、片付けたあとは雑巾で仕上げをするなど、掃除の手順がゲームになっていました。 二人の時は作成中の画面を良く見せてくれたり、雑談をふってきたりもするのですが、だいきくんが先生に見せないで一人で提出しているのを見たら、一気に秘密主義になってしまいました…。 提出後にも、頑なに紙への記入を拒んだり、IDを教えてくれなかったり等、作品を見られたくないモードでしたが、帰り際にこっそりと、ゲームをドライブに保存したから、と報告してきたり、かと言えば「僕がいないところでは見ないでね。一緒にみよう」と言ってきて、構ってほしそうな様子を見せたりもしていました。', null, '時間帯: その他
盛り上がり: ゲームをプレイさせてもらって、良くなっている点を指摘したら、嬉しそうにしていました。本人なりには、思った通りのゲームができて満足できているようでした。
備考: 教室にくるなり、学校の先生と親子プログラミングの話になり、教室で教えてもらっている伊藤さんって、あの伊藤さん？と聞かれたんだけど…と聞いてきました。伊藤さんが主催者だとこたえると、とても驚いていました。'),
  ('44821b38-b882-528c-b0b9-8096ebb340ec', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-29', null, null, '通常 / チエテラス、またはScratchでのスキルを増やす', '最初に検定合格をお祝いしたら、満足そうにしていました。このまま1級までとってしまいたいそうです。 チエテラスの説明もした上で、Scratchの学習との配分を話し合い、お母さんからの希望（LINE参照）もふまえ、Scratchとチエテラスを6:4～7:3くらいで進めていくことで合意しました。 過去に自作したアルスパークの作品を見直していて、シューティングゲームで弾の連打が思うようにいかないところがある、と聞いてきたので、宇宙バトル3を見せて確認させ、「スペースキーが押されたではないまで待つ」がなかったため、と原因を発見できていました。 今日はScratchで色々やりたい気分、とのことだったので、シューティングゲームで使い始めたクローンの学習、中学生なので数学的要素が入る作品、ゲーム以外にもScratchでできることを学ぶ、等の目的を話した上で、本日タイムリーの花火を課題にしました。 とりあえずテキストを見ながら自力で作成してもらい、その後で改善したい点を見つけてもらいました。「花火の消え方が本物っぽくない」とのことなので、色々な数値に着目して編集してもらい、消え方のきれいな華やかな花火を作成していました。 タイマーの整数判定をしたいとのことで、しもさんに教わっていました。', '次回ももう少し作り込みたい、とのことでした。', '時間帯: その他
盛り上がり: ゲーム以外の作品にも興味を示してくれたので、視野やスキルを広げるために色々な作品をやっていこうと話すと嬉しそうにしてくれました。 花火をきれいにするのに熱心になって、今日はチエテラスではなくこのまま編集を続けたいと言って、時間を少し延長して頑張っていました。
備考: お母さんのLINEにもありましたが、学校での勉強では英語がダントツでできる反面、周りが優秀なせいか落ち込んで登校が難しいこともあるそうなので、ここでは楽しく自信をつけてもらう方向ですすめていきたいです。'),
  ('e5708f19-b506-590c-b092-31bab00ba3a6', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-29', null, null, '通常 / 大会準備、提出', 'エントリーシートのアピールポイントに書いてあったラスボスが未作成だったのでそれに取り組みました。スクラッチのゲームにはまってしまったらしく、製作途中もそれをやってしまうことが多々あったので、今日中に頑張って提出までしようという目標を改めて共有しました。残り時間が少なくなってくると危機感から集中力が上がっていました。最終的にレッスン時間はけっこうオーバーしてしまいましたが、ラスボスのドラゴンが吐く炎で攻撃するところやゲームオーバー・ゲームクリアなどを作り、ゲームとして完成しました。 エントリーシートは全部書いてもらったので先生側が提出しました。', null, '時間帯: その他
盛り上がり: あおしくんの完成作品をそうたくんが楽しみにしていたのがモチベーションになったと思います'),
  ('0b948e00-80ba-597d-8a30-6a24b56f7818', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-29', null, null, '通常 / 壁のすり抜けをしないようにつくろう', '20分くらい遅れてきたので、最初からチーズの探せのゲームを作りました。遊びを長くとったから、コード作成に移りたかったです。後ろで、授業の終わったそうたくんの遊んでいるゲームにだいぶ気がとられていました。気がそれて、急に「どうやんの」と突っ込んでくるので、その時の気持ち高めて進めました。上下左右の向きの感覚が正しくできていたので、それは良かったです。跳ね返る仕組みを軽く説明したが、何とか迷路は貫通しないよう人はしました。', null, '時間帯: その他
盛り上がり: 半分はそうたくんの遊んでいるゲームに気がとられました。'),
  ('4292b0db-765d-51e7-8e0b-801302bb596c', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-29', null, null, '通常 / 作品提出、レッスンを進める', '今日は来た時は落ち着きがなくプログラミングを始めるのは難しい状況だったので、最初のほうはゲームで遊んでもらいました。 しばらくしたあとレッスンを勧めると、サメから逃げろに興味をもったので始めました。動画で「矢印キーで動かせるようにしよう」と言ったときに、「これは自力でできる！」と意気込んでいたので、その部分のコードを書いてもらいました。使うブロックは合っていましたが、動く方向の左右が逆になってしまったのが惜しかったので「〇歩動かす」の使い方を改めて確認しました。 虹色ピンポンについては完成はしたが提出が済んでいないとのことだったので、お迎えに来たお母さんに必要事項をうかがって提出しました。', null, '時間帯: その他
盛り上がり: レッスンを始めたあとは集中していました。'),
  ('09207844-83d4-5f4b-86b2-35f58f6b8ade', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-29', null, null, '通常 / 使えるコードの幅を広げよう', '今までの作品で使われていなかった「まで待つ」や「乱数」について学ぶために、チーズを探せを作りました。最初に、さいころで乱数とはどのようなものか見せて、コード上での仕組みを理解できていたので、スムーズに進めました、迷路の壁がすり抜けないことは、ヒントを与えずに進んだ分戻ることが理解できていました。また、1個1個動きを別に作る傾向があったので、見やすさの観点から1つの旗の押されたのみでまとめて作ることや、壁のすり抜けが起きてしまいやすいコードの並びの違いも教えておきました。乱数による座標移動は、最初からスプライトを動かして移動させたい範囲を調べることをできてたので、センスがいいです。コイン集めになるようにアレンジして完成できました。', null, '時間帯: その他
盛り上がり: 作るときは作るモードになって、のちのゲームをたらふく楽しんでいました。あおしくんのゲームの試運転もしてくれました。'),
  ('6cc1eb8b-c9b7-5814-bb32-256970fa9087', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-29', null, null, '休み（振替対象）', null, null, '時間帯: その他
備考: 本日、コンテストビギナーズ部門に作品提出しました。'),
  ('3cad9b06-5d9f-52f1-88b0-9e504c693afa', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-22', null, null, '通常 / 作品提出、レッスンを進める', 'にじいろピンポンについてはゴールの点数などを作る予定でしたが、気が変わったらしくやっぱりいいと言っていました。ゲームとしては成立していて面白いアレンジもできているので、そのままアピールポイントなどを書いてもらい提出しました。 その後はレッスンを進めました。以前途中で終わってしまったゾンビをたおせ1を完成までもっていきました。比較的複雑なコードを書くのにも慣れてきて、「もし～」の中にいくつかブロックが入っていても整理しながら作れていました。', null, '時間帯: その他
タイピング: よくできたときはこうしろうくんに自慢していました
盛り上がり: 製作するときは集中していました。'),
  ('8bd774d2-98bb-5157-a354-0635e398818e', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-28', '17:30:00', null, '通常 / チエテラスの続き', 'for文とif文の使い分けの方法を覚えていたり、今回から初めて出てきた配列についての数え方や引き出し方なども少しずつ覚えていました。しかし、配列には少し苦戦しているようでした。特にfor文と組み合わさっていたものでは正答率が少し落ちていました。しかし、少しずつ覚えていけていると感じました。', null, 'タイピング: javascriptの関数についてのタイピングだったので、少しつまるところもありましたが全体的は高得点を出していました。
盛り上がり: for文とif文の内容を分けて考えているときは特に頭を回転させていました。'),
  ('2867181e-1eab-5902-80a2-f7b28b4fbd75', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-28', '17:30:00', null, '通常 / 基本03 世界を想像しようの続き 大きさを変える、音を追加する、場面を追加して変更する', '今日は得に座標とメッセージも含めて説明したのですが、動きが加わることによってこれからやることの期待感のようなものが、ゆづきくんに芽生えていたような感じがしました。 また、今までは緑の旗だけの開始〜がメッセージの送受信に代わることで、ゲームの中にも物語のような順番ができるのだということが知れたようで、満足していました。', '来週は基本操作コース06 でメッセージの送受信の部分を深掘りしていきたいなと思います。', 'タイピング: 初めてタイピングをしたようで、最初は時間がかかっていましたが最終的には自分で最後までできていました。
盛り上がり: 色々な知識が増えることによって、やれることが増えるとこんなゲームを作ってみたい〜などの意欲的な感じが見て取れました。'),
  ('9475578f-799f-52ba-af93-d2632f34365c', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-28', '18:40:00', null, '通常 / ビデオモーションの使用', 'ビデオモーションの使い方や、先週やっていたクローンの使い方もしっかりと扱うことができていました。教えたことはしっかりと吸収してその通りに作ることができていました。終わったあとは、また別のクローンを使った作品を検索して同じものを作っていました。本体とクローンのコードを見極めながら作っていました。', null, 'タイピング: それほど間違えることもなく順調にタイピングしていました。
盛り上がり: プログラムがしっかりと動いたときは、ゲームを楽しそうにプレイしていました。'),
  ('b044fbbe-62ce-5cab-8db9-82122952dd6f', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-28', '16:30:00', null, '通常 / ビデオモーションを使う', '今までにやっていたクローンを使い、今回新たな要素として登場したビデオモーションを使ったゲームの作成をしました。チュートリアルのビデオを見ながらやっていたので、問題なく作ることができました。ビデオモーションについての操作や内容の理解も問題なくできていると感じました。', null, '盛り上がり: お手本通りに出来上がった後に、自分のキャラクターを作って同じようなプログラムを作成して作っているときは、張り切って作っていました。'),
  ('62d61d29-cfea-59e1-91ad-1b5837fd5626', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-28', null, null, '通常 / 大会作品提出', 'まだ気になる部分もあるようでしたが、終わりの部分を作れていなかったので作成しました。時間が少ないことも伝えましたが、宝箱のデザインにかなり凝っていました。プログラムもひとつずつ丁寧に取り組めて、ひとつひとつの理解はできていましたが、全体をみるのが苦手な様子でした。地面の高さの調節をし、うまくジャンプさせることができました。自分ひとりで取り組もうとする姿勢が素晴らしいです。 やりたいことはある様子でしたが時間がなく、かといって急ぐ様子もなかったです。最後の提出フォームの入力もひとりで頑張っていました！', null, '時間帯: その他'),
  ('28355e9c-8f61-54b7-96c4-ad3068d7a81c', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-28', '17:30:00', null, '通常 / 大会の作品提出', 'のプログラムについては、スクリプトの複製を多用してしまったため、プログラムが重なりうまく動いていなかった様子でした。 さらにそれぞれの矢印キーにスコアを設定しました。スコアをつけるプログラムは理解できている様子でしたが、どこにプログラムするべきかはあまり理解できていない様子でした。最後に0秒になったとき、スコアが全て10点になったときに終わりの画面に切り替わるようにしました。最後に提出しました。', null, '盛り上がり: 来たときはあまり元気がない様子でしたが、最後は笑顔で帰ってくれました！良かったです！'),
  ('f2b55965-81c6-586e-aefb-176b11357339', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-28', '16:30:00', null, '通常 / チエテラスの続き', 'フローチャートの読み方からif文やfor文についてを学習していました。条件分岐や処理の順番など初めてやることに少し混乱していましたが、スライドを見ながら問題を解いていった結果少しずつですができるようになっていました。ゆっくり考えていけばできるようになるのではないかと感じました。', null, '盛り上がり: フローチャートを読み解いているときに、流れを読み解いているときは特に集中して取り組んでいました。'),
  ('d3879fea-db53-5f4f-bbed-fe27e7753c42', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-28', '16:30:00', null, '通常 / 自分の作品提出', '緑の丘の上に乗りたいとのことだったのでジャンプのプログラムを変えました。地面につくまで下がり続けるようなプログラムを提案しました。説明したのですが、「～まで繰り返す」の部分があまり理解できていない印象でした。エンディングがまだ完成していなかったので、幽霊の効果を使って作成していました。何通りか試していましたが最後は時間切れになり、少し悔しい様子でした。提出は全部自分で入力して提出できていました。', null, '盛り上がり: とても集中できていました！'),
  ('c9be0dfa-a820-5805-92d2-f50aabda8dad', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-28', '17:30:00', null, '通常 / ①親子大会用のビギナー部門での提出 ②物語をつくろうの登場人物がメッセージを送り合って出てくる場面を作成 （タイピングをするのは難しそうなので、何秒まつ～や背景が変化したら登場人物が変わる＞＞演算をつかってランダムに敵が出てくる）など、すこしゲームの要素を多めにしながら、何かのボタンを押して弾が発射するみたいなのを完成イメージにして', '大会の作品の話で最初は色々と話を聞いて、バグを直しながら提出することになりました。（青木提出をやりました） その後に物語を作ろうの部分で、背景が変わったりする部分や、メッセージの後にスプライトの大小を音をつけながら変えてみるというのをやってみました（ゆづきくんも同じような部分をやっていたので、ゆづきくんのをみて自分もやりたいと思ったのだと思います。）', '今まで漠然とコードを挿入していただけだったので、今度から同じコードを重ねることをもう少しやってもいいかなと思います。特に座標系に関しては、重ねて使うことや音や待つが挟まれた後にも同じように引っ張ってきて使うということをおさらいした方がいいかな', 'タイピング: なし
盛り上がり: 大会のバグを潰せたので本人はとても満足していたようでした！'),
  ('6a1380bb-a3fc-502c-b1a0-de9497a6a10f', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-28', '16:30:00', null, '通常 / プログラミングようのタイピングを長めにやって、チエテラスの１を復習', '続きの２から始めるかなと思ったのですが、本人的には１を復習したいとのことなので、１の部分で苦手だった変数以降の部分、繰り返し、演算などの部分をもう一度やっていました。 どうしてもスクラッチで苦手だった部分とつながっていて、変数という箱の中に数が入っていてそれをうまく活用するというのが、理解できないようでした。 なので、復習していても漠然とこれでいいでしょ的な感じで答えてしまっている感じです。 今後１をそのまま続けても悶々としてしまいそうなので先に進めてもよいかな・・・', '２の方にすすめてもいいかなと思います。その上でわかる部分もあるだろうし、何より先に進んでいるという感覚を掴む方がいいかなとは思います、ただ本人的には漠然と感があるのでもしもう一度復習したいと言い出したら、そっちでもいいかな', 'タイピング: 最初はコードの文字列を打つのが大変そうではありましたが、だんだんと英語と記号をまぜて打つのが速くなっていました。 少しこの文字列の意味が何を意味しているのか？をタイピングしながら学べたみたいなので、まこちゃんにとってはとてもよかったのかなと思います。
盛り上がり: タイピングの部分に関しては初めてのJava用の文字列を打つというのにチャレンジしたためか、とても楽しそうにしていました（文字を打つこと自体にはあまり抵抗がなさそうなのでよかったです）'),
  ('47c3eb41-6f4a-5618-9de0-10bc44993410', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, null, '2023-07-28', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('d706b3ba-146a-5ac8-8318-25235943f202', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-07-28', '18:40:00', null, '休み（未対象）', null, null, null),
  ('91e39848-b11d-54de-ab81-6d85b1e8b421', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-27', '16:30:00', null, '通常 / 大会準備', '情報がわかりやすいように、商品にカーソルを当てたときに値段や商品名を表示させるようにしました。野菜売り場から出たときも野菜が表示され続けるバグがありましたが、一緒に原因をつきとめると、同じ役割のコードが二重で書かれていたことがわかったので片方を消しました。買った商品の合計代金を計算できるようにすることを促しましたが、お金は十分持っている設定(9万円)だから大丈夫とのことでした。また、メニューの複数選択が可能になっているなどの不完全な点について聞いたところ、普通に遊べば問題ないので直す必要がないと言っていました。セール品のジャガイモは賞味期限が近くて芽がたくさん生えている代わりに安くするなど、面白い工夫も見られました。時間が終わるまでにりょうやくんが納得できる形で完成し、提出しました。', null, '盛り上がり: ラストスパートでしたが、リラックスした状態で製作を進めていました。'),
  ('d4c63bc5-5a10-5914-9f35-7c2c26795765', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-27', '17:30:00', null, '通常 / 同上', '同上', null, '盛り上がり: 同上'),
  ('bd128949-2bae-5882-ba85-5d7357cec39f', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-27', '16:30:00', null, '振替 / コンテスト作品の完成、提出', 'ストーリー部分は完成していて、別ファイルでゲーム部分を作成中とのこと、勇者とウイルスの闘いをどのようにするか、しもさんと話しながら決めていました。 バトルモードには制限時間をつけたいと言ってタイマーについてWeb検索をしていたので、時間もないことから、ゆきちゃんが知っている方法で作ることを提案しました。変数と1秒待つを使ってみたら、のアドバイスで自力で作成できることに気付き、作成していました。 バトルクリアやゲームオーバーのときの文字表示など、工夫してゲームっぽさをうまく出していました。', 'ストーリー部分とバトル部分のファイルの統合、見直し、提出', '盛り上がり: 昨年、よくわからないまま提出してしまったときと比べて、ゆきちゃんなりに丁寧にコードを見て納得がいくまで頑張っていました。ゲームとしては一応完成形にはなっていたのですが、本人の希望で要素を付け加えたため今日の提出には至りませんでしたが、ゴールは見えているためか、満足そうにレッスンを終えていました。'),
  ('8371b3f5-23db-56c9-b322-0cd8e010b82e', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-27', '17:30:00', null, '通常 / コンテスト作品の完成、提出', '前回でボーナスタイムのコードの続きをやっていきました。パッと無駄と思えるコードもあったので、どのようなものがボーナスタイムか聞きだして、修正してあげました。その際に、「まで待つ」や「演算式」などは、かみ砕いて教えたが、定着するには繰り返し必要だと思われる。集中力もあって、提出フォームも半分は自力でやれて、提出できました。', null, 'タイピング: あまり体力を削られずに進めていました。
盛り上がり: 夏休みは暇で暇で早く来たかったそうです。'),
  ('f9525344-9198-59b1-8c1e-ef403ee909dc', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2023-07-27', '17:30:00', null, '休み（未対象）', null, null, null),
  ('f8244187-ba7d-5aa7-9094-f2e5822293d2', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2023-07-27', '16:30:00', null, '休み（未対象）', null, null, '備考: 7/13の振替分'),
  ('6838dde5-712d-5db8-ba9d-8f4e73c0132e', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, null, '2023-07-25', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('a567af09-732e-55eb-b03a-9deca51f18be', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, null, '2023-07-25', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('1ff3745f-d426-50b0-91af-adf32ecc1011', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-20', '17:30:00', null, '通常 / 大会準備', '順調に作成を進めていました。ゲームの説明部分まで終わったようで、次回は戦闘場面に入れそうです。戦闘についても見通しが立っていて、そこまでつまづきそうなポイントもなさそうです。', null, '盛り上がり: じょうたろうくんと話して楽しみながら制作しています'),
  ('c97b75ba-cac4-5e30-9ee3-465ab2c3f66c', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-20', '17:30:00', null, '通常 / 大会準備', 'ときどき進捗を見に行きましたが、今日の作業は比較的順調に進んでいたみたいです。ゆきちゃんと横並びで話し合いながら進めていました。', null, null),
  ('85555e10-653e-5c25-9f9b-44f23f4102d4', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-20', '17:30:00', null, '通常 / 自由製作とそのための小技', '最近まさきくんはネコのスプライトを動かすゲームをよく作っているので、それに使えそうな残像の小技を勧めました。いつもこちらの提案には乗ってくれないことが多いのでダメ元でしたが、実用性を感じたからか興味をもって取り組みました。クローンには慣れていないようだったので、「スプライト本体とクローンの動きは分けてプログラムする」などの基本を教えながらやったところ、素材のみ(コメント付き)から試行錯誤を経て完成しました。 自由作品は、先週作ったイライラ棒風の迷路の第二弾を作りました。ネコの残像については当たり判定が広くなってしまうからと断念しましたが、先週と比べて、プレイヤーに緊張感を持たせるような洗練されたゲームができました。', null, '盛り上がり: 作ったゲームの難易度がかなり高いですが、どうしても先生たちにクリアしてほしそうです。'),
  ('b8d16e50-54d6-55db-8837-f7a6c9e864d4', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-20', '16:30:00', null, '通常 / ゲーム制作のためにステップアップする', '今までゲームを一通り作ってきたのですが、メッセージなどを習得してステップアップすることを目標に、物語を作りました。こたろうくんはゲーム制作のほうが好きなので、嫌にならないか少し不安でしたが、「これをやればもっと面白いゲームが作れるようになる」と動機付けしたところ興味をもってやってくれました。基本的には何をしているか納得しながら作れたと思いますが、初めて扱った「メッセージ」については理解が曖昧かもしれないので復習などで確実にしていきたいです。', null, 'タイピング: だんだんタイピングにも慣れてきたみたいです
盛り上がり: 海の生き物が会話するほのぼのした世界観でした。'),
  ('6636ac4e-900b-5916-a57b-30cdb218da3b', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-25', '17:30:00', null, '通常 / コンテスト作品の提出、座標での当たり判定', '用紙を持ってきていたので、作品に変更がないかを確認して提出作業に入りました。前半は自分でローマ表を見ながら入力していましたが、文章になると机にのびてしまったので、手伝おうかと声をかけ、文章を読ませてこちらが入力をしました。文章を読むことで声を出すことに少し抵抗がなくなったのか、その後は話しかけると基本的に返事をしてくれるようになりました。 提出後は、作ってほしいゲームがあると声をかけ、【Prg】25 野球ゲームを作ろうをプレイした後で、なぜこの教材をするのか説明したところ、素直に聞いて「やってみる」と言ってくれました。 注意してほしいコードを説明語、見本をプリントアウトして写経させましたが、かなり熱心に時間すぎまで頑張っていました。', '【Prg】25 野球ゲームを作ろうのピッチャーのコード続き', '盛り上がり: スキルアップのために新しいゲームを作る、ということが嬉しかったのか、いつもより姿勢がだらけることもなく、頑張って取り組んでいました。今日やったことをお迎えのお父さんに説明しているときも、わきでちょっと嬉しそうに話を聞いていました。'),
  ('7bd2ae92-7294-52c0-84d4-04dc0cade8e5', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-25', '16:30:00', null, '通常 / コンテスト提出', '大会の提出をしました。事前に詳しく紙に書いてくれたので、スムーズに提出を進めることができました。プログラム名や氏名などは自分で入力してもらいました。マインクラフトの影響でタイプできる文字や知っている感じが増えているようです。 後半はあるくんの冒険1(レッスン)を進めました。ジャンプのプログラムは知っているとのことでしたが、様々な方法があることを復習していもらいました。レッスンを始める前に自分のできるジャンプを説明してもらいましたが、角度、動きについてはしっかり把握することができていました。', null, null),
  ('2d7ef0cc-534a-5f09-8566-7beea80ee2ef', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-25', '17:30:00', null, '通常 / キャッチゲームに挑戦', 'ボールをいろいろな位置に移動させて配置させることが難しかったようです。x座標、y座標の向きはしっかり把握できていましたが、それを画面上に落としこんでイメージすることが難しいようです。リンゴを落としたり、かごを動かしたりするプログラムは自分でしっかり組み立てることができていました。スコアの設定もできていましたが、一度に何点も入ってしまう原因に関してはこちらから詳しく説明しました。勝利の画面を表示するときに「まで待つ」のブロックではなく、「もしなら」をどうしても使いたい傾向があるようです。 動きや角度など基本的な操作は定着してきた様子ですが、まだ制御の部分は苦手な様子です。', null, 'タイピング: 集中して取り組めていました！'),
  ('81ee4666-267c-597a-9b5c-6c3f69c6d3c9', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-25', null, null, '通常 / チエテラス・Scratch', 'チエテラスでは10進数の計算に取り組んでいました。正解率までは確認できませんでしたが、順調に手を動かして計算できていたので素晴らしかったです。Scratchでは電車のゲームの作成に取り組んでいる様子でした。標識板（?）のデザインにこだわって丁寧に取り組めていました。コメント機能も使ってしっかりプログラムできている印象です。', null, '時間帯: その他'),
  ('3c7ea8b3-416e-5275-82ed-7cb1a0bceb56', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-25', '17:30:00', null, '振替 / 大会提出', '今日中に大会提出はできませんでした。説明画面の背景になっているときの音楽を流すタイミング、速度に苦心していました。前回録音したものを参考に、時間を調節していました。また、別のスクリプトではもし～ならとずっとを併用していたのでずっと音楽が鳴るようになってしました。「まで待つ」を使うことを提案しました。 時間中に提出は出来ませんでしたが、完成させることはできました。来週、提出予定です。提出用紙を家に忘れてしまったようなので、来週は必ず持ってくるように伝えました。', '大会提出', null),
  ('dc5d096a-5683-52a1-ac72-737ea1782e64', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2023-07-25', '17:30:00', null, '振替 / コンテスト作品の完成、提出', '録音してきた音声などを一生懸命編集してとりこんでいました。 エンディングで追加のアイディアがたくさん思いついたようで、19時近くまで熱心に編集していました。 Scratchで見つけたという、テキスト掲示板？表示板？の代わりに変数表示を使う方法をやりたがり、一緒に作成しました。 メッセージを受け取った時のコードが1つの動作しか書けないと焦りから思い込んだのか、少し混乱が見られました。どのコードも順次処理をしているため、実行したいタイミングの箇所にブロックを入れていけばいいことを整理して話しました。', '仕上げと提出の予定', '盛り上がり: 全体としては満足のいく方向に仕上がってきているようで、あと少し、あとここだけ、と最後まで良いものにしようという集中力が見られました。'),
  ('265bd52f-a596-5fd9-999c-06024ecf8143', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-25', '16:30:00', null, '通常 / コンテスト作品の完成、提出 最後の敵の確認とエンディング作成', '意図しない所でスプライトが表示されてしまうバグに大幅に時間をとられていました。 結局メッセージの送信タイミングの間違いが見つからず、受信のタイミングで背景ナンバーによる条件分岐を入れて強引に解決しました。 30分ほどオーバーして頑張っていましたが、バグを探すのに丁寧に見直していると他のアイディアや修正点が見えてきたりして、続きは家で見てくることになりました。', 'バグ探しは家で対応してきて、どうしても解決できない場合は事前にLINEを入れておいてもらうことになっています。 8/1に提出をすることを、本人、お母さんも承知済みです。', '盛り上がり: 作品内では得点やタイミングなど、かなり細かくこだわりを持って設定しているようで、ここまで頑張ったのだから悔いのないように提出したい！という意志を強く感じました。'),
  ('0cb58006-e05a-5b62-afd8-981625d2ce17', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-25', '17:30:00', null, '通常', 'フローチャートやプログラミングについての問題をやっていましたが、特に拒否するような素振りもなく基本的には、問題に載っている説明のスライドを見ながら順調に解答して行くことができていました。初めての単元だったので、基本的なことは教えながらやっていきましたが素直に飲み込んでやっていたので、正答率も高く安定していました。', null, '盛り上がり: フローチャートの考え方を理解するのに身近なものをもとに出題されていたので、共感を示しながら回答していました。'),
  ('537f2267-8d9d-5aae-be0a-e830a7de18fb', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-25', '17:30:00', null, '通常 / コンテスト作品の提出', 'ほとんど完成していたので、作品提出の入力でIDと説明を書いていました。独創性を加えたIDと説明を考えていて、ゲームの内容をわかりやすく簡潔に書きつつそこに工夫を加えながら入力をしていました。', null, '盛り上がり: 自分で説明を考えている際は、どのようにして書けばいいのか苦戦していましたが、楽しそうに行っていました。'),
  ('48ab5fee-e680-54b2-adf2-4e8658799fdb', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-25', '16:30:00', null, '通常 / コンテスト提出作品の完成', 'ステージ４に残っていたバグを潰し、新たにステージ５とクリアした際の画面を追加し、フォーム入力から提出まですることができました。２時間ずっと制作をしていたのでかなり疲れた様子でした。集中して取り組むことができていたので、うまく作れていました。', null, '盛り上がり: 新しいステージを作っている時は、アイディアがどんどん湧いてきていたので時間内に作るのが大変でした。'),
  ('be4e3e39-45f1-5461-8934-234d560e6360', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-24', '17:30:00', null, '振替 / 検定２級の応用問題１１', '今日は久しぶりにやったと言っていたので、検定の問題の読み方に若干慣れてない感じではありましたが、一緒に読み込むことで思い出した感じではありました。 バグの修正の部分が本人は難しいと話していましたが極論コードを組む部分がちゃんとできれば大丈夫だよと伝えておき自信を持たせる作戦にしてみました。', null, 'タイピング: なし
盛り上がり: 色々と思い出すことが多かったようでしたが、理解できるとすぐ思い出してスラスラと書くことができていました！'),
  ('70b07db6-97d6-557e-8333-2ef8b1979f83', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-24', '16:30:00', null, '通常 / 自分の作品作成', 'クローンの動作がわからないという話をしていたので、もう一度親子の関係性を思い出してもらいながら、ゴミがあたったら海亀の体力が減るというゲームを作成していました。 おそらく、このゲームで提出ということになると思うのですが、ラストにうみがめの説明を持ってきたい様子なので、その部分をどのようにつなげるか？が次回の問題点かなぁと思います。', '来週提出なので出来た部分で提出でよいかなと思います。', 'タイピング: なし
盛り上がり: ゲームの部分で色々考えていることがあるようです。'),
  ('56f1d5fa-aaf0-5b33-939c-314a2c19c148', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-24', '16:30:00', null, '振替 / 自分の作品作成＞剣を飛ばす', '提出のためのプリントは持ってきてもらいましたが、やりたいことも一緒に書いているため（まだコードを書いてない部分）今日は、その書いていない部分を重点的にさくせいしました。 覚えきれているところや、あぁそうだったなという部分があり、見守る必要があるなと思います。次回今週土曜日に提出とのことで、LINEでお母さんからメアドと電話番号のお知らせ待ちです。', null, 'タイピング: なし
盛り上がり: ゲームを作るのはとても楽しそうにしていました。本人は自分が思っていることをキチンとできることに満足していたようでした。'),
  ('0a9a300a-390a-5f00-b686-0241f43d4e8e', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'e46e603c-1913-57f7-95eb-d30ec9d2bf3a', '2023-07-24', '16:30:00', null, '通常 / 提出作品の作成続き', '提出作品の作成続き。 第３ラウンドの相手（サメ）を倒すと、第４ラウンド開始（夜景になりコウモリが相手）までは実装。 相手のHPがマイナスになる件については、手つかず（「へーげる」は、HP１未満（０）でダメージを受けるスクリプトは止めているのに、 「スラボー」と「サメ」はダメージを受けるスクリプトが止まっていないため）。 第４ラウンドに関しては、コウモリが表示されてすぐ非表示になってしまう状態 （第４ラウンドの初期化で、「相手のHP」を１７にするべきところを、「（自分の）HP」を１７にしているため）。 また、コウモリの攻撃（「コウモリ２」に触れたときのダメージ）が未実装。 明日（２５日）に、次の敵（第５ラウンド）まで作成して、提出予定です。', null, 'タイピング: ─'),
  ('43506d6a-6d50-5695-ba11-0111b2d9d2d8', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'e46e603c-1913-57f7-95eb-d30ec9d2bf3a', '2023-07-20', '16:30:00', null, '通常 / コンテスト作品（買い物ゲーム）の続き作成。', 'コンテスト作品（買い物ゲーム）の続き作成。 リストの照合を実装。買い物リストにある要素がすべてカートに入っていたら正解、そうでなければ不正解とし、 その結果に基づき、クリア・ゲームオーバーの画面に遷移するように実装。 一通り、ゲーム終了までは動く状態になりました。 お金の計算は手つかず。また、買ったものリストからの削除も不可能のままです。 現状では、余計なものが入っていてもクリアになるのと、メニューを複数選択したり、逆に一つも選ばなくても開始可能になっています……。', null, 'タイピング: ─
盛り上がり: △竹花個人的なところ： メニューの複数選択や、余計なものがある場合にＯＫかＮＧか、などといった、細かいところをどうしたいかを聞ききれず…。 時間の制限もあり、それらについてどこまでやるかの規模感も掴めませんでした。'),
  ('75545876-b25a-5b63-ae91-ed4d5a5c9de8', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'e46e603c-1913-57f7-95eb-d30ec9d2bf3a', '2023-07-18', '17:30:00', null, '通常', '〇チエテラス チャプター２－４まで実施。 わきで見ている感じ、特に苦労しているようには見えませんでした。 〇アルスパーク 京王線のドア開閉シミュレータの作成を開始していました。雰囲気がよく出ていると思います 「開」を連続で押すと、ドアの開く速度が変わるようですが、おそらくバグ？ （まだ作ったばかりなのでそこまで手が回っていないだけにも思いますが）', '△竹花個人的なところ： チエテラスについて、今日やったチャプターやそのちょっと先あたりには、 中学1年生ではまだやっていない数学の内容があったはず…。こういうところはフォローしたい。 （アルスパークも含めて）もう少しコミュニケーションをとりたい…。', 'タイピング: ─'),
  ('983b4726-8482-54ff-a761-d359c549161a', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-22', null, null, '通常 / チエテラスを進める', 'だいきくんのお父さんとも話し合って決まったことですが、1時間ずっとチエテラスをやるのは疲れるので、40分はチエテラスを頑張って残りはロブロックスで遊んでもらいました。 英単語を使う必要があるので覚えるまでに少し時間はかかりそうですが、「スクラッチでいうとこれのこと」というのを時々伝えると納得できた様子でした。大体の内容は理解したと思いますが、たまにわからない内容の問題を適当にやって終わらせることがあったので、復習しておきたいです。', 'チエテラスは復習から始める(間違えた問題が多い単元を重点的に)', '時間帯: その他
盛り上がり: チエテラスに気乗りしない時間帯もありましたが、嫌というわけではないと思います。'),
  ('e9a57396-0d8a-5ff4-bf6c-2eb526ef912b', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-22', null, null, '通常 / コンテスト作品アピールポイント探し', '最初は虹色ピンポンは完成していたので、アピールポイントは書き出していきました。その質問を最初聞き返したら、終わらない所と1文しか出てこなかったので、既存の作品の違うポイント、（背景やコードなど）を理由を聞いて、こだわったところが見つかりました。そのごは、アルスパーク内になるゲームを遊んで、気になったところやうまくいかない所を少しだけアレンジしていきました、そこで、このゲーム直そうとしてコードを開いてみたが、「やっぱいいや」急転換してしまうことは、コードの難しさもあるが、気持ちの波が激しいです。', null, '時間帯: その他
盛り上がり: アピールポイントを考えていた時も元気よく多動していました。'),
  ('bf6b1d45-8475-5a4c-8b91-e26650e92baf', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'd9c6b046-22a6-5c9a-9d2f-cf9d98dfc23c', '2023-07-22', '17:30:00', null, '通常 / 大会作品の制作', 'エンドロールを作るということで、パワーポイントで画面を作成していました。 完成してScratchに取り込み、クリアボタンを押すと画面が出るようにしていました。 最初から、クリアボタンが出てしまっているので、クリアしてからボタンが出たほうがいいのでは？と聞いてみたら、全部クリアしたことを判定するプログラムを作るのが面倒くさかったのか、雑巾でふいた後にボタンが出てくるようにしていました。', 'もう少し作りたい部分があるということで、次回作品提出予定。', 'タイピング: なし
盛り上がり: 自由にやってもらっているので終始楽しそうではありました。 学校の先生にも作品のアドバイスをもらっている模様。
備考: 技術的に抜けている部分が多いので、大会が終わったら基礎の基礎から順番にやった方がいいと思います。'),
  ('c438458b-349c-5e3d-9d55-83ebb3df190f', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-22', null, null, '通常 / コンテスト作品を提出', '前回提出フォームの紙を渡したので、今日はその打ち込みをやりました。アピールポイントが１つと物足りなかったので、ゲームに触れながら、先生と一緒に良いポイントを探して、こちらで文章を修正して、あとは提出させました。最初は提出の準備をする前は一向にゲームを止めなかったのは気にかかりました。', null, '時間帯: その他
盛り上がり: 提出の打ち込みで疲れた解放感でそのあとのゲームは楽しくやっていました。'),
  ('5e6f17a1-bcde-5044-be3b-89a49edfa099', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'd9c6b046-22a6-5c9a-9d2f-cf9d98dfc23c', '2023-07-22', '16:30:00', null, '通常 / 大会作品作製', '最初から課題がわかっていたので、課題クリアに挑戦。 エレベーターと地面すり抜けてしまうバグの解決に挑戦して、見事解決していました。', '上から出ている地面に触れた時に、上に動いてしまう問題を解決して応募予定。 ※上から出ている地面を撤去するか、色を変えるかで対応しようとしている。', 'タイピング: なし
盛り上がり: 最初に自分で言っていた課題をクリアした後も、自分で問題点を見つけて積極的に取り組んでいました。 解決できると嬉しそうにしていました。'),
  ('1caa8ef5-8619-552b-99bf-c11443aec956', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-22', null, null, '通常 / コンテスト作品作り', '今日は集中力の波がありました。作るぞと気持ちが高ぶって集中してやっていましたが、ちょっと詰まったり、バグが発生したりしたら、集中切れて寿司打に逃げてしまう方向がありました。やりたいことはあるけど、コードをうまく表現できなくてだれてしまうことがありました。作品提出は、本人的にはもういいやの気分でいしたが、お母さん的には、内容の出来よりかは物事をやりきるという提出事実を大切にしたいそうです。そのことをあおしくん自身に伝えたら、頑張るそうなので、来週に仕上げたいと思います。', null, '時間帯: その他
タイピング: 伊藤さんと勝負してました
盛り上がり: そうたくんによってやる気を伸ばせていました。'),
  ('ecd71363-cdca-526d-9dc1-8ece7171cafc', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-22', null, null, '通常 / 検定練習', '一通り解き切るまでは比較的短時間で終わったのですが、一部わからないところがあって詰まってしまったとのことだったので、そこで打ち切って答え合わせをしました。 まずブロックを一つ入れ忘れるケアレスミスがあったので、本番では一度完成したら見直すことを勧めました。また、意味がわかりづらい問題文を変に解釈してしまったところがあったので、問題文をしっかり文字通りに読むことの重要さを共有しました。最後に、今回の問題のポイントだった 「ではない」かつ「ではない」まで待つ について確認したところ、以前の2級の練習問題でも同じようなものが出てきて覚えているとのことだったので大丈夫そうです。', null, '時間帯: その他
盛り上がり: ミスしたところについても冷静に考えていて、直せたときはほっとしていました。'),
  ('d5cfad43-620a-538d-a6a7-7d16021d2ee8', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'd9c6b046-22a6-5c9a-9d2f-cf9d98dfc23c', '2023-07-22', '16:30:00', null, '通常 / 大会作品制作', 'やりたいことを教えてくれたので、一緒に考えながら一つずつ要素を加えていった。 「家に入る」「家から出るボタンを作る」の部分を作りました。', '次回は残りのやりたいことを、完成させて応募予定。 地面のコスチュームを変えられるようにしたいみたいです。', 'タイピング: なし
盛り上がり: 思っていたことができたようで嬉しそうでした。'),
  ('52c9adab-4ca6-53ca-8cea-28fdf4bd02da', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-21', '17:30:00', null, '通常 / スクラッチの基本要素を覚えよう', '今まで作っていったものはランダムで動いて物が多かったから、自分が動かしたい方向へ動かすことを重点に置きながら進めました。画面の上下左右の対応にx、y座標の感覚が薄かったので、ゆっくり説明しながら作りました。各動きのコスチューム変化をつけるのを指示したところ、棒人間が落下する動きをアレンジしました。そこからビルのスプライトを自分で持ってきて、そこから落ちている風にして、ホラー好きな傾向が見られます。その流れ、音の選び方も教えました。フリーにアレンジし始めたところから楽しんでいたので良かったです。', null, 'タイピング: 3連続の打つスピードは速いです
盛り上がり: はるくんとホラーゲームなぞ解きを一緒にしてました。'),
  ('26f65476-32e1-5f93-8207-7b8a6d6a3438', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-21', '18:40:00', null, '通常 / コンテスト作品の提出準備 用紙の記入が済んでいるようであれば、作品を見直してから提出。', '前回作成したキャッチゲームの完成が嬉しかったのか、最初に開いてプレイを見せてくれました。 コンテストの用紙を持参していなかったので、クローンの使い方に慣れていくという目的を説明して【Prg】28 まゆネコをさがせをプレイし、プリントアウトした完成コードを見ながら写経してもらいました。 しっかりとコードを読みながらうつせていたようで、「１そうおくにさげる」ブロックを「これは初めて使うけど、どういう意味？」と自分から質問にきてくれました。 まゆねこのコスチュームを変えて、2種類のゲームを作ることができました。 途中でお母さんが応募用紙を書くためにゲームを見に来たのですが、まゆねこを作っている最中だったせいか、お母さんに説明するのが少し面倒そうでした…。', 'まゆねこは完成したので、次の課題に進んでください', '盛り上がり: 鼻の調子が悪かったようで、頻繁に鼻をかみながらも、最後まで頑張って新作に取り組めていました。'),
  ('63ce2ec3-6547-5c97-b600-c4caa0d2085b', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-21', '16:30:00', null, '通常 / コンテスト作品の提出準備 用紙の記入が済んでいるようであれば、作品を見直してから提出。 時間があまったら、小技のどれか（残像とか）、または次回以降も続ける前提で、prgのどれか', '家でしっかりと応募用紙を書いてきてくれたので、スラスラと入力してエントリーしていました。 30分もかからずにエントリーが終わってしまったので、prgのゲームをいくつか見てもらって好きなゲームを選んでもらい、【PRG 31】ふうせん&こうもり割りゲームのアレンジに取り組んでいました。 最初にコードを見て、これなら大体わかるといって、ふうせんを増やしたり動かしたりするゲームに書きかえていました。その過程で紙のテキストを見ながらScratchの座標範囲の復習をしました。 風船が下から大量に飛んでくる華やかなアレンジができていましたが、その後はどこかのコードに干渉したのか動きが悪くなったと言って、「今日はここまで」と終了していました。', '小技系は結構やった、とのことなので、prgのゲームをやってスキルを磨いていこう、と予告してあります。', '盛り上がり: タイピングが早いので、エントリーもスムーズに進んで少し得意そうにしていました。次回のタイピングコンテストにも「挑戦するよ！」と前向きでした。 エントリーが終わってすっきりしたようでした。
備考: 中学受験をするので歴史を覚えているんだと話してくれました。'),
  ('73dc1aa7-c733-5c12-805a-01d00b034215', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-21', '17:30:00', null, '通常 / 検定練習', '3級の検定問題を練習しました。終わった後、ボールが動かないバグが残っていました。一緒に確認していったところ、やはり、不等号の向きが逆なっていました。そのミスに後から確認していくうえで自ら発見できたことはよっかったです。ほかは、コードが条件の中に入ってないことなどの順序がずれていることが少し見つかりました。それ以外の演算や条件は問題なく組めていたので、不等号とコードの順番を気を付けてもらいたいです', null, '盛り上がり: ゆずきとホラーゲームのなぞ解きをしてきて盛り上がっていました。'),
  ('3a518866-68bb-51ee-8b00-b8e3b4c53981', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, null, '2023-07-21', '18:40:00', null, '休み（振替対象）', null, null, null),
  ('72cf3e09-a0bd-5010-836e-c3fe377226e3', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-07-21', '18:40:00', null, '休み（未対象）', null, null, null),
  ('948f073c-4c81-54e1-9dbf-27e261a2f23f', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, null, '2023-07-21', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('1735f424-b1b4-56a8-8e91-47504f747a11', '13bd73d0-f535-5291-8362-6712e5cd7384', null, null, '2023-07-21', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('08308855-c765-5282-a9ea-de834d30766a', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-07-21', '16:30:00', null, '休み（未対象）', null, null, null),
  ('0a3a9bd8-afd3-55f5-a796-2767a112e7b9', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-21', '16:30:00', null, '通常 / コンテスト作品作り', '今回は、雪のステージでの戦いを作っていきました。爆弾による敵の攻撃がフグのステージと同様にあったのですが、なぜか上でたまってしまうバグがありました。これは、端に触れるまで繰り返すの中に「端に触れたら」の条件が入っていてクローンの削除ができてなかったことが原因でした。この二重条件の間違いは検定でよく見たので、共有しておきました。そっして、バトル中に体の大きさを変化させたり、新たな技を加えてゲーム性がさらに向上してました。授業が終わった後、残りの進捗を聞いてみたところ、もう1体敵を増やして最後EDを作るそうです。自宅でも作れるがペース配分をしっかり決めてから作ってほしいと伝えました。', null, '盛り上がり: 新しい技でいい演出が光っていました。'),
  ('4de37f16-d8f9-5fb8-9f09-1d9412c06cc6', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-21', '16:30:00', null, '通常 / 作品提出', '八王子プログラミング大会への作品提出をしました。作品紹介や操作説明などの多くの文章を打ち込む場面でも、優れたタイピング能力で授業時間の半分ほどで打ち込みが完了していました。打ち込んでいた内容に関しても、詳しく書かれておりかなり読みやすい内容になっていました。', null, 'タイピング: なし
盛り上がり: 提出時に付けるIDを考えるのに、長く考え込んでいました。自分の作品に対してこだわりを持っているようで、IDを決めるときも妥協をせずに真剣に決めていました。'),
  ('4bc23bb8-4d42-52cc-a8c7-e6e85404ae55', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-20', '17:30:00', null, '通常 / 大会準備', 'ステージ3の作成に取り組みました。家で構成などを考えてきたそうで、ラスボスがいるステージ4までを最終的に完成させたいそうです。もう一回振替分があるので時間も足りそうです。最初は敵が表示されないというバグがありましたが、敵の体力を初期化するタイミングが遅すぎたことによるものだと分かりました。そのほかにもいくつかバグを発見しては直していました。最後は、計画通りステージ3の作成が終わりました。', null, '盛り上がり: ステージ3が完成したときは達成感があったようでした。'),
  ('83108f09-3a7e-573c-8ee8-c6e8ad9fb8e1', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-13', '17:30:00', null, '通常 / 虹色ピンポンのアレンジ', 'ボーナスタイムの内容について思考・制作をしていきました。一定のスコアに到達した際にボーナスタイムに突入し、10秒間獲得スコアが変化するというコードを作成していました。やりたいことが明確になっていたので順調に制作できていました。', '虹色ピンポンアレンジの完成', 'タイピング: 無料でできる範囲は全てクリアしていました。
盛り上がり: ボーナスタイムの内容を考えているときは様々な案を出していて、とても楽しそうに取り組んでいました。'),
  ('b6ed4930-6192-5a77-9ef6-3210f4ee5de6', '57f45872-1f3e-5540-b676-bf9023444e39', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-07-13', '16:30:00', null, '通常 / 基本操作コース６_物語を作ろう', 'メッセージを表示するという目標を達成して完成させていました。基本操作は理解してできていたので、次のステップは進んでも大丈夫だと思います。一度集中してしまえば、完成まではスムーズにいきました。', null, 'タイピング: なし
盛り上がり: 集中し始めてからはかなり楽しそうに制作していました。'),
  ('50f87b60-023d-5a95-9ad6-48841358f915', '7d01236e-620e-5177-a6f4-af325a582aae', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-18', '17:30:00', null, '通常 / 作品をもう一度見直し&ドラゴンが当たる判定の部分を作成', 'メッセージの送り合いが複雑なので一度見直ししてもらい、どれがどれと対応しているのかを確認しました。メッセージ名に関しては一旦自分が作成した名前のままで行い、最終的にはドラゴンを倒すという部分までは作成しました（０点になったら止まるというコードに） 少し目を離すと手が空いてしまう感じなので、ちょいちょい話し合う時間を設けてなるべく、どうしてだっけ？という感覚を身につけてあげた方がいいのかなと思いました。', '最終的な作品が完成している感じではないので、もう一度提出があるかも。 エントリーの名前などはファイルに挟んでいるので再提出する場合はその名前でお願いします！', 'タイピング: プラチナ級を獲得してご満悦でした！
盛り上がり: 作品を提出しました！結構本人的には今ので満足だった様子です。'),
  ('8585b360-bd93-56f3-b0a9-d1daeeb11d5d', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-18', '17:30:00', null, '通常 / 現状とても良くできているので、このままラストまで進んでもらえたら ①自動で動く車が勝った後の動きで、１PもゴールしたらWinの表示になる ②終了の時の背景がずれているのを修正', '①と②に関しては色々と試行錯誤を一緒にしながら編集しました。最終的には自分が思い描いたようにできたようなので、最後の10分ほどは一緒にゲームの説明やアピール部分を書いて終わりました。', '来週は提出です。E-mailアドレスだけお母さんにきいて、他の部分に関しても書いてきてねと伝えてあるので、来週はそれを入力するところから、かなと思います', 'タイピング: なし
盛り上がり: 自分からバグがあることを理解していたり、このゲームをヒントにしてみたら？と話した時に、「いやこれじゃな〜」と自分のゲームとのすり合わせができるかどうか？を理解できているようでした。'),
  ('81b44f84-6fa0-5890-9ff4-56909b4b7e2d', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'ffddc12c-2b0e-53f2-9581-885dafe01d35', '2023-07-14', '16:30:00', null, '通常 / 作品つくり、バグの修正', 'エントリーに向けた作品作りの続き。おうちでもプログラミングをしていたようで、「泳ぐ」の動きが、ちゃんと呼び出されるようになるなど、いくつかバグを修正していたようでした。 今日の授業でも、ストーリーや敵などの追加はせず、バグの修正がメインでした。 個人的に、メッセージや画面の遷移についてあまり理解できず、適切なアドバイスができず残念でした。 ただ、実際としてメッセージが多い点がバグにつながっている（修正が大変になっている）ようにも感じられました（メッセージの名前をちゃんとわかりやすくつけているのは好印象）。 世界観や基本的な動きはよくできている（作りたいものについてもしっかりしている）と思うので、もし次回担当することになれば、（要素の追加をお勧めするより） メッセージや画面遷移を理解して、（場合によっては紙に書きつつ）バグ修正のアドバイスができればいいと思いました。 最後に、作品のエントリー用のプリントを渡しました。', null, 'タイピング: ─'),
  ('1326bf4c-093a-56ce-ad3d-5d4583d5ee7c', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-07-14', '16:30:00', null, '通常 / 自分の作品作成（色々なバグがあるのでもう一度確認しながら、出てくるタイミングやキーの確認などをきちんとしよう！）', '色々と確認することがある感じだったので、ここはどうかな？と質問しながら作成してもらいました。ジャンプや攻撃などは自分で考えているものがあるようで、それを一生懸命達成しようと集中して行っていました。', '次回は提出の流れまでをやっておきたいので、今できている部分までで提出でもいいかな？と思います。', 'タイピング: なし
盛り上がり: 大人がこれってどうなのかな？の質問をした時、きちんと自分で答えられていたのがとても良かったと思います。'),
  ('688a1eb4-b1ac-5eee-acc7-33cfbf7c06f7', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-14', '18:40:00', null, '通常 / キャッチゲームはやってるが、基本操作コース10をおさらいでやってもいいのかな？問題形式で出してどこまでできるか？を確認', '１つ約束としてどのゲームが面白かったか？を見つけてもらって、どうしてそう感じたのか？など説明してねと伝え、「おさるのRPG」をあげていました。', 'キャッチゲームの難しいもの〜か、ゼルダのようなPRGゲームをやれたらいいのかな？', 'タイピング: 簡単のもので練習していました！今日はちょっと最初から眠たいモードが発動していたので、タイピングも乗り気ではなかったようです
盛り上がり: おさるのRPGはちゃんと会話をしてくれる部分が気に入った様子でした。 将来的には、そういったゲームが作れるようになろうね？と勧めました。'),
  ('50513110-4b14-5617-9e9e-08f033483770', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-14', '16:30:00', null, '通常 / 自分の作品作成', 'ジャンプして最後にアイテムを取りに行くというゲームに変更、ジャンプが地面で触れたら浮いているという状態にしたかったのですが、演算の部分がうまくいかずそこで立ち止まってしまった状態になっていました。 ひとまず、ゴールでアイテムを獲得したらの部分を作ってもらってで最後は案内して、本人の思うきりがいい部分まで作品作成してもらいました。', '地面にふれる判定の部分。 ドカンに乗った後の動きがどうしても止まってしまうので、そこを先生たちはみてあげてください。', 'タイピング: なし
盛り上がり: バグなど自分がやりたいことと、今のソースコードがうまく噛み合ってない箇所を理解できていたのはとても良かったです！'),
  ('8f4a377e-4c5c-5668-bb6c-76477e736b79', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-18', '16:30:00', null, '通常 / キャッチゲームの後にたべものが点数ごとにでてくるものが変わるのはどてもGOOD エンディングだけではなくて、それぞれの得点に音をつけてもいいかも？ また飢餓の説明ももしかするともう少し長めに表示しながら、自分が朗読している声を録音してもいいのかも？', '今日は、飢餓の説明の部分を録音したのと、スコアによって音を変えるという部分にとても夢中になってやっていました。 ほぼ作品としては出来上がったので、来週足りない部分を埋めれば大丈夫かと思います。', '今回の作品は音とスコアの部分も頑張って、以前よりも作品として完成度は高くなったかなと思います。来週提出なので、いい部分を書いてもらえたらと思います', 'タイピング: 昔よりもタイピングミスが少なくなっているものの、何かに気を取られる時間があるためかなかなかスコアは上がらない様子です。
盛り上がり: 録音にとても手間取ってはいましたがとても良い経験になったかな！と思います。'),
  ('4307b368-74ca-5be4-a341-ef9e4f54555c', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-13', '17:30:00', null, '振替 / 大会準備', '弱すぎる敵をもう少し強くしないか聞いたところ、最初の敵だからむしろこれくらいがいいとのことでした。その後はやはり「もうゲームは完成した」と言い張ったのですが、話し合ってみるとアイデアが出てきて、敵の分身を作って動かすという面白い仕掛けが作れました。今度こそ完成と言ってもよさそうになったので、エントリーシートを渡し、親御さんと一緒に書いてもらうように言いました。 最後は、まさきくんとお互いに今日作ったゲームを遊びあいました。二人とも楽しくて盛り上がっていました。', null, '盛り上がり: スクラッチでも、自分の作っているものに似ているRPGゲームを遊んでいました。'),
  ('81960c79-537b-5759-ab18-d80299819bbc', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-07-15', null, null, '通常 / コンテスト作品の作成続き テストプレイをしてバグつぶし等 または prg野球ゲームか水泳ゲームでスキルアップ', 'コンテスト作品は、見ようとすると隠す傾向もありますが、見せたい部分、自慢したい部分もあるようで、そういうときは席をたって呼びに来るなど積極的な態度が見られました。 ゲームはほぼ完成とのことなのですが、部屋を片付けた後、唐突に終了はもったいないと話したら、そのあとのエンディングを作成すると言って設計図をPowerPointで作成していました。説明やエンディングは、別アプリで作成して家でScratchに取り込んでくるそうです。 残り15分でやることがなくなったと言い始めたため、「スキルアップ」を提案したところ、やってみるとのことでprgに入りました。 コードを見せて、（はるくんには難しいレベルですが）変数を使ったスピードや大きさの変化などのスキル獲得を目指すことを説明し、動画を見ながら作成に入りました。 授業時間が終了してお迎えの電話が鳴るまで、熱心に取り組んでいました。', '【Prg】25 野球ゲームを作ろう 動画7:45～', '時間帯: その他
盛り上がり: 今日は人も少なかったせいか、こちらにもよく声をかけてきながら、それなりに楽しそうにできていました。'),
  ('7bed628f-6bec-572f-b0b3-fdc83dc6e50b', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-15', null, null, '通常 / コンテスト作品の作成続き 壁ジャンプの作成 変数の追加等があるので、少し丁寧に。サンプルは大原作成済み。', '前回からの続きで、エンディング画面のヘーゲルやスラボーの動きを楽しそうに作成していました。 エンディング画面が一通りできたところで壁ジャンプのサンプルコードを見せましたが、新しく作成する必要があるコード数に少しおじけづいたようで、他のアイディアを考え始め、上に上昇するエレベーターを作ることにしました。プラットフォーマーにはなかなかない斬新なアイディアなので、そこで盛り上がったら嬉しそうにしていました。', '上昇エレベーター作成', '時間帯: その他
盛り上がり: 授業にもだいぶ慣れてくれたのか、雑談しながらエンディングを作るのをとても楽しんでくれていました。 残り回数を考えて自分で仕様を考え直すことができたのもよかったです。'),
  ('1ac65a7e-e8ab-5ee0-bea0-b24fd670e30a', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-15', null, null, '通常 / 大会作品アレンジ', '1度作った作品が消えてしまったようなのでリミックスしてアレンジしました。 「スプライトを増やしたい」とのことだったので、アレンジの種類としていくつか提案すると、「新しいスプライトを追加したい」とのことだったので、ボールのプログラムを見ながら新しくスプライトを追加しました。大きさや速さもよく考えて取り組めていました。既存のプログラムに対していくつか質問するとしっかり答えることができていました。 来週はゴールの点数、勝ちの画面を作ってプログラムの終わりを作る予定です。', 'ゴールの点数、勝ちの画面を作ってプログラムの終わりを作る予定です。', '時間帯: その他
タイピング: 根気強く取り組めていました！すごい！！
盛り上がり: ほぼ1時間集中して取り組むことができていました。'),
  ('6ae941ed-1b7c-584b-a271-7e1e11a0bc01', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-07-15', null, null, '通常 / 大会作品', '地面の挙動を修正したり、スプライトの見た目を変更したりしました。ジャンプの仕方も忘れてしまっていたようなので、座標の復習もしつつ振り返りをしました。メッセージを送るタイミングを整理し、地面を掘り始めのタイミングを変更しました。細かいプログラムは忘れてしまっているところがありましたが、プログラム全体をよく見て、メッセージもしっかり使いこなせている印象です。スプライトの見た目の変更も良くできていました。 やりたいことはあるようですが、時間が足りるかが少し心配です。自分が持っているものを表示させたいようです。プログラムはほぼ自分の中で完成しているものの、つくる時間が足りなそうです。', null, '時間帯: その他
盛り上がり: しっかり集中して取り組めました！'),
  ('1c0888ad-423e-5bf0-9df2-88f902672f3e', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-15', null, null, '通常 / 検定練習', '時間に余裕を持って最後まで終わりました。問題文と照らし合わせて答え合わせをすると、全部正解していました。演算ブロックを複雑に組み合わせるのを何回もやらないといけなかったのですが、特に混乱はしなかったようです。2級の練習をするまで知らなかったという「聞いて待つ」ブロックも使いこなせていました。', null, '時間帯: その他
盛り上がり: 淡々と進めていましたが、楽しんではいるようです。'),
  ('d4a242a1-72e9-5007-bd87-0bf0fefe193d', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-15', null, null, '通常 / スクラッチとは違う形式のプログラミングに慣れる', '最初はコードモンキーをやりました。繰り返しのコードを書くとき、繰り返しの対象を間違えたことで想定通りの動きをしないというバグが起こりました。そこで、どこからどこまで繰り返すかという範囲を決めるのはスクラッチでもコードモンキーでも同様に大事だということを確認しました。 後半はチエテラスを初めてやりました。「if文」=「もし～なら」のように、初めて聞くJavaScriptの用語はスクラッチの内容と対応させながら進めました。プログラミングの根本的な考え方である順次処理、反復処理、分岐処理にも触れたのですが、すんなり理解できていました。チエテラスのレッスン内にある確認問題にもすぐに答えられていました。', null, '時間帯: その他
盛り上がり: Robloxを遊びたがることが多かったのですが、プログラミングをやる気になるときちんとやっていました。'),
  ('70e83e58-3571-5b3b-9cff-92ceb11cab0b', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, null, '2023-07-15', null, null, '休み（未対象）', null, null, '時間帯: その他'),
  ('3b2836ae-775c-57ed-a399-14f1989e34f3', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, null, '2023-07-15', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('f3080f4f-03e2-5a07-9658-ba95e7e53539', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, null, '2023-07-15', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('dcd50a53-7f82-5c59-8677-bb731bc595a0', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, null, '2023-07-13', '17:30:00', null, '休み（未対象）', null, null, null),
  ('e0fdf3f4-58dc-5d7a-b05f-90955d83d52a', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, null, '2023-07-13', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('f5b3f208-6ddb-5983-8fd3-d72ff0c31ddd', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2023-07-13', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('d31557e6-8046-515f-a97e-8b74f352db26', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-07-14', '17:30:00', null, '通常 / 大会用作品を完成させる', '気分がのらない様子だったので、「今日は息抜きデー」と決めてScratchで好きなゲームで遊ぶ日になりました。とは言え、大会作品のエントリーが必要だったので、最後にエントリー用の作品について話をし、用紙の書き方を説明しました。 そもそも、大会へのエントリー意欲もかなり下がっています。 前回のアレンジ大賞で頑張った分、できるスキル全部出しきってしまったのか？燃え尽き症候群に近いのではないかと思います。なので、あまり「やれやれ」言わないようにしました。「大会、出すのやめとく？」と聞くと、「でも、怒られる、、、」とのことでした。 なので、「提出したら抽選で賞品が当たるかもしれないから、それ狙いでいくか！」としました。', '次回、大会エントリーを済ませてしまい。（簡単で良いと思います） このところプラットフォームゲームが気に入っているようだったので、次回以降、プラットフォームゲームを作ろうとなりました。 その際、残像、ゆるやかな動き、背景、この３つのスキルが必要だと説明しました。 このあたりの具体的なスキルアップをを明確に意識させてあげて、プラットフォームゲームと言う目標ですすめましょう！ ◆クローン ◆演算 ◆定義（←これは、みんなよく使ってるけど、何？と興味を示しました） 以上のスキルに対して 【小技】きれいな残像の作り方 【PRG】34 ルのすきまを抜けよう！ または アクションゲーム_移動とジャンプ 完成版ステージアップ【LR】https://app.arspark.jp/contents/2953 これを目標にするか、相談してみてください。 アクションゲームは、現時点のものはゲーム的に面白くないので、一旦きちんと作ってからゲーム制を高めるというのもいいかも。 １ヶ月ぐらい、かかってもいいんじゃないかな。 よろしくです。', 'タイピング: なし
盛り上がり: https://scratch.mit.edu/users/hoshimon19/ ↑この人の作品にハマっています。比較的簡単なプラットフォームゲームです。 アルスパークで【小技】残像を少し見せたら、ちょっと関心を見せていました。'),
  ('75a4e468-504c-5068-b9b2-421a18ceaae7', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-08', null, null, '通常 / 大会準備', '今日はある程度やる気を取り戻したようで、戦闘画面やストーリーの作成を進めました。途中でまた嫌になり、この後登場させる予定だった敵を「めんどくさい」といって消してしまったのですが、最終的にはまた作成に戻っていました。特定のキーを押すと主人公が右下にワープするギミックは少し面白かったです。', null, '時間帯: その他
盛り上がり: そうたくんに釣られて頑張れた面もあるかもしれません。'),
  ('8cb73539-9f4f-511b-9f27-9396f7027b8e', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-14', '18:40:00', null, '通常 / コンテスト作品作り', '今回は、当たり判定やステージ再構築しました。手裏剣や弾に邪魔するようなコードがなかったので、「あたったたら最初の場所に戻る」という案に取り入れてくれて、自ら作れ楽しくなっていた。イベントの背景の判定を使ってバグが発生していたので、まで待つと多少のディレイを入れて、この使い方の方がバグらないと教えてあげました。そのはずみ化、2ステージ目を大きく変えたので、モチベが高く保たれていると思います。ただ、いろいろいじって、脈絡なくコードを組んでしまっている感じがありました。次回はEDをつくって、ほかに動くブロックに乗りたいとことだったので、余裕があれば、やってみてほしいです。', null, null),
  ('20c9d5c3-415c-5f71-b1e0-56e877733ab9', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-14', '17:30:00', null, '通常 / 検定問題の復習', '前回、検定問題がやったので、後半があまりできてなかったので、一緒に振り返りながらしました。若干の読み飛ばしと「まで待つ」と「まで繰り返す」が混合してうまくコードが進んでいませんでした。1文ずつ追いながらゆっくりやっていけば、コードを自分で選べて作れていたので、やり方を少し薄れてしまった感があります。もう1度問題をならしてやれば、読み飛ばしに注意してもらえば、いい感じになると思います。 残り時間は中途半端ったので、検定のアレンジ練習として、コスチュームを増殖させて、にぎやかなものになっていました。', null, '盛り上がり: ピクミンの連れての相撲はかわいかったです'),
  ('4e594699-3fc1-518a-9e2a-90defca9710f', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-14', '16:30:00', null, '通常 / コンテスト作品作り', 'ゲームの流れはほぼ完成していたので、あとは不必要にあった表示隠す、変数の表示タイミングを調整しました。最初作っていたであろう、「騎士」と「騎士の体力」の変数が混ざり合わさっていて、隠すが機能してなかったみたいです。 次に、アピールポイントの文章の作成をしました。操作方法はセリフで説明があったからスムーズに進んで、アピールポイントは自分で描いた絵や攻撃手段のところ、自ら出てきてくれたので見せるポイントはわかっていました。確かに攻撃手段は乱数を使ってほかに見ない手段だったので、先生的にもよいポポイントだと思います。', null, '盛り上がり: 文章は虎君よりきれいに書いていた'),
  ('a916db41-06f6-5963-93a0-dfc2c6132349', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-14', '16:30:00', null, '通常 / コンテスト作品作り＆アピールポイント文章作り', 'ほぼ完成していたので、気になっていたバグをつぶしていきました。何度かに1度止まってしまうことやコインの流れについて直していきました。 操作方法とアピールポイントの文章を考えてもらいました。アピールポイントで、物語は言われたから付けたなどと第3社から自分のの意志ではない文章の書き方は良くないと修正してもらうように言いました。先生からの助言として、変数の使い道が上手に組み合わさっていてすごいと付けくわえてておきました。', null, '盛り上がり: たつくんのゲームの良しあしつけて評価してました。'),
  ('a0c7f3b5-6f7e-5e36-b6ac-4dafc451dec0', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-14', '16:30:00', null, '通常 / チエテラス１の章末問題を全部やる', '章末問題をやってみましたが、反復問題と変数の部分がむずかしかったようで全体の3割程度の正答率となっていました。 自分でもむずかしいと話していたので、言葉としての理解よりも整理して理解するというのが身につけられたらいいのかなと思いました', null, 'タイピング: タイピングは大好きな様子で、自分から進んで何問もやっていました！
盛り上がり: 自分で息抜きをタイピングとしていたので、ある意味それはそれでいいのかなと思いました。また章末をやった後にもう一度反復の部分を復習し、ある程度は使える感覚を身につけた感じでした。'),
  ('7676cca5-28e5-5944-a23c-8f38cfe0e2e6', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, 'ffddc12c-2b0e-53f2-9581-885dafe01d35', '2023-07-14', '17:30:00', null, '通常 / チエテラスをやってみて感触をみる', 'チエテラスの、チャプター１の最初から「フローチャートからプログラムを作る」までを勉強しました。 電車の遅延の都合もあり時間が限られていましたが、集中して学習している様子でした。 変数名に使われている英単語（Temperatureなど）がおそらく未学習なので、それが原因で基礎問題が（機械的に）不正解になってしまうところもありますが、こういうところで学習意欲が落ちることだけは避けたいと思いました。今日は、未学習の単語のところで間違えるのは仕方がない、ということで声をかけておきました。', null, 'タイピング: ─
盛り上がり: もともと英語に苦手意識があるので、その場合はコピペさせてあげよう！今回は一文字一文字入力したようで。本当は入力すると英単語も覚えられて良いけど、苦手意識になるよりはコピペで「楽！」と思ってもらって意味を覚えてもらう方が良いね(^^)v'),
  ('32fd6e6c-a673-58b8-a819-ecfce532fa18', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-14', '18:40:00', null, '通常 / 自分の作品作成', '今日は遅刻してきたため20分だけ授業を行いました。現状、赤と青のブロックが押されたらどちらかの変数になるという条件分岐が微妙だったため、そこを修正するというので終わりました。', null, 'タイピング: なし
盛り上がり: 久しぶりに来て来れたので最初はゲームをしてもらいました おやすみのことに関してはあまり触れずに、楽しいのが一番だから何かやりたい項目があったらその日に伝えてねと話したら、来てみようかな・・という雰囲気になっていたので次回からその日何がやりたいか（作品作成、検定問題、チエテラス（まだチエテラスは初めてない））を確認してください。'),
  ('1b4d11c8-5e0e-53a7-97a6-8dfd8a4f7d13', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-14', '17:30:00', null, '通常 / 基本操作コース０６ 物語を作ろうで言葉を話させるというコードを覚える', '今日は他のこと一緒に授業だったためかだいぶ落ち着きがなく、言葉を言わせ合うというのがなかなかうまくハマらなかった感じでした。 なので、一旦今までやってきたおさらいも含めて向きや矢印キーのおさらいも一緒にやりながら、基本操作コース６の言葉の出だしの触りの部分だけを行いました。', null, 'タイピング: いつも自分から率先してタイピングを始めているのでとても素晴らしいと思います！'),
  ('f4e5beff-5946-5e20-a630-c229c09152b2', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-07-14', '17:30:00', null, '通常 / 基本操作コース 追跡ゲーム', '先週やっていたことを覚えていたようで、色々と角度など自分でできる部分はやってもらいました。 質問を投げかけた回答がきちんとでき、理解できていることもとてもGOODだと思います。', null, 'タイピング: まだタイピングを始めたばかりなので、不慣れ感はありますが段々と慣れてきた様子でした！
盛り上がり: 今日は演算、変数、条件分岐を習ったことでスキルアップしている！という満足感があったようでとても良かったです'),
  ('d22975e5-a29f-559f-b501-4e5c89597628', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-07-13', '16:30:00', null, '通常 / 大会準備', 'ゲームのステージ1が終わったので今日はステージ2を進めました。残り作れる時間が少ないことをときどき伝え、終わりまでもっていくことを意識してもらいました。敵の攻撃はステージ1のをコードをコピーしたりして作り、ステージ2がちょうど作り終わりました。とても多くの種類のメッセージを使っていたせいでコードがわかりづらくなったときがあったので、同じメッセージを数か所に送ったりしてシンプルにできるといいねと伝えました。', 'ゲームのエンディング(ステージ3は厳しいか？)', '盛り上がり: 楽しみながら作っていました。'),
  ('20a5fc98-f659-5de8-85f1-4e5724a03c15', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-13', '16:30:00', null, '通常 / 前回の宇宙バトル1をプレイして思い出してから、宇宙バトル2に進んでスコアの変数の学習。 時間が余ったら、前々回に作成した追跡ゲーム（をアレンジした野球ゲーム）に同様に変数を追加させてみる。', '前回のゲームをプレイして、1度でゲームが終わってしまうのはつまらないから、ゲームがもう少し続けられるようにしてみない？と提案したら、すぐにノッてきました。 基本的に、チュートリアルはきちんと聴いているようですが、今回は途中の座標の説明が長くて何を言われているのかわからなくなってきた、と言ってきたので、そこだけはチュートリアルをとめてこちらが実際のスプライトを使って説明しました。その場ではなんとなく理解はできたようでしたが、何度か反復してとりあげてあげると定着できるかと思います。 座標の説明以外は、自分でチュートリアルを聞きながら熱心に作成していました。9割ほど完成できたところで、敵のサイズを色々変えて遊び始めましたが、楽しそうにアレンジを加えていたので自由にさせておきました。結果、とても面白かったのか、授業時間後も30分ほど、何度も繰り返して作品をプレイしていました。', null, '盛り上がり: ゲームらしいゲームが作成できるようになって、とても楽しそうに取り組んでいます。 勘も悪くはなさそうで、作成しているときの反応も体験時と比べてずいぶんと良くなりました。
備考: 今日、学校の授業でプログラミングをしたそうですが、「とっても簡単だった！」と嬉しそうに報告してくれました。 蚕を4匹抱えてやってきました。 普段は学童に行っているそうで、そこで宿題をしたりして19時過ぎまで過ごしているそうです。教室へも一人で来ていて、授業後に宿題をしていいか聞いてきたので、宿題は自由だけれど、終了時間は18時半と決める約束をしました。'),
  ('e0086f34-a231-5517-92f8-2d9b648a8f3d', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-13', '17:30:00', null, '通常 / 虹色ピンポンのアレンジ', '前回虹色ピンポンが完成したので、そのアレンジをしていきました。緑の奴は上から降ってきて視界を遮るものとなっています。アレンジ最中楽しくなって、ゲームをし続けてしまうことが何度あったので、気長に待ってうまく修正しました。そして、かずまくんからの案として、「スコアが20点以上言ったら、ボーナスタイムになって別の球を5回打ち返すとプラス20点される」が出ました。この案は面白いので、補助をしながら、一緒に作り始めました。まで待つとか演算式はかみ砕いて交友機能だよと説明しながらい作りました。次回もこの続きで', null, 'タイピング: キーの位置にまだ戸惑いがある
盛り上がり: コンテストに出したい気持ちはあるので、アレンジのアイデアはかずまくんらしさを出すために、じっくり考えました。'),
  ('81f4452b-be4d-579c-b0e2-49b33f90a743', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-07-13', '16:30:00', null, '通常 / コンテスト作品続き 買い物メモと買ったものリストの照合等', 'リスト名の「買い物リスト」「メモ」の区別が自分でも混乱しがちでうまくやりたいことの説明ができずにいらついていたので、リスト名や変数名、メッセージ名などは後からでも変更できること、少しでもやりづらいと思ったら本人以外にはもっとわかりづらいので、すぐに変えた方が良いと思われることを説明し、納得して変更していました。また、一致するかどうかの判断を正確にするために、ひらがなや片仮名表記の統一が必要であることも説明しました。 片方のリストに、もう片方のリストにある項目名が含まれているか判断するブロックの使い方を説明し、自分の作品に反映させることができました。 ゲームをプレイしていくにつれて、「買い物メモ」と「買ったもの」リストの中身の相違によってその後の動きを変えたかったり、セール品の扱いや値段の計算を入れなくてはいけなくなったりと、やるべきことが増えていって少し混乱したので、必要なスプライトを先に作成してもらい、コードは次回にまわすことにしました。', '買い物メモと買ったものリストの中身が違った場合の動き、合計金額の計算', '盛り上がり: だいぶイメージが完成に近づいてきたのは嬉しそうでした。 本人としても、あともう一歩がんばりたい、という感じでした。'),
  ('632d36ad-1609-5212-8058-799fd3250887', 'b2246586-4496-52f9-a825-be2488a00a31', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-07-13', '17:30:00', null, '通常 / 自由作成', '最初は、扉によって違うアクションが起こるゲームを作っていました。色の変色やグラデーションの使い道が独自のものになっていて、見ごたえのあるものになっていたが、少しホラーです。 後半は、迷路と弾除けを組み合わせたゲームを作っていました。ボールのタイミングがいい感じ調整されていたり、自分だけの隠しコマンドを作って、ゲーム性としてとても楽しいものとなっていました。振替できていたそうたくんも楽しんで、二人で盛り上がていました。', null, '盛り上がり: 協調しあう子がいると、アレンジがはかどる')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
